-- Poems batch 347
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f18b9b64-5d23-4ccd-8d9c-259d47dff887','趨府馬上悠然思陳無己三兄成詩寄之','晁說之','宋','宋诗','song-poetry','','[]','瓦釡毁未棄，黄鍾幸且存。',240,'全唐诗/poet.song.67000.json','["瓦釡毁未棄，黄鍾幸且存。", "於焉正律呂，誰爲到崑崙。", "相思出苦淚，東漢太丘孫。", "聞之在徐州，無衣出柴門。", "亦賦乞食詩，饑瘡故拙言。", "靖節非此夫，如似校静喧。", "顑頷不悲傷，自知美蘭蓀。", "龍伸能蛇屈，土不蝕璵璠。", "魴鱮書懶寄，天公牋可論。", "名不入葦笥，欲報天地恩。", "明光出須臾，一破萬古昏。", "蒼生訖康濟，坐覺君子尊。", "浄盡城上烏，變化北溟鯤。", "豈但喜囚冠，故亦慰纍魂。", "我既美子志，爲子盡嬋媛。", "吾曹寧餓死，終肯傍祭墦。", "孔明與荀賈，豈不共中原。", "崎嶇入巴蜀，雅志正本根。", "柳子一失此，羅池爲鬼寃。", "問訊寄此辭，飽腹何時捫。"]'),
('50bd07e4-dfc2-4b5b-bce7-08fbe90ca8c3','欲自邯鄲趨府復從中山行覺風異常馬上作','晁說之','宋','宋诗','song-poetry','','[]','山行豈不惡，清音興自長。',96,'全唐诗/poet.song.67000.json','["山行豈不惡，清音興自長。", "風從巀嵲來，不比人間涼。", "浮涼誇湛露，屈子自悲傷。", "披襟青蘋末，玉也媚君王。", "驩見西王母，笑酌白玉漿。", "當今第幾人，此樂可共當。", "車馬邯鄲道，側身一相望。", "爲謝南亭女，世方賤鉛黄。"]'),
('5a0f4ffc-a3a0-47db-8baa-75755a3dbeac','秋來庭下雜花盛開對之感懷作','晁說之','宋','宋诗','song-poetry','','[]','春花擢翠榦，秋花披芳叢。',48,'全唐诗/poet.song.67000.json','["春花擢翠榦，秋花披芳叢。", "叢花都且閒，天質不爲容。", "寧謝兒女賞，本自能淒風。", "持之奉君子，令德晚更崇。"]'),
('8c5d2279-96b8-4b8f-b23b-0ae6a992312b','秋來','晁說之','宋','宋诗','song-poetry','','[]','秋來頗自適，撫此清收時。',48,'全唐诗/poet.song.67000.json','["秋來頗自適，撫此清收時。", "不假絕交論，聊吟招隱詩。", "山阿新橡栗，朝廷舊臯夔。", "早晚罷給散，恩偕雨露垂。"]'),
('bbd7f251-9612-4f1c-a9d1-601899f33186','十月十三日自郡歸山中寄周秀實昆仲','晁說之','宋','宋诗','song-poetry','','[]','陰靈識陽月，怪樹知窮谷。',87,'全唐诗/poet.song.67000.json','["陰靈識陽月，怪樹知窮谷。", "路轉山迎人，崢嶸失南北。", "回首人間士，總總今何役。", "嗟子此行李，志尚亦云獨。", "世事兼漳{氵鑒}，溫涼俱所欲。", "耿介自小人，大匠死繩墨。", "伯仁莫妄評，阿奴不碌碌。"]'),
('bae45eee-9472-47c1-ad0c-12bfbe10510d','忽蒙秀實內黄賢尉寄書期許稠至有經世之語輒代書爲謝','晁說之','宋','宋诗','song-poetry','','[]','歲宴慕羣侣，魚鳥各知息。',180,'全唐诗/poet.song.67000.json','["歲宴慕羣侣，魚鳥各知息。", "故人音書來，憐我此時憶。", "忠言開靡靡，豈但問寢食。", "我有山耕願，久矣君已得。", "中道忽獻書，明時思自立。", "一官雖漫與，頗知民苦疾。", "豺狼不當路，雨露發天秩。", "植杖聽班詔，去暴看甲乙。", "閭閻心欲速，廊廟慮匪棘。", "恨不死褚淵，歎嗟起安石。", "固云小人鄙，未易君子識。", "悠悠定誰堪，世事兒女劇。", "君才雄且鋭，欲振排雲翮。", "但恨張公子，蹶蹶難與適。", "功名良可圖，燕然銘謾勒。"]'),
('bd2412c5-8fe6-4cbd-baf3-10b465f7fedd','趙德麟書來言黄九聞移命後徑遊峨嵋慨然有作','晁說之','宋','宋诗','song-poetry','','[]','蹇産久無賴，相羊忽有期。',120,'全唐诗/poet.song.67000.json','["蹇産久無賴，相羊忽有期。", "野馬脱羈日，逐客賜環時。", "鄉國眼中見，申肘猶云遲。", "夫子獨不爾，西復到峨嵋。", "初非身世謀，無淚竹枝辭。", "豈是軒冕人，要路莫相疑。", "歸來舊臺閣，風霜嘗路岐。", "曰予有末契，斯焉定何之。", "興懷白象士，復自話别離。", "萬行端難渝，短軸賞新詩。"]'),
('003cf78d-3c71-4036-98bd-56624bb85bfa','無己初除正字以詩寄之','晁說之','宋','宋诗','song-poetry','','[]','平生阮步兵，口不道臧否。',96,'全唐诗/poet.song.67000.json','["平生阮步兵，口不道臧否。", "每笑謝著作，自是雌黄口。", "閉門秋草多，金風搖白晝。", "忽傳黄紙書，校藝羣公後。", "執鴈有楚越，佩劍無左右。", "難畫渾沌眉，遽識齊宿瘤。", "彭城陳夫子，笑我顔何厚。", "爲語陳夫子，人生無不有。"]'),
('b16189c8-559b-4c8a-a6f9-c235a8dfa303','寄陳叔易','晁說之','宋','宋诗','song-poetry','','[]','春色今似我，已老不足愛。',92,'全唐诗/poet.song.67000.json','["春色今似我，已老不足愛。", "花隨浮雲空，只有蜂蝶在。", "問春歸處無踵跡，腸斷江南與江北。", "青春不似青山常有情，處處相逢好顔色。", "山中故人頭亦白，何敢勞渠坐相憶。", "願得春風一夜萬丈高，乘之歸去舊巖谷。"]'),
('93848775-7ba0-4107-a9d2-5dad1143f3cb','答趙德麟見招之作','晁說之','宋','宋诗','song-poetry','','[]','王孫囚冠安穩無，骨清肉健今更癯。',64,'全唐诗/poet.song.67000.json','["王孫囚冠安穩無，骨清肉健今更癯。", "學似東山何所歉，才如北海莫言疏。", "幾年漢上狂歌散，今日山前幽夢餘。", "消息遠來知有意，碧巖却要子來居。"]'),
('c2ec4e99-8ea1-4b3c-ba4d-faf15da382fd','和十二弟見降羌過洛','晁說之','宋','宋诗','song-poetry','','[]','百代興亡吐谷渾，聖主神謨不世恩。',32,'全唐诗/poet.song.67000.json','["百代興亡吐谷渾，聖主神謨不世恩。", "解縛再生有孫子，無勞倚笑上東門。"]'),
('fb234a80-4595-4808-985e-7fcb6b60a1a9','君莫惡行','晁說之','宋','宋诗','song-poetry','','[]','今年蠶母連萬箔，屋邊桑葉渾不着。',112,'全唐诗/poet.song.67000.json','["今年蠶母連萬箔，屋邊桑葉渾不着。", "彷徨何計救戢戢，出棄陌頭空涕泣。", "前日初眠不敢語，今日賤之如糞土。", "不容身老吐一縷，回首室中殊樂苦。", "何敢願天不我與，亦太無情彼蠶母。", "芙容錦帳醉新粧，那知有恨如許長。", "相公日戀北門樂，迎候馬前君莫惡。"]'),
('a34a0f65-8d1b-44e3-b5f2-b7d5a1f70808','夜行自戲六五言','晁說之','宋','宋诗','song-poetry','','[]','觸熱褦襶幾許，我生何艱哉。',52,'全唐诗/poet.song.67000.json','["觸熱褦襶幾許，我生何艱哉。", "九天星斗初轉，汲井意徘徊。", "不解鳴珂帝所，踉蹡没塵埃。", "爲問晚嫁盧姬，一笑爲誰開。"]'),
('c2880117-eb65-4421-8d34-d354060c613e','題卲武軍泰寧縣葉恪循道清風樓','晁說之','宋','宋诗','song-poetry','','[]','葉公賢父子，清風何奕奕。',108,'全唐诗/poet.song.67000.json','["葉公賢父子，清風何奕奕。", "愛彼清風好，危樓高百尺。", "來從玉宇遠，照衣光可擲。", "桂葉尚飄飄，蕙草不習習。", "平生眼豁開，脱然凌羽翼。", "對飲伴明月，故人念疇昔。", "詠歌何穆如，援琴更幽寂。", "慈烏遶難老，霅溪非其匹。", "華陽三層上，松韻亦蕭瑟。"]'),
('900c2e70-7660-453d-903e-504f5255187c','始到無極作','晁說之','宋','宋诗','song-poetry','','[]','徂歲若飛羽，去矣不可招。',216,'全唐诗/poet.song.67000.json','["徂歲若飛羽，去矣不可招。", "諒積寒暑多，我髮覺翛翛。", "是身一枯木，引憂自焚燒。", "河山再遊宦，鄉國夢魂勞。", "友朋不敢思，得意在本朝。", "弟妹天一方，披衣泣中宵。", "介拙取如此，罪侮肯相饒。", "眷言此邦人，不與我逍遙。", "五日無羊俎，十日無魚庖。", "懶我蔬菜慣，妻兒嗔呶呶。", "亦有寢食地，肘申瓦歎搖。", "政自不容膝，如彼風後巢。", "當此仲夏時，何以謝炎歊。", "前聞嚴君平，氣和生涼颷。", "但恐此語欺，古道久可嘲。", "平生鄙潘岳，懷縣復鬱陶。", "靖節真吾師，一去何超超。", "終期不自墮，賦詩畔牢騷。"]'),
('6fb1e3b1-31c4-4270-9a9f-8d8c43cfe952','送杜通直乞罷無極南歸','晁說之','宋','宋诗','song-poetry','','[]','青堂帳下白題歌，王師城外横天戈。',160,'全唐诗/poet.song.67000.json','["青堂帳下白題歌，王師城外横天戈。", "白首國母契丹女，泣問王師來謂何。", "將軍突騎擅府庫，羌兒逃死獨峰駝。", "軍中即日拜太守，兜鍪未脱羣冠峨。", "杜侯别乘不願行，自言壯志今消磨。", "顧豈不知金幣饒，家有清風誓不頗。", "歸來南北信所之，無極陋壤留則難。", "却卷前志隨征鴈，回首三吳風景和。", "憐君骨法可學道，此身肯與樹婆娑。", "嗟予投幘亦不晚，君好訪我嵩山阿。"]'),
('b151d2d1-2330-49d9-bce5-13079aeb4210','趙君年十六作雨詩極奇驗可畏說之輒次韻和之','晁說之','宋','宋诗','song-poetry','','[]','天地綿綿寄一水，上有浮羽下累塊。',192,'全唐诗/poet.song.67000.json','["天地綿綿寄一水，上有浮羽下累塊。", "時時出溢不自持，或濛或霔初有底。", "人間妄見得雨名，穴居那解知其際。", "既久天地如卵毈，漏下涌上潛相繼。", "日雞月蟾喜瀦污，力斂光明慳不費。", "兹復何時霖未休，萬牛高木同茅刈。", "朽屋欹傾嗟莫支，好逐苴浮連一穗。", "何處紅藥媚芳妍，但見土花爭點翠。", "被濕出門意憀慄，刺舟庭下却車騎。", "茫然誰與散此愁，文定諸孫森葆翳。", "青青稚齒口鼻哽，滂沱苦語天工棄。", "趙生十四識嵇康，諒知前言非我戲。"]'),
('c9a82c04-a540-4dc0-a13f-97913cef8985','黄河多淘河之屬有曰漫畫者常以觜畫水求魚有曰信天緣者常開口待魚感之賦三詩 淘河','晁說之','宋','宋诗','song-poetry','','[]','淘河復淘河，后土激浪沙分波。',74,'全唐诗/poet.song.67000.json','["淘河復淘河，后土激浪沙分波。", "大石羽轉雜龍鼉，汝欲澄清力幾多。", "官家費盡水衡錢，萬夫政待汝漪漣。", "天上有河鵲以填，可增汝漫髠其顛。", "虚名覈何嘗，休譏汝在梁。"]'),
('df6222a5-7021-4f5e-87ad-1b67a0ea346c','黄河多淘河之屬有曰漫畫者常以觜畫水求魚有曰信天緣者常開口待魚感之賦三詩 漫畫','晁說之','宋','宋诗','song-poetry','','[]','漫畫復漫畫，河尾沙軟喙一尺。',54,'全唐诗/poet.song.67000.json','["漫畫復漫畫，河尾沙軟喙一尺。", "天生剛啄不解禿，倦魚薄淺幸有得。", "謀拙力百費，何處有金翅。", "饑腸倚暮煙，慚愧信天緣。"]'),
('c72c6ebd-4871-4b45-b408-3fca632bab2a','黄河多淘河之屬有曰漫畫者常以觜畫水求魚有曰信天緣者常開口待魚感之賦三詩 信天緣','晁說之','宋','宋诗','song-poetry','','[]','信天緣，何爲者，非達亦非賢。',70,'全唐诗/poet.song.67000.json','["信天緣，何爲者，非達亦非賢。", "終朝開咮不敢仰，待魚落咮急下咽。", "大魚變化小魚黠，誰肯効命於爾前。", "皇天日月高，無心憐爾曹。", "幾欲强求索，豈不鑒漫畫。"]'),
('c4bf653a-9065-41ba-b6b0-d5f109dbdb67','比日風雨甚異山下人云此六月龍會時也中頂有會龍洞予嘗遊焉賦詩記其事今感之有作寄趙德鱗','晁說之','宋','宋诗','song-poetry','','[]','西峰掩映東峰明，倐忽起滅令人驚。',152,'全唐诗/poet.song.67000.json','["西峰掩映東峰明，倐忽起滅令人驚。", "九野雨足龍上征，六月正乃會瑲珩。", "雷電斷絕風來輕，鼓倡鼙和鈴簫笙。", "虹霓舒斾雲搖旌，萬龍夭矯宿崢嶸。", "天門大開仙子迎，不比它邦時雨行。", "中天有洞遺珠纓，我昔酌泉探幽清。", "尚疑不然今信誠，安得問訊驂騎鯨。", "脱去禁令朝玉京，相羊容與俯四瀛。", "下呼我友何營營，寒饑暑渴亦已更，胡不同我此長生。"]'),
('27d2f37b-c05d-4a99-929a-abb039066751','和澗上丈人石淙作依元韻','晁說之','宋','宋诗','song-poetry','','[]','岷江將入海，金山中斥攫。',276,'全唐诗/poet.song.67000.json','["岷江將入海，金山中斥攫。", "近樵得鴈盪，平地風落落。", "獰兒一稱絕，如夔理舜樂。", "那知嵩石淙，視彼削則削。", "兩處各瑰俊，一旦得磅礴。", "水從嵩陰來，到此幾谿壑。", "勢盡劃縱横，天地自開鑿。", "腹背涵叢峰，星斗俱漠漠。", "波搖下嶔崯，雲度上岞崿。", "爲山無麓趾，突兀便可樂。", "北首揖三頂，鴈行共遼寞。", "睥睨萬培塿，飄然風中籜。", "莫言聚石耳，乍如五陰剥。", "試觀煙霞生，如蓮敷青雘。", "非山亦非石，水亦非激躍。", "癡龍有路寢，醉蜃不收閣。", "因得爲人戲，何處顔色怍。", "或疑上帝宮，盆山映叢薄。", "盲風吹下將，塵世暫斟酌。", "又疑涿野戰，行陣龍虎作。", "過怒禁不散，結此空黝噩。", "寧論八陣圖，水來俄而却。", "惜哉遊者稀，元老情不惡。"]'),
('85c3a057-9795-41e0-a3f9-05bd4c64dee0','偶得雙頭蓮花戲作','晁說之','宋','宋诗','song-poetry','','[]','君子不見昭儀飛燕姊妹在漢宮，同妍共麗媚赤鳳，赤鳳一日與俱逝長空。',221,'全唐诗/poet.song.67000.json','["君子不見昭儀飛燕姊妹在漢宮，同妍共麗媚赤鳳，赤鳳一日與俱逝長空。", "又不見大舅小舅兄弟專晉亦何有，兄招千里兵，弟殞一杯酒。", "嗟爾芙蓉芬芳姿，出水無染稱瓌奇。", "亭亭各映清漣漪，高下淺深何不宜。", "嘗遊鏡湖五月時，目極萬疊青羅衣，一花獨出擅朝暉。", "譬如神情散朗王夫人，不爭鉛黄桃李春。", "又如君子立朝廷，朋而不倚自修正。", "何乃反常爲異失故態，比之人事那足愛。", "只恐横塘知我有恨處，故教絕艷相並語。", "莫言才氣世無雙，並蒂何如君看取。", "不然戲我坎壈此世每不偶，逢人好匹開笑口。"]'),
('df454cda-0b5b-4afd-bf32-717d473057e2','正月六日七日書所見','晁說之','宋','宋诗','song-poetry','','[]','扶光歲首當何辰，荐視變異紛無垠。',112,'全唐诗/poet.song.67000.json','["扶光歲首當何辰，荐視變異紛無垠。", "既驚馬日不爲馬，況復人日不成人。", "咸疑白晝懸月魄，譁言日月相鬭格。", "如負如空天風愁，似食不食自毒螫。", "空裏黄埃下百重，日心黑氣交四磔。", "不知何地匿陽烏，人間百鳥競號呼。", "可憐海氣使如此，杏梁瑞彩想中都。"]'),
('dd3ec242-7321-4cf1-bb71-51220626533a','送許同年赴江寧知錄','晁說之','宋','宋诗','song-poetry','','[]','風稜索索許子伯，軺車督郵聲赫赫。',96,'全唐诗/poet.song.67000.json','["風稜索索許子伯，軺車督郵聲赫赫。", "裔孫德似官亦同，獨乘瑞霧開羽翮。", "金陵城裏春色多，疑是六朝舊金碧。", "只宜細看後庭花，慎莫垂淚江家宅。", "吳驃那解醉離腸，嗟余自是思歸客。", "荷葉開時楊梅熟，江南江北遙相憶。"]'),
('cc27e5ba-472b-4488-b9e9-b422e6d3724e','送壇守赴闕','晁說之','宋','宋诗','song-poetry','','[]','昔時江南士人輕吳會，正如長安洛陽論賓主。',126,'全唐诗/poet.song.67000.json','["昔時江南士人輕吳會，正如長安洛陽論賓主。", "自從九州花開一日來，欣欣不復聞此語。", "明州太守江南英，信美之鄉是吾土，莫言只飲甬水便無情。", "黄鵠排赤霄，垂翅一再舉。", "御廚賜食紫駝峰，情多猶憶馬夾柱。", "依然夢斷四明山，花信風裏憐梅雨。", "潮平驩喜浪婆兒，莫錯舉櫂新城江上去。"]'),
('fa4ba115-dc14-433c-b543-359d0426ce44','顧彌邵以其尊內翰所有歐陽公集遺侄季澈賦詩篇末見及輒次韻作','晁說之','宋','宋诗','song-poetry','','[]','昭陵人物一朝盛，晚有醉翁爲擬倫。',128,'全唐诗/poet.song.67000.json','["昭陵人物一朝盛，晚有醉翁爲擬倫。", "譬如羣鳳粲羽翰，來下千里儀九成。", "鳳歸樂絕天寥寥，人間墜簡空垂精。", "可但光華開日月，要識忠憤聳幽神。", "虎頭本是當時客，教子傳孫無粟亭。", "晝吟夜誦翁文耳，池蛙何容聒正聲。", "得之不待金錯贈，好守門律如時令。", "君家此叔定不癡，莫厭家雞外勤請。"]'),
('265f5069-c5d5-4591-bf48-ae12319e1e56','送公望','晁說之','宋','宋诗','song-poetry','','[]','竊獨悲秋霖，江湖難爲客。',96,'全唐诗/poet.song.68000.json','["竊獨悲秋霖，江湖難爲客。", "短髮思歸時，奈此西行色。", "念君諸王孫，風骨秀而整。", "衣冠舊諸生，不羞見狹領。", "邂逅託末契，君室獻可孫。", "豈但姻婭舊，有感風義敦。", "君知前輩好，寧用文墨期。", "潁麟陳留言，爲君愛吾詩。"]'),
('5990e9c7-48ec-4760-b5d3-c7844df13745','新作竹軒','晁說之','宋','宋诗','song-poetry','','[]','齋壁值墨竹，文蘇兩先生。',72,'全唐诗/poet.song.68000.json','["齋壁值墨竹，文蘇兩先生。", "移根今何殊，初度風雨聲。", "妙識前日意，歡見此時情。", "家山幾千里，客恨倐似傾。", "歸期恨今晚，像此葺茅楹。", "故知江海夢，常共月華清。"]'),
('bfe3034f-2539-4d38-9ce2-014cfcb2c697','感懷','晁說之','宋','宋诗','song-poetry','','[]','甬東爲客久，心期日自昧。',72,'全唐诗/poet.song.68000.json','["甬東爲客久，心期日自昧。", "秋風滄海潮，尚餘桂江泪。", "形影悵已老，頗識前人意。", "柳子與沈侯，超邁萬人外。", "終日常戚戚，不知果何是。", "我亦負罪臣，視彼才藻愧。"]'),
('2f154d44-90d9-4f55-b589-e923cb82de8d','感興','晁說之','宋','宋诗','song-poetry','','[]','越山無黄葉，客子自悲秋。',60,'全唐诗/poet.song.68000.json','["越山無黄葉，客子自悲秋。", "朝來風雨惡，白浪翻山頭。", "歸鴈不敢度，何事此淹留。", "少時笑古人，耻爲關外侯。", "老識古人意，首山復首丘。"]'),
('55593475-2f32-40c5-a618-6e75d086190e','秋晚','晁說之','宋','宋诗','song-poetry','','[]','居恨日不過，復此秋云暮。',60,'全唐诗/poet.song.68000.json','["居恨日不過，復此秋云暮。", "一歲餘幾何，挽之安得住。", "老矣且勉學，高談非所與。", "貧賤苟不慚，勢力則不懼。", "涼飇幸已多，寧煩賦不遇。"]'),
('82e86ea2-a9a5-478e-85cb-8c1170ef2bd3','題琦公讚光堂','晁說之','宋','宋诗','song-poetry','','[]','山川固高深，不掩珠玉光。',120,'全唐诗/poet.song.68000.json','["山川固高深，不掩珠玉光。", "道人覺物者，明明豈自藏。", "奈何一世中，暝醉不我臧。", "收斂萬古志，風雨一茅堂。", "問之默不語，詩成蘭蕙香。", "山中多卉木，有待而芬芳。", "自憐年少時，徹今晝公行。", "虛空流水遠，天外有鸞凰。", "白髮此種種，紅塵誰茫茫。", "嵩少今卜築，因之歸興長。"]'),
('267711fd-8ab7-44c5-9ea5-f3335fd57409','風','晁說之','宋','宋诗','song-poetry','','[]','一雨一月强，天地同翳如。',96,'全唐诗/poet.song.68000.json','["一雨一月强，天地同翳如。", "大風半夜起，上下痛掃除。", "彼蒼不自壓，人力端奈渠。", "不然何特異，搖蕩此寰區。", "癡兒怖懼起，無衣凍不蘇。", "尚恐山岳仆，寧暇小物謀。", "人生所托微，造化仁有餘。", "明朝木杪静，晏晏看天衢。"]'),
('07caa0a9-61c4-4797-a29f-c2a19c2c07b0','夜雨','晁說之','宋','宋诗','song-poetry','','[]','夜雨聽沉寂，頗似嵩少時。',60,'全唐诗/poet.song.68000.json','["夜雨聽沉寂，頗似嵩少時。", "但怪越江上，非此嚴冬宜。", "重岡迷積霰，故山今付誰。", "潮頭斯更健，魚尾適自嬉。", "獨如客子何，耿耿問心期。"]'),
('d9854e9d-f479-420a-ad06-6971c8505dd4','寒江','晁說之','宋','宋诗','song-poetry','','[]','寒江不可望，怖爾船中客。',60,'全唐诗/poet.song.68000.json','["寒江不可望，怖爾船中客。", "波濤已無時，風雨又幾日。", "人多冒險艱，我獨幸沉寂。", "蛟鼉得意豪，鴻雁歸期急。", "吾孫解蠻語，政可一戲劇。"]'),
('10faca0a-0a45-40cd-b13e-f102d04d1273','夜大風','晁說之','宋','宋诗','song-poetry','','[]','夜半江頭清客耳，彷彿鐘聲風雨裏。',96,'全唐诗/poet.song.68000.json','["夜半江頭清客耳，彷彿鐘聲風雨裏。", "雨收風冷獨嚴威，鼉號龍戰江聲徙。", "政是夫差破吳時，鼙鼓百萬當者靡。", "白頭嵩客奈此何，他年慣聽山之阿。", "惟彼天地之中央，岫塤篪谷寧厭多。", "吾土信美小人哉，何不處處作好懷。"]'),
('f3394673-98e1-430b-8c11-f81fc9fa0060','和胡少汲遊山','晁說之','宋','宋诗','song-poetry','','[]','峭直漢大夫，伊余忝末胄。',288,'全唐诗/poet.song.68000.json','["峭直漢大夫，伊余忝末胄。", "出不遇良媒，生本值惡宿。", "高曾耀圖牒，罪戾辱堂構。", "十饑付羣兒，萬恨閣孤咮。", "耻爭市井日，雅願農田壽。", "感慨觸目新，忠憤平生舊。", "欲論國中樞，誰識不下輳。", "偶爲江湖遊，喜見園林茂。", "但恨老子迂，難復處士秀。", "懷我故時人，識彼往歲綬。", "故人多零落，高義或邂逅。", "有美中庸胡，願息金蘭臭。", "家住灊岳雲，賦此小山狖。", "纔顯便官豸，暫處得僧鷲。", "大篇既錦舒，小章亦玉鏤。", "本期古人知，豈急今朝售。", "又如五色丹，必待九轉就。", "不近戀洛陽，何遠憚句漏。", "神智此既澄，世網不待透。", "明珠雀能銜，黄金鳥解潄。", "遺骨一國珍，死鬢百草鬬。", "果誰真美惡，亦曷定先後。", "食柏莫分甘，種漆要自守。", "無思粱肉肥，忽厭藜藿痩。"]'),
('4d9041a8-95ae-40f1-94f8-ffdd1636c13b','謝周同年通叟詩卷','晁說之','宋','宋诗','song-poetry','','[]','周郎既老曲不顧，自作吳音歌白苧。',80,'全唐诗/poet.song.68000.json','["周郎既老曲不顧，自作吳音歌白苧。", "二三名勝能知音，傖翁得之嗟已暮。", "玩之在手一載讀，愈見佳處心愈妒。", "君乎瘖休無復鳴，我宜如許他宜慮。", "鄉曲豫章皆奇才，直上千尺已摧去。"]'),
('bdb5efdc-71d0-4215-946d-6a4ca838ba31','送琦公詩卷','晁說之','宋','宋诗','song-poetry','','[]','孤山教體外，賦詩湯休上。',96,'全唐诗/poet.song.68000.json','["孤山教體外，賦詩湯休上。", "後來數參寥，接手得宗匠。", "東遊四明山，懷人增惻愴。", "何言遇老琦，二公論輩行。", "但欠主盟人，汲古自清唱。", "明年已七十，句法何蕩漾。", "兹山近蓬萊，展卷到絕曠。", "島子敢賡酬，我正恨難傍。"]'),
('4bd3e8fc-ec04-4301-96f2-95d3614f485e','次韻和法琦','晁說之','宋','宋诗','song-poetry','','[]','野寺木魚午不響，老僧乞米樵松根。',128,'全唐诗/poet.song.68000.json','["野寺木魚午不響，老僧乞米樵松根。", "志幽思苦作詩戲，處身不忌如窪罇。", "大軸視我正其欲，尚恨近體意虚辱。", "報以五字陶謝家，要看素絲難純束。", "江頭梅雨滅槐火，我正思公慚飯顆。", "復我苦淡來惱予，歎息有能無不可。", "枉是晝公出前溪，猥效蘇州失故棲。", "蘇州風流今不見，公乎老矣誰提攜。"]'),
('56f85577-b281-46d1-b3da-5aa27dba04a8','書事','晁說之','宋','宋诗','song-poetry','','[]','越天梅雨短長思，嵩陽客子問歸期。',56,'全唐诗/poet.song.68000.json','["越天梅雨短長思，嵩陽客子問歸期。", "幽夢遠近徒猶夷，細字老眼厭紛披。", "身將隱矣又何爲，且舒縈滯爲客時，故自平平欲語誰。"]'),
('52b4bbe4-5934-4688-8f04-c8e2e86e6a96','連日酷暑異常攄悶而作','晁說之','宋','宋诗','song-poetry','','[]','寒暑平分，東南之徼，何多暍哉。',183,'全唐诗/poet.song.68000.json','["寒暑平分，東南之徼，何多暍哉。", "遠望炎洲，近觀火井，相與朝燼而夕灰。", "名曰冰紈霜練，服之一縷如十襲，而信衣冠之不能。", "敢疑夏祖之居會稽，短髪文身自蔽以草萊。", "浪婆兒，身世世，共道常年不如是。", "誰復憐北客，此日真憔悴。", "深山乳虎想騰倚，清風不來空嘯死。", "安得人如葛稚川，脱身直下坐井底。", "奈何滄海濁沸，日不敢浴，金波自爛玉兔熟。", "四方上下濁氛滿，何許層冰映雕玉。", "苦熟何不可，濁氛端惱我。"]'),
('034284ce-d96b-4a51-ae0a-ca838fd69490','大熱戲作','晁說之','宋','宋诗','song-poetry','','[]','仕板三十年，罪籍乃十歲。',84,'全唐诗/poet.song.68000.json','["仕板三十年，罪籍乃十歲。", "妻兒歎朝夕，欲免饑寒累。", "爾來官南陬，長夏苦炎熾。", "自疑吾其魚，釡鬵方盡沸。", "金石方流爍，況此病而悴。", "却顧妻兒笑，聊取一嬉戲。", "饑腸雖自鳴，寒凍非吾事。"]'),
('1876e2d9-8b6b-404a-9b81-cb8e67124ff8','謝仲長通判朝議兄惠顧渚茶','晁說之','宋','宋诗','song-poetry','','[]','天子不嘗陽羨茶，二百年餘吾儂咨嗟。',118,'全唐诗/poet.song.68000.json','["天子不嘗陽羨茶，二百年餘吾儂咨嗟。", "可是吾儂咨嗟休，濤江春色遠含羞。", "趙卿老矣刺史半，緘題寄我甬水頭。", "故副委員長不敢西爭去貴嗜，最宜東來同羈愁。", "人生趣尚有窮達，草木還亦如人不。", "誰家棄婦泪未乾，忍對孤鴻暮影寒。", "趙卿蝦菜且良食，莫教歸夢到長安。"]'),
('473fb19a-cd16-4d04-af89-525cc69a25fc','初秋思舊山','晁說之','宋','宋诗','song-poetry','','[]','秋江未澄瀾，秋聲已先到。',78,'全唐诗/poet.song.68000.json','["秋江未澄瀾，秋聲已先到。", "頗謝涼風吹客愁，何須落葉驚人老。", "古來此興定何如，自愁不愁自傾倒。", "直爾相羊好遠遊，何不命駕歸嵩丘。", "君乎不上三十六峰頂，只恐君家未是秋。"]'),
('2f6124ad-0499-4db5-bc82-f2c20d22455b','送范八西上','晁說之','宋','宋诗','song-poetry','','[]','江頭楓樹秋，東吳王孫愁。',72,'全唐诗/poet.song.68000.json','["江頭楓樹秋，東吳王孫愁。", "誰復憐北客，夢不到中州。", "子能中州去，獨我不自聊。", "心事豈如期，來歲同歸舟。", "子今未二十，志氣長者流。", "勤讀未勤問，有待再見不。"]'),
('ca1f929f-3ebf-4d5c-a65c-9d20d7c7dc6e','秋日江上作','晁說之','宋','宋诗','song-poetry','','[]','秋色千里來，潮波八月壯。',60,'全唐诗/poet.song.68000.json','["秋色千里來，潮波八月壯。", "起帆增江勢，勁風滋頡頏。", "海道當如何，燕羽去雲上。", "人生自窘束，有情宜騁望。", "兩眼幸未盲，莫謾讀易象。"]'),
('c9c79ddb-3018-4dd0-a70c-20e877ecdbfd','題明發所畫訪戴圖渠自有詩','晁說之','宋','宋诗','song-poetry','','[]','扁舟雪夜興，千載風流存。',48,'全唐诗/poet.song.68000.json','["扁舟雪夜興，千載風流存。", "詩畫能幽絕，不似諸王孫。", "興多却易盡，一世復何待。", "傖父莫罵予，猶且不見戴。"]'),
('17121875-f31d-4857-a5ea-3c4d50c0eb42','嵐露雨','晁說之','宋','宋诗','song-poetry','','[]','越山八月時，颺颺嵐露雨。',72,'全唐诗/poet.song.68000.json','["越山八月時，颺颺嵐露雨。", "却疑梅再黄，奈何燕已去。", "平生始知名，要來愁羈旅。", "前愁豈不多，紛紛新代故。", "誰爲司愁者，特於予不負。", "寄言宦遊子，行李莫匆遽。"]'),
('2ed44c1e-d169-48bf-8cfb-f5eb58266960','寓興','晁說之','宋','宋诗','song-poetry','','[]','秋風來偏戰，萬葉倐奔亡。',72,'全唐诗/poet.song.68000.json','["秋風來偏戰，萬葉倐奔亡。", "客子江海間，是時多慨慷。", "何事新來鴈，矯翼過吾鄉。", "吾鄉多霜雪，豈不坂路長。", "思覽萬物表，試登千仞岡。", "徜徉未終樂，急景歎扶光。"]'),
('b6ed9b88-102b-4a21-9b19-0547b6666a4c','古人','晁說之','宋','宋诗','song-poetry','','[]','古人愁已極，今我不用愁。',60,'全唐诗/poet.song.68000.json','["古人愁已極，今我不用愁。", "去日已忽忽，來日諒悠悠。", "便能如此志，終恐慚白頭。", "經月不讀書，閉目得自求。", "不如懸車好，更復外言不。"]'),
('40ddcccd-ff46-4b34-bc71-2190e4efd3cc','風雨縱横至','晁說之','宋','宋诗','song-poetry','','[]','風雨縱横至，此非淵明廬。',48,'全唐诗/poet.song.68000.json','["風雨縱横至，此非淵明廬。", "勉哉風雨操，人品有賢愚。", "彼方適雲旗，我切畏泥塗。", "淒淒向深夜，何處識斗樞。"]'),
('0b7df9ae-a2e6-4b36-8543-86a7e9f12cdf','乘小艇戲作','晁說之','宋','宋诗','song-poetry','','[]','知章騎馬似乘船，我今乘船若騎馬。',96,'全唐诗/poet.song.68000.json','["知章騎馬似乘船，我今乘船若騎馬。", "舳鳴艫噴索莫馭，左磬右控手不把。", "稍稍風恬可騁望，忽忽波駭難遊冶。", "既信河流怒頰豪，不疑瞿唐不可下。", "婆兒未用傖兒怪，赤馬能戰馳馬敗。", "傖兒自哂亦以屢，愧爾會稽夏仲御。"]'),
('e79108e5-0de8-40a8-b621-ff58fa904dea','憶江南贈通叟年兄','晁說之','宋','宋诗','song-poetry','','[]','北客而南征，蹇産非所志。',252,'全唐诗/poet.song.68000.json','["北客而南征，蹇産非所志。", "問津人尚絕，後來狂避世。", "流離竄斥者，其數非一二。", "風流稱南朝，文物始佳麗。", "要途在荆揚，僻左處吳會。", "吳會興國來，乃以丹漆貴。", "若其大才豪，終是江南最。", "君家住江南，豫章生次第。", "非但吾言逼，正爾百憂似。", "易見巖下電，難識斗間氣。", "結綬三十年，膽策未一試。", "譬如瑚與璉，詎落日中市。", "飄然渡浙江，式慰此憔悴。", "我屋梁園久，近卜嵩峰邃。", "海蟲難下筯，粟漿有賤嗜。", "不讀非聖書，忍更增疣贅。", "又不求甚解，未肯爭破碎。", "排悶亦吟哦，清潦誰滋味。", "自從住囚籍，一語不敢謂。", "豈惟要絕言，自憎生此喙。", "因君發吾狂，明當保嚴誓。"]'),
('510dbc28-64e1-46ab-a00a-65dc98fe2316','桃','晁說之','宋','宋诗','song-poetry','','[]','江南桃葉齊，江北桃根低。',36,'全唐诗/poet.song.68000.json','["江南桃葉齊，江北桃根低。", "各自擅風流，人情千載迷。", "桃花竟誰比，風雨日淒淒。"]'),
('f9ab333b-ffde-421e-9751-ea9c5eac0391','園中戲作白紵','晁說之','宋','宋诗','song-poetry','','[]','人間春色不須臾，芳草妬華不縈紆，楊花不分上空虚。',56,'全唐诗/poet.song.68000.json','["人間春色不須臾，芳草妬華不縈紆，楊花不分上空虚。", "宓妃一去百代無，不如雲外萬樂俱。", "南斗鼓瑟北斗竽，與酬酢者非君徒。"]'),
('6001b14d-83b4-4ec1-ada0-63bc567dd6f1','題沖弟詩卷','晁說之','宋','宋诗','song-poetry','','[]','阿沖五字來，江山千里餘。',60,'全唐诗/poet.song.68000.json','["阿沖五字來，江山千里餘。", "能爾麗金碧，定是勤詩書。", "文章與神明，動作本自俱。", "古人既云已，令公有規模。", "五世以文稱，故家誰復如。"]'),
('e576d651-26b7-4709-989e-a357103b1cc5','昨日之日','晁說之','宋','宋诗','song-poetry','','[]','昨日之日夢可追，今日之日愁能遲。',96,'全唐诗/poet.song.68000.json','["昨日之日夢可追，今日之日愁能遲。", "日之授謝亦何有，但莫令吾忠信虧。", "但莫令吾忠信虧，家山北斗身海湄。", "膾鯨斮蛟既不得，蝦虫腥鹹安用之。", "難將短髮留長恨，山中好在雞黍期。", "有船載書復歸去，高誼解釋幽林思。"]'),
('557561af-cca9-4387-9d7d-7cb95fd763e2','贈然公界方','晁說之','宋','宋诗','song-poetry','','[]','西方石爲簡，東山人可與。',24,'全唐诗/poet.song.68000.json','["西方石爲簡，東山人可與。", "不用量三江，聊以壓四虎。"]'),
('7ae6acc0-1819-4330-93ea-9a56d7f6cf86','偶見陳誠之一詩不勝欽歎輒紀贈求其巨篇深愧蕪累','晁說之','宋','宋诗','song-poetry','','[]','四明唐中葉，處士有陳深。',84,'全唐诗/poet.song.68000.json','["四明唐中葉，處士有陳深。", "書既殫萬象，詩想瑤華音。", "惜哉不並傳，裔孫自苦吟。", "豈易識此孫，海底珊瑚沉。", "邂逅我見之，昔恨阻沖襟。", "念我理歸棹，旅夢斷遙岑。", "願乞十九首，降盡河外心。"]'),
('08ec6bbd-8756-4852-9fa6-da868eb92cbd','贈琴照','晁說之','宋','宋诗','song-poetry','','[]','會稽城畔不見海，會稽城裏海有聲。',128,'全唐诗/poet.song.68000.json','["會稽城畔不見海，會稽城裏海有聲。", "此海之聲三尺桐，渺如渤澥含太清。", "惜哉寂寥三十載，月出愁空不肯明。", "邂逅彼孫曰沖照，燕坐之餘秋色横。", "搖手照乎休可已，悲風河水客心驚。", "我少學此今白髪，念昔知音冢草生。", "亦復何人能子知，空問世身不得輕。", "庭鶴待此朝入饌，子食有禁寧無情。"]'),
('feff7b6c-b0dd-4c6a-af56-1d39806a6f36','缺門遇王三兄師文','晁說之','宋','宋诗','song-poetry','','[]','生民本羈旅，何以娛今朝。',120,'全唐诗/poet.song.68000.json','["生民本羈旅，何以娛今朝。", "風雨崤澠道，離别秋冬交。", "忽復有好懷，故人道旁招。", "如狂語錯亂，疑夢情飄飄。", "君鬚何盡白，我志則全消。", "憂患君恐可，圖書興尚豪。", "玷珪宜委土，良驥乃繫匏。", "但願不再辱，敢慕無久勞。", "馬蹄分異縣，朔吹結同袍。", "三年以爲期，嵩少理居巢。"]'),
('8838b26a-e8a2-43fa-9133-dfb9220c93ee','河中府古興寄劉杜輿','晁說之','宋','宋诗','song-poetry','','[]','肘腋患難禦，垣墻傾莫制。',120,'全唐诗/poet.song.68000.json','["肘腋患難禦，垣墻傾莫制。", "茲者論戰國，破秦必在魏。", "初疑此語謾，身到識真是。", "河山既設險，信食以自治。", "秦雖百虎狼，得進不得退。", "襄王昧遠圖，蘇秦嗜近利。", "惜哉計畫疏，爲此山河愧。", "我懷誰與語，劉子長論議。", "方爲十二史，吾言不可廢。", "眺聽常思君，夢魂先朔吹。"]'),
('a4a19474-817a-4f81-a887-6079e118c906','至河中首訪鬼拔河圖有畫人云因陸學士移其壁乃毁寸盡令人感慨終日有作','晁說之','宋','宋诗','song-poetry','','[]','坎坎分明拔河戲，盛在北朝唐尚爾。',288,'全唐诗/poet.song.68000.json','["坎坎分明拔河戲，盛在北朝唐尚爾。", "畫手何人鄭子虔，妙不戲人惟戲鬼。", "更無獰厲可嚴怖，既曰依人人是擬。", "家家賈勇負勝餘，見之心寧不知耻。", "最是隋宮窈窕春，汗粧蓬髮羞相比。", "故宜落筆在蒲州，門外河來三萬里。", "鄰幾舍人有搨本，詩翁賦詩名更起。", "詠詩想畫二十年，客舍此邦心自喜。", "攬真永絕僞物欺，顧影豈盡形儀美。", "嗟予斷絕百事心，癡處留情獨在此。", "魑魅魍魎好奔迸，文彩風流終棄圯。", "出門訪之無處所，惜哉史君陸子履。", "但欲便坐易瞻玩，不知壁古難移徙。", "豈無剥落一寸餘，我願寶之若瓊蘂。", "不然當學補亡詩，收拾粉本細綱紀。", "或謂前年九鼎成，時無雜糅清如水。", "雖有高室誰瞰之，亦莫揶揄毛手指。", "帖壁不祥宜遁逃，綵門抛捘方靡靡。"]'),
('ec8cc984-7f2d-4dda-b2af-06f55f75c117','初至鄜州感事','晁說之','宋','宋诗','song-poetry','','[]','罪斥云一紀，常亦守官箴。',288,'全唐诗/poet.song.68000.json','["罪斥云一紀，常亦守官箴。", "置身江海畔，放言麋鹿岑。", "大吏不呵譴，小吏自堪任。", "蝦菜日異饌，著書敵南金。", "豈無二三子，善叩響不沈。", "更逢四高士，語妙何愔愔。", "俯攬塵土影，仰攄冰玉心。", "苦辛雖在昔，菑穫實於今。", "歸榜不忍速，故廬尚可尋。", "金閨朝轇轕，荃壁夢蕭森。", "領闊貽爾誚，新貴使我瘖。", "饑寒一丈室，奔走九秋砧。", "長坂馬難健，敗絮虱易侵。", "池西别故舊，税駕雕山陰。", "白翟無曩迹，赫連有脱鐔。", "幸哉廊廟術，勇不誇縱擒。", "誓表前日來，父子恩更深。", "戰士老腐粟，癯儒適懦襟。", "羊肥卧沙種，酒美西涼斟。", "農武自先烈，五律勤窺臨。", "禮樂被遠俗，三嘆斥哇淫。", "勉旃不再辱，聊爾容華簪。", "斂迹有餘愧，難聞弦誦音。", "尚喜屋山阿，雙泉如鳴琴。"]'),
('71e75017-07a2-41ba-a091-bc1bf17f8c18','趨延安過野猪嶺','晁說之','宋','宋诗','song-poetry','','[]','塹峭十月寒，一步不得整。',36,'全唐诗/poet.song.68000.json','["塹峭十月寒，一步不得整。", "如何騎鯨客，來度野猪嶺。", "遙語謝康樂，爾輩易清省。"]'),
('526e76b0-f44f-4b60-9538-ce930a9629ac','題楊如晦二畫 蜀道圖','晁說之','宋','宋诗','song-poetry','','[]','山鈎樹白何年歲，流瀑可聽下無地。',32,'全唐诗/poet.song.68000.json','["山鈎樹白何年歲，流瀑可聽下無地。", "行人愁絕却無愁，始信宜歌蜀道易。"]'),
('50bc16b2-1efd-4afa-9bf8-6344eb1ca5ea','題楊如晦二畫 邊鸞雉','晁說之','宋','宋诗','song-poetry','','[]','駭雉丹青人姓邊，無花無石自瞿然。',32,'全唐诗/poet.song.68000.json','["駭雉丹青人姓邊，無花無石自瞿然。", "已能倚壁音聲絕，何用蹲飛欲上天。"]'),
('8e0632f2-9e5e-4b0b-8721-055d092e2237','三川言十數年前嘗有一短帽騎驢之士半醉徘徊原上久之曰三川非昔時比矣恍惚失其人所在有收杜老醉遊圖者物色之知爲杜之再來也予獨鄙之作詩二首  其一','晁說之','宋','宋诗','song-poetry','','[]','君不見少陵有客字子美，三賦獻罷胡塵起。',163,'全唐诗/poet.song.68000.json','["君不見少陵有客字子美，三賦獻罷胡塵起。", "招魂收涙謁行在，寧論家室三川裏。", "雲寒日淡劍閣深，翠華望斷塵埃底。", "狼虎食人大道傍，回首妻孥須怖此。", "亦嘗寄書問訊之，鯉魚何在滄溟徙。", "晚年雖卜浣花居，心折秦雲恨有餘。", "茯苓不御丹砂就，仙去還來縱目初。", "乾坤宿醉參横醒，且策東家舊蹇驢。", "鄰里一人安可得，亦無墳冢可蓁蕪。", "人間偪仄何偪仄，却自騎驢追李白。"]'),
('557a9729-076a-41ee-9289-23132b59405e','三川言十數年前嘗有一短帽騎驢之士半醉徘徊原上久之曰三川非昔時比矣恍惚失其人所在有收杜老醉遊圖者物色之知爲杜之再來也予獨鄙之作詩二首  其二','晁說之','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君不見杜老死去傲九天，肯顧帑臭下山川。',152,'全唐诗/poet.song.68000.json','["君不見杜老死去傲九天，肯顧帑臭下山川。", "問予何事知其然，此世此老無姻緣。", "平生志願得酒眠，暫時去作酒中仙。", "況今仙侣瓊琚連，瑤池醉倒阿母前。", "一瞬人間億萬年，泰山爲塵海作田。", "何處更復有山川，鳳凰五色歌雲烟。", "三川何人莫浪傳，汝曹虱腦真可憐。", "華清有夢亦狂顛，夜闌秉燭仍悁悁。", "君不見狄郎志尚冰玉堅，獨聞此老近作佳城篇。"]'),
('66f385bc-864d-4820-89e4-d6ba1a060730','萱草','晁說之','宋','宋诗','song-poetry','','[]','山中萱草三赤長，山中高人萬事忘。',64,'全唐诗/poet.song.68000.json','["山中萱草三赤長，山中高人萬事忘。", "欲借忘憂汝輩力，世間兒女徒顛狂。", "汝亦忘憂非世憂，臨風恐汝亦分將。", "願爾忘憂忘終始，莫教老大空悲涼。"]'),
('c4735786-856d-45cd-9df4-9dc0c2f7e96b','鄜州張路鈐處見東坡所書漁父四首感歎之餘因思諸王孫伯言善歌此辭每以爲樂作寄伯言視張','晁說之','宋','宋诗','song-poetry','','[]','庾郎幾尺大腰圍，江北江南有好詩。',128,'全唐诗/poet.song.68000.json','["庾郎幾尺大腰圍，江北江南有好詩。", "今日王孫渾得似，仍知漁父醉醒時。", "爲我高歌掩明鏡，上方涼簟鬼神悲。", "我曹早有江湖興，風雨輕鷗細細隨。", "君朝明光我圁洛，愁腸只有醉爲期。", "海外騎鯨消息斷，無窮飛絮解相思。", "孤舟本要載西子，欲付此聲知有誰。", "安西將軍元好事，紙背題來十襲之。"]'),
('d57af986-68ea-4b36-a192-0d5d9fd47eae','宿洛川嘉槐驛其槐真可愛因思李承之待制嘗爲此縣令有所建退省堂存焉','晁說之','宋','宋诗','song-poetry','','[]','昔爲扁舟客，益覺此生浮。',96,'全唐诗/poet.song.68000.json','["昔爲扁舟客，益覺此生浮。", "逮今郵亭役，重膇仍百憂。", "嗟予何所可，歸去無田疇。", "慚愧庭下槐，百年霜霰秋。", "上苑誰移根，兔目自山丘。", "曾見李長官，矯矯增風流。", "欲登退省堂，秀句吟白頭。", "天上問風月，還似當年不。"]'),
('897f60ba-a4ba-424d-b0b6-6023f439c1f3','三川誦杜老觀水漲詩','晁說之','宋','宋诗','song-poetry','','[]','平生少陵詩，佳處豈盡識。',144,'全唐诗/poet.song.68000.json','["平生少陵詩，佳處豈盡識。", "何敢窺意韻，尚且昧形迹。", "身到三川來，瞀瞀迷咫尺。", "連天穹谷句，忘饑三歎息。", "高高方若懸，下下仍如績。", "扶上而削下，乃在吾行役。", "突然念此老，鎔寫不可極。", "意中無遺境，象外有餘力。", "後來羣偷兒，蠧魚恣口食。", "安知九鼎珍，宜爾終身瘠。", "此行敢告勞，顧影若有得。", "不見水漲時，兩眼猶歷歷。"]'),
('559c2bf0-07cd-449c-b2b1-a794ce4adab4','感事','晁說之','宋','宋诗','song-poetry','','[]','十年三冬時，櫃火簾小室。',120,'全唐诗/poet.song.68000.json','["十年三冬時，櫃火簾小室。", "讀書似少疲，坐睡塵兩膝。", "飛雪封我窗，號風過我壁。", "時有可語人，對之亦默默。", "當時不知樂，興言在今夕。", "今夕何爲者，荒山事行役。", "僕馭同饑寒，惝恍若有失。", "旅舍既淒涼，臺牒更狼藉。", "始信柳柳州，幸此南夷謫。", "歸去亦何難，清時惟所適。"]'),
('88c4a022-7b64-4b16-9536-b5f78d65a51c','平昔於王褒贈同處士八絕中喜誦其龍尾禪室一首今連日行荒山中頗增幽居之興以其句爲一詩寄楊中立謝顯道劉壯輿陳叔易同趣歸期也有好事者亦不予鄙 井汲纔通徑','晁說之','宋','宋诗','song-poetry','','[]','山頭百尺井，有徑看如失。',24,'全唐诗/poet.song.68000.json','["山頭百尺井，有徑看如失。", "唯有參横時，山人起自汲。"]'),
('b08ba7c6-9885-4477-9af3-a123649f8432','平昔於王褒贈同處士八絕中喜誦其龍尾禪室一首今連日行荒山中頗增幽居之興以其句爲一詩寄楊中立謝顯道劉壯輿陳叔易同趣歸期也有好事者亦不予鄙 蓬蒿自杜門','晁說之','宋','宋诗','song-poetry','','[]','藜牀坐來久，前年曾到門。',24,'全唐诗/poet.song.68000.json','["藜牀坐來久，前年曾到門。", "聞道蓬蒿滿，秋風著舊根。"]'),
('9b1550b8-67f7-4a10-9062-18c18073037d','平昔於王褒贈同處士八絕中喜誦其龍尾禪室一首今連日行荒山中頗增幽居之興以其句爲一詩寄楊中立謝顯道劉壯輿陳叔易同趣歸期也有好事者亦不予鄙 人還虚室静','晁說之','宋','宋诗','song-poetry','','[]','何許人到來，得葯尋歸徑。',24,'全唐诗/poet.song.68000.json','["何許人到來，得葯尋歸徑。", "吾廬月不落，象外獨常静。"]'),
('5fe6cb75-a0c2-4e57-8c1f-2c2951661d26','平昔於王褒贈同處士八絕中喜誦其龍尾禪室一首今連日行荒山中頗增幽居之興以其句爲一詩寄楊中立謝顯道劉壯輿陳叔易同趣歸期也有好事者亦不予鄙 鳥宿暮林喧','晁說之','宋','宋诗','song-poetry','','[]','朱晚鳥歸宿，倦飛憎世樊。',24,'全唐诗/poet.song.68000.json','["朱晚鳥歸宿，倦飛憎世樊。", "綸巾久接狎，訴語不嫌喧。"]'),
('ba708ca9-a97b-4a07-a2d2-216d79d3e982','貧賤','晁說之','宋','宋诗','song-poetry','','[]','貧賤不可惡，白首不敢辭。',72,'全唐诗/poet.song.68000.json','["貧賤不可惡，白首不敢辭。", "聖人爲我戒，敢不周旋之。", "山王亦何事，五君詎見遺。", "奈彼後世何，論評相瑕疵。", "雖有解謿人，正自漫爾爲。", "寄言宦達子，努力向金閨。"]'),
('c18705af-9382-44b9-854a-b9a55e28eed7','送知府張路鈐還闕','晁說之','宋','宋诗','song-poetry','','[]','櫜戈未肯下靈州，白馬将軍今白頭。',96,'全唐诗/poet.song.68000.json','["櫜戈未肯下靈州，白馬将軍今白頭。", "将軍父子重儒術，坐有綠衣人則休。", "六年謡頌流圁洛，卧使雕山添岞崿。", "看山飲水無一事，日俸歲饑欣自若。", "匹馬飄飄朝九天，晚交送别亦潸然。", "煩君去路望嵩少，猿鶴相思端可憐。"]'),
('d58fe45d-fb89-4477-a3c3-30c5c38aae99','思四明所居與桃紅渡相對','晁說之','宋','宋诗','song-poetry','','[]','今朝旅恨到何處，軒窗直對桃花渡。',32,'全唐诗/poet.song.68000.json','["今朝旅恨到何處，軒窗直對桃花渡。", "桃花渡上風吹雨，道人芒屩誰來去。"]'),
('b6a9d299-51e5-4e72-8b48-846142a01bea','涼州女','晁說之','宋','宋诗','song-poetry','','[]','涼州女，紫塞春，輕黄濃黛君莫謳，漢宮曾此選才人。',64,'全唐诗/poet.song.68000.json','["涼州女，紫塞春，輕黄濃黛君莫謳，漢宮曾此選才人。", "鹿角角，魚鱗鱗，有山有水無此珍，我强寛愁亦怒嗔。", "逢著澄江悔不詠，功曹豈自誇詩聖。"]'),
('72a6a99a-3de4-4321-b356-553bd38d6aa2','楊班湫神恩加廣應公以其誥祭之','晁說之','宋','宋诗','song-poetry','','[]','平生笑殺詛楚文，今朝鄜峙祭湫神。',320,'全唐诗/poet.song.68000.json','["平生笑殺詛楚文，今朝鄜峙祭湫神。", "嗟爾湫神何爲者，上公衮冕皇恩新。", "日出輝輝收霰雪，彷彿拜命若可親。", "湫神傳云是楊班，墳墓突兀自姚秦。", "當時功閥今不著，崔蕭之史討無因。", "将軍得名宜勇哉，里俗所頌疑未真。", "黄蜂往媒康氏女，親迎波間不敢嚬。", "至今七夕後二日，康家送女紛紅巾。", "神視可已胡不已，清明之德先諸身。", "湫初來徙雷霆夜，鬼借百車載淵奫。", "宜囚厲鬼縛惡虎，螟螣何足煩怒嗔。", "邦人不困亦不饑，山可夜入耕陽春。", "初無粳稻勞灌溉，黄𢇲黑黍易與仁。", "敢言此水淺於舊，霶沱雨起雲輪囷。", "千人一日酌不竭，神物所寓誰敢塵。", "豈但簫鼓十州遠，祭秩已入四瀆倫。", "異時香火故允會，品極勢重力益振。", "位浮於人神所殛，神忝厥職亦愧人。", "我勞再拜不私禱，上佐邦國下斯民。", "敢學韓子炭谷湫，嘲慳悔怪徒踆踆。"]'),
('bd9de3dc-4594-4fed-a170-1baa7a8c7958','寄琦公住小溪','晁說之','宋','宋诗','song-poetry','','[]','窮塞歲暮懷，琦公實真侣。',48,'全唐诗/poet.song.68000.json','["窮塞歲暮懷，琦公實真侣。", "恨此長城風，不送小溪雨。", "夢斷七十强，心留五字苦。", "斯世何寂寥，無人稱支許。"]'),
('87efd125-d3a1-477c-af75-5faff7ff26d6','寄光公','晁說之','宋','宋诗','song-poetry','','[]','湖上石楠花出屋，待久老僧來默默。',64,'全唐诗/poet.song.68000.json','["湖上石楠花出屋，待久老僧來默默。", "徐言經歲不出門，偶向今朝移苦竹。", "有琴掛壁積塵埃，强之使彈響山谷。", "至今兩耳猶泠泠，邊風日夜相思曲。"]'),
('85a38bab-305f-4d70-9e6d-adb47233fc86','洛川驛中夢與一故人作詩十餘韻既覺惟記其兩句南山絡條華四顧吃所哀因識之','晁說之','宋','宋诗','song-poetry','','[]','西征豈不樂，夢中詩佳哉。',48,'全唐诗/poet.song.68000.json','["西征豈不樂，夢中詩佳哉。", "南山絡條華，四顧吃所哀。", "山川今可夢，小謝恨能裁。", "無令辜此夕，羸馬空徘徊。"]'),
('42e9eaad-2a56-45cb-a1ab-49be2f4ca621','君子有所恨','晁說之','宋','宋诗','song-poetry','','[]','君子有所恨，擊指血不躁。',60,'全唐诗/poet.song.68000.json','["君子有所恨，擊指血不躁。", "相望已千古，欲語安得到。", "荆卿無劍術，商君棄霸道。", "二子苟不然，功烈迴穹昊。", "嗟哉淺丈夫，不自極懷抱。"]'),
('2ab84610-4c37-429b-96dc-59b20e6d07bc','洗山','晁說之','宋','宋诗','song-poetry','','[]','公事豈不猥，吾性自有適。',120,'全唐诗/poet.song.68000.json','["公事豈不猥，吾性自有適。", "驩言春風物，洗山出怪石。", "何幸此土壤，頑驁壓空碧。", "嶄巖有天姿，畚鍤不待力。", "横如劍出泥，縱若月退蝕。", "乃知凶讒輩，暫爲忠良賊。", "后皇德清明，萬類各有職。", "吾悲兹世人，因之聊嘆息。", "嘗聞道人語，無垢法第一。", "多謝讀易者，洗心如玉璧。"]'),
('c9aa7265-f2ac-4725-b3b9-576e010ae898','二月初山上作','晁說之','宋','宋诗','song-poetry','','[]','與春相别云一歲，遼鶴有恨不足加。',160,'全唐诗/poet.song.68000.json','["與春相别云一歲，遼鶴有恨不足加。", "意韻寂寥莫我適，起逐春風山逕斜。", "春風自與時窈窕，豈爲來開桃李花。", "不然春來已幾日，何處桃李不枯槎。", "乃知桃李善卑陬，遠交深託待紛葩。", "政如世間嫵媚子，巡牆倚戶漸齒牙。", "公卿初豈以爾故，腰金佩玉牢聲華。", "區區更憐蜂蝶輩，草根花底爲生涯。", "此理前人未見之，我今獨得頻咨嗟。", "生無京國名園分，況此邊城萬里沙。"]'),
('374d9a95-a0b5-4537-949f-60b4180b4dc0','夜雨','晁說之','宋','宋诗','song-poetry','','[]','夜雨豈不好，欠竹與芭蕉。',60,'全唐诗/poet.song.68000.json','["夜雨豈不好，欠竹與芭蕉。", "可想春意足，不聞聲蕭蕭。", "清夢江之南，雲霓正逍遙。", "舊遊二三子，爲我吹笙簫。", "覺來耳餘清，明日是何朝。"]'),
('0f2b7045-8879-4b90-add3-8958a89c058e','久留帳下日夕思歸輒作長言一首告别經略安撫侍郎','晁說之','宋','宋诗','song-poetry','','[]','亂山急雨佐吾愁，春去已遠人淹留。',96,'全唐诗/poet.song.68000.json','["亂山急雨佐吾愁，春去已遠人淹留。", "誰能一飲一車酒，縱談醉膽下涼州。", "元戎高韻撫鸞凰，舊有沙堤幾步長。", "眼底不堪論往事，且誇羯鼓似邠娘。", "應憐逋客羞澀餘，思歸欲自駕柴車。", "月邊風冷不得住，凡骨從來有曼都。"]'),
('8cf74ac1-185d-4591-9e87-714236a98d31','聽唱秦少游溪路雨添花詞感舊作','晁說之','宋','宋诗','song-poetry','','[]','秦郎不知我，我豈知秦郎。',144,'全唐诗/poet.song.68000.json','["秦郎不知我，我豈知秦郎。", "相逢每戲劇，此狷而彼狂。", "坐有今輔弼，正色屢低昂。", "逮今白髮垂，悔昔少年場。", "一聞溪路雨，淚與雨争行。", "黄鸝千百在，斯人今則亡。", "如其並老去，娛樂豈遽央。", "況復有諸生，遺頌滿汝陽。", "瘴霧殺君時，龍門曾慟傷。", "今雖苟生活，蒼蠅待我傍。", "誰家有歌喉，此曲宜斷腸。", "攄我一夕恨，與世同悲涼。"]'),
('f8c98e71-bfca-4209-8e39-000b2e6f357c','書事學謝康樂','晁說之','宋','宋诗','song-poetry','','[]','南北夐綿絡，同名圁與鄞。',156,'全唐诗/poet.song.68000.json','["南北夐綿絡，同名圁與鄞。", "歲月老羈旅，何事勤所勤。", "情勝古今契，身以邪正分。", "清音幸先後，曠懷得朝曛。", "山腰轉嘉樹，風袖落閒雲。", "盤磴去來迷，飛泉高下聞。", "龍柏肯予媾，上苑侍吾君。", "三花論繾綣，丹丘舊絪緼。", "中抱既兀兀，外騖徒紛紛。", "映窗有翰墨，滿架亦典墳。", "攄虹宮棟宇，流汗程斧斤。", "少時喜詭俗，老境思迨羣。", "不復夢江湖，詩成心自欣。"]'),
('c287b4e3-80f6-40fe-8737-bba7ae6ef9d0','書觸目','晁說之','宋','宋诗','song-poetry','','[]','山以石得名，土惟山之賊。',120,'全唐诗/poet.song.68000.json','["山以石得名，土惟山之賊。", "如何云此山，土石相充斥。", "土上而石下，無良躋有德。", "土實最下底，位高忝厥職。", "或云三千年，此土化爲石。", "頑陰不堅陽，如寄暫容迹。", "因知造化功，不出纖毫力。", "君子自苦辛，小人多羽翼。", "念從開闢來，久矣莫變革。", "吾其奈此何，唧唧復唧唧。"]'),
('31636046-7679-4481-b91b-b148b48fddcd','題鄜州牡丹','晁說之','宋','宋诗','song-poetry','','[]','牡丹憎我真惡客，不解飲酒不吟詩。',128,'全唐诗/poet.song.68000.json','["牡丹憎我真惡客，不解飲酒不吟詩。", "欣持一尊勸花飲，那知不醉但淋漓。", "爾花既醉應似我，耿耿一世幾傷悲。", "綠珠樓下香猶在，西子舟中意尚遲。", "三尺晏嬰頻欲殺，爾何夭矯尋常爲。", "沅湘草木共憔悴，幽蘭何足九畹滋。", "昔人妙語不爾發，顧我安得有好辭。", "晚來亦解意自足，秀色直可餐待肥。"]'),
('6c192402-a3e6-438f-8208-8465b9f23e1a','寄陳留江子我','晁說之','宋','宋诗','song-poetry','','[]','江家宅在嚴家瀨，亦有商聲歌半夜。',64,'全唐诗/poet.song.68000.json','["江家宅在嚴家瀨，亦有商聲歌半夜。", "不煩死魚遠吐墨，誰識天馬早流赭。", "嗟予久已烏角巾，愧爾當年白蓮社。", "唯昔灊山見老禪，枉嘆門人才下下。"]'),
('73d7022f-56b4-49c5-9449-45efe733233a','庚子初伏前一夕大雨','晁說之','宋','宋诗','song-poetry','','[]','雨來夜早晚，夢斷驚所向。',120,'全唐诗/poet.song.68000.json','["雨來夜早晚，夢斷驚所向。", "鼓鼙聲後先，龍蛇勢下上。", "奈此老屋何，詩書果何當。", "幸矣托皇州，高枕得無恙。", "瑞物日紛紜，豈我獨飄蕩。", "興言反山楹，羸思輒以張。", "疏泉到雲根，松竹青益放。", "胡不返柴車，於焉事鬱怏。", "平生知顧行，短髮增惆悵。", "明朝入初伏，金火兩無恙。"]'),
('e0cd4032-a516-48de-a984-5ecfa39dac09','次韻和江子我卧病謝予相過之作','晁說之','宋','宋诗','song-poetry','','[]','棄婦不言貧，孤兒不知病。',120,'全唐诗/poet.song.68000.json','["棄婦不言貧，孤兒不知病。", "美疹亦何有，衰蓮披綠浄。", "大昜疾無妄，要且觀情性。", "我來自山中，非征亦非聘。", "但恨清風薄，安識皇都盛。", "況聞藥艾攻，之子駭觀聽。", "策羸七里灣，憂醉豈易醒。", "今兹早嘗饌，高人能自勝。", "不廢五字吟，久與金石稱。", "我老言亦衰，同鳴不相應。"]'),
('b7a0edbc-074c-4d51-b608-df2efbf7c788','數蒙楊澤民秀才惠佳篇謝以長句','晁說之','宋','宋诗','song-poetry','','[]','嘉陵江聲不到耳，嘉州清音得之子。',64,'全唐诗/poet.song.68000.json','["嘉陵江聲不到耳，嘉州清音得之子。", "豪英磅礴狎鷗鷺，金錢棄擲等泥滓。", "青樓不使白髮生，萬恨都歸一杯裏。", "三蘇死後三川愁，君輩人才誰所喜。"]'),
('49eb9a04-c522-46c5-b204-2680c797df73','以李約交遊晚歲重爲韻作五絕句别韓二十七  其一','晁說之','宋','宋诗','song-poetry','','[]','紅塵歲月晚，白社煙霞交。',24,'全唐诗/poet.song.68000.json','["紅塵歲月晚，白社煙霞交。", "相思得相見，作底不逍遙。"]'),
('e8766a3d-458a-4b29-b6af-bd8ceac9fdff','以李約交遊晚歲重爲韻作五絕句别韓二十七  其二','晁說之','宋','宋诗','song-poetry','','[]','幾歲不出門，一朝事遠遊。',24,'全唐诗/poet.song.68000.json','["幾歲不出門，一朝事遠遊。", "長安初豈遠，孤客難淹留。"]'),
('4be9be08-a79b-4e89-8e20-e1d2a70cdec5','以李約交遊晚歲重爲韻作五絕句别韓二十七  其三','晁說之','宋','宋诗','song-poetry','','[]','菡蓞露不遲，蒹葭霜豈晚。',24,'全唐诗/poet.song.68000.json','["菡蓞露不遲，蒹葭霜豈晚。", "我生寜免愁，别離無近遠。"]'),
('eb2f90cb-71f6-43c3-99f4-6f73ffff2656','以李約交遊晚歲重爲韻作五絕句别韓二十七  其四','晁說之','宋','宋诗','song-poetry','','[]','敝廬無良辰，荒田多荒歲。',24,'全唐诗/poet.song.68000.json','["敝廬無良辰，荒田多荒歲。", "貧賤重離别，君乎休富貴。"]'),
('aa3bafa6-71c9-45a4-8249-e8db5ec93a86','以李約交遊晚歲重爲韻作五絕句别韓二十七  其五','晁說之','宋','宋诗','song-poetry','','[]','少貴别離輕，老賤别離重。',24,'全唐诗/poet.song.68000.json','["少貴别離輕，老賤别離重。", "後日君亦老，我髪亦種種。"]'),
('850bacbd-587f-442d-b18c-1e88c11d00da','京居秋歎','晁說之','宋','宋诗','song-poetry','','[]','京居少蟋蟀，失我田園秋。',96,'全唐诗/poet.song.68000.json','["京居少蟋蟀，失我田園秋。", "何用外物感，不勝中心愁。", "少多王霸略，老窘衣食謀。", "神臯既絕分，蠻徼亦願遊。", "鵲飛徒繞樹，坎止信乘流。", "顧惟爾青簡，能令人白頭。", "當年魏公子，今日無遺丘。", "出門何所從，垂淚且復收。"]'),
('c3cf22b0-1a4f-4e48-8c36-c76fb6600dca','送周秀實知新昌','晁說之','宋','宋诗','song-poetry','','[]','尊公文律自瑰奇，雖持使節未相宜。',128,'全唐诗/poet.song.68000.json','["尊公文律自瑰奇，雖持使節未相宜。", "子敝青袍哦五字，州家不喜縣家嗤。", "十年主簿今遷陟，縣衙簿尉來趨揖。", "越絕山川舒嘯時，莫歎鑑湖今幾尺。", "鑑湖幾尺吾其那，聞道新昌佛仍大。", "昔賢墨妙誰識之，一日清風千嶂破。", "人間月色過中秋，天際風光稱遠遊。", "陽關本是西州曲，鷺舞蘭橈不解愁。"]'),
('d05a1d59-6065-4a4f-a25b-37cdba59c3f6','謝高四十子昂詩卷','晁說之','宋','宋诗','song-poetry','','[]','我有瀟湘淚，還供閶闔愁。',88,'全唐诗/poet.song.68000.json','["我有瀟湘淚，還供閶闔愁。", "故人過我窗燈下，謂言客子宜悲秋。", "往體格律乍相視，久矣揉練幾百過。", "不然何以解能云，是中不放客愁破。", "文字能自達，何處有富貴。", "莫愛離騷亡國音，學乎大雅則知未。"]'),
('3e902961-a2d3-4730-94dc-4272dfbee55b','送邵大兄知果州','晁說之','宋','宋诗','song-poetry','','[]','先生之子徵聘日，自當黌舍稱先生。',144,'全唐诗/poet.song.68000.json','["先生之子徵聘日，自當黌舍稱先生。", "即今白頭青眼絕，空持短策長安城。", "漢宮雨露一朝到，劍閣山川五馬行。", "既成詩書鄒魯俗，難忘家世伊洛情。", "穰橙鄧橘饒渠勝，魏紫姚黄如我盟。", "約束南充謝家女，飛空倦矣復齊氓。", "鴈遠難羣聲不斷，□□□□□□□。", "顧我寧無意遠遊，羸病不得俱徂征。", "長亭無酒酌君别，獨将此恨西南傾。"]'),
('21ceef78-4b14-48f0-a5d1-321ee110a446','送顧彌邵朝奉知錢塘','晁說之','宋','宋诗','song-poetry','','[]','錢塘宰是會稽客，一身見盡元與白。',112,'全唐诗/poet.song.68000.json','["錢塘宰是會稽客，一身見盡元與白。", "元白風流且置之，是家尊翁勇金石。", "早受申公國士知，誰任東坡邦人責。", "之子敢嗟官不達，惟慚家世無踵迹。", "大才小試亦丹青，衆前獨却自朝夕。", "童稚欣欣新有謡，湖山藹藹舊相識。", "定知不用酒遣閒，流行舉要百代曆。"]'),
('54643fb3-f673-4556-ae9e-0b5c4e7e195a','謝程致道監丞以秋夜直舍二詩相視并簡蘇在廷少監','晁說之','宋','宋诗','song-poetry','','[]','秋風雖云高，不到建章宮。',120,'全唐诗/poet.song.68000.json','["秋風雖云高，不到建章宮。", "巨麗發妙思，翰墨争豪雄。", "移子范舟興，入此潘廬中。", "詩成到誰手，蠒面絲髮翁。", "豈不憐此老，氣薾志亦窮。", "聊以壮觀之，行潦落長虹。", "低頭謾漠北，攘臂徒遼東。", "自娛蓬蒿興，敢傍珪璧叢。", "清時難但已，有感如霜鐘。", "慎莫視蘇子，是更得家風。"]'),
('77170bae-d8fe-4f28-b60f-a6f3506b2177','謝邵三十五郎博詩卷','晁說之','宋','宋诗','song-poetry','','[]','我嘗爲曆學，上元要極遠。',288,'全唐诗/poet.song.68000.json','["我嘗爲曆學，上元要極遠。", "上元有遠邇，疏密出早晚。", "顧惟爾大父，皇極探其本。", "唐堯上百代，日月來滚滚。", "因之知百索，孰可妄憎噂。", "子前視我詩，與子論詩壺。", "子詩既煥爛，我言得安穩。", "爲子極源流，無難如瓴建。", "風雅闢大田，騷些助鋤墾。", "曹劉鮑謝輩，風雨得藨蓘。", "閒居既識陶，詠懷宜知阮。", "不有鮑與謝，白也胡婉娩。", "苟無阮與陶，蘇州曷息偃。", "上下曹劉來，少陵自益損。", "豈易少陵學，浪走徒多踠。", "況復爾來人，不竈而市飯。", "大兒誇蘇豪，小兒争黄謇。", "詎知韓柳先，學大忘赫烜。", "餘事五七言，朝鸞參暮鶠。", "又如萬仞姿，松巖絕蘭畹。", "念彼形似徒，澀舌吞枯菌。", "何人分詩文，兩隊有魴鱒。", "子早知此病，我語出復返。", "何以謝子勤，王道不可緩。"]'),
('a349607f-6d69-4215-943f-58fadceab62c','庚子冬至祭鼎閣差充太祝致齋於內西廊待漏院以近法物庫有火禁甚嚴不勝晝夜寒苦輒成長言','晁說之','宋','宋诗','song-poetry','','[]','至日爲客昔人歎，況乃客次在齋宮。',112,'全唐诗/poet.song.68000.json','["至日爲客昔人歎，況乃客次在齋宮。", "齋宮所寓有火禁，冰食霜寝多淒風。", "豐屋高懸日不到，未信一陽生是中。", "嘗聞鼎以大祭祀，未聞祭鼎陳笙鏞。", "兹焉祭鼎戒羣吏，古也拜竈勞皇躬。", "森森鼎閣祚厥西，矗矗明堂配自東。", "天子萬歲調元象，歲歲年年爲祝工。"]'),
('2cc95e33-4880-4e50-ac62-10a67c8605b8','高藤州六觀堂','晁說之','宋','宋诗','song-poetry','','[]','曾子三省予未能，夫君六觀何自入。',144,'全唐诗/poet.song.68000.json','["曾子三省予未能，夫君六觀何自入。", "天台敖我三觀妙，君又三之彌有得。", "露下聚散俱已空，電出有無仍不實。", "一世假夢暫踟蹰，萬緣托幻聊戲劇。", "澄淵泡起不離中，端形影見無差忒。", "兹惟一心之所發，邈乎此心近不識。", "更須止之艮爲山，隨其觀處離非日。", "與君相遇紫陌邊，不謂我言無不急。", "君方度嶺駕朱輅，我言之外何所識。"]'),
('752a4f2e-a7a2-43b9-92b1-53a94b7d302a','詠老','晁說之','宋','宋诗','song-poetry','','[]','腳踏浮雲身已老，訪道修行恨不早。',32,'全唐诗/poet.song.68000.json','["腳踏浮雲身已老，訪道修行恨不早。", "曾見商周全盛時，不及唐虞古風好。"]'),
('58696b4d-014e-4fad-a16f-cfb7fb295d82','同表甥趙康游种范李園','晁說之','宋','宋诗','song-poetry','','[]','百態范氏石，千尋种氏木。',36,'全唐诗/poet.song.68000.json','["百態范氏石，千尋种氏木。", "灌以邠李水，禽鳥識故國。", "使我從今去，魂夢常不足。"]'),
('4b4d3637-7dd8-4687-b761-8c5a0401547a','蓬萊仙','晁說之','宋','宋诗','song-poetry','','[]','我是蓬萊山上客，暫到人間管春色。',64,'全唐诗/poet.song.68000.json','["我是蓬萊山上客，暫到人間管春色。", "謝家池館縱吟魂，卓氏酒爐迷醉魄。", "人間春色将奈何，瀲瀲灧灧濃如波。", "歸來說與秦王女，麻姑偷去唱爲歌。"]'),
('3b8b2e90-b85a-4a28-8f2d-92fbde6db6a2','十二弟寄所和邵子文病中感懷之作復次韻寄子文','晁說之','宋','宋诗','song-poetry','','[]','先生窮著書，寧比近術赦。',216,'全唐诗/poet.song.68000.json','["先生窮著書，寧比近術赦。", "天故使之貧，赤手唯書籍。", "或者窺殘篇，律呂起韶夏。", "微意有子傳，光燭不鄰借。", "大臣薦曰才，留守勸征駕。", "講席出正塗，肯以眇跛訝。", "生平畎畝心，願被草木化。", "卧龍終佐漢，捫虱聊倚華。", "二君獨何居，耿耿心中夜。", "不悟伊呂間，安容管葛亞。", "璞玉詎連城，祇堪雙則價。", "何事揶揄鬼，疾病尋舋鏬。", "井臼每苦煩，藥食則不暇。", "不藥得中醫，默符覆器□。", "哦詩便無恙，乞酒宴茅舍。", "彌荷天地恩，性命永其貰。", "饑鷹侍中輩，死矣一飽乍。", "顧我與君侯，更愧東山謝。"]'),
('21bf4330-3af2-4bc2-9f3e-4288b424403b','迎赦一首','晁說之','宋','宋诗','song-poetry','','[]','燈頭異花垂永夜，占云明日當有赦。',104,'全唐诗/poet.song.68000.json','["燈頭異花垂永夜，占云明日當有赦。", "咄哉無煩汝報我，三年郊恩遍天下。", "知人所知豈神聖，偷歡送喜真便佞。", "羲卦箕疇汝詎知，冰凍火炎子不問。", "曈曨日出迎赦來，沸渭頌聲何休哉。", "陛下萬歲御九垓，王母獻壽滄海杯，更看正仗單于陪。"]'),
('cac2990f-6ff6-402b-97ee-bf19ec6f1017','申謝經略安撫待制送酒之什','晁說之','宋','宋诗','song-poetry','','[]','真茶竊所貪，薄酒亦云嗜。',144,'全唐诗/poet.song.68000.json','["真茶竊所貪，薄酒亦云嗜。", "況此兩乘壺，旨哉出廳事。", "歌美秦州半，樽罍更幾倍。", "元戎眷非一，於焉則有二。", "癃老欲扶持，牢愁使破碎。", "風雪客歲殫，無隕故園淚。", "我實不能飲，自有愁常醉。", "顧彼昔之人，何必陶阮類。", "槌劍劇孟俠，文武衛公貴。", "宜飲不飲者，我言尚何費。", "顧分玉帳春，遠以金壺致。", "舊都新奏功，如花方高會。"]'),
('696786eb-e4bb-459a-9536-4d6c9c23539a','陰山女歌','晁說之','宋','宋诗','song-poetry','','[]','陰山女漢服，初裁淚如雨。',204,'全唐诗/poet.song.68000.json','["陰山女漢服，初裁淚如雨。", "自看顔色宜漢裝，琵琶豈復傳胡譜。", "赤車使者傳琵琶，翩然雌鳳隨凰去。", "豈不憐此女兒心，父母生身遠有祖。", "平生父母九原恨，得幸一朝收拾取。", "使者高義重咨嗟，衣裳盟會其敢許。", "漢装漢曲陰山墳，七十年來愁暮雲。", "即今山川還漢家，泉下女兒聞不聞。", "誰将一樽內庫酒，招此芳魂亦何有。", "崔盧舊族自豪英，顧此女兒慚色否。", "巍巍之功惟陛下，萬歲百男固宗社。", "赫赫雷電暫出車，陶陶韶濩詠歸馬。", "墨荘侍讀如尚在，應有好辭獻壽斝。"]'),
('ae4ef0d9-d662-4fcc-b66b-6af42a36a3ff','月下作','晁說之','宋','宋诗','song-poetry','','[]','今夜隴頭月，往歲沃洲山。',60,'全唐诗/poet.song.68000.json','["今夜隴頭月，往歲沃洲山。", "短髮添盡白，遐觀彌多閒。", "遙憐大定僧，注彩衲畦間。", "塵冠何可久，曳杖吾當還。", "胡不忘言休，自箴兹厚顔。"]'),
('b40516ff-b262-4ecf-aab4-56a5b4c8f526','恨契詩','晁說之','宋','宋诗','song-poetry','','[]','坎壈愚無計，慟哭老無淚。',264,'全唐诗/poet.song.68000.json','["坎壈愚無計，慟哭老無淚。", "居處近何適，隱遁遠何暨。", "爰來未嘗恨，始恨金石契。", "何朝鎔而泥，亦暮泐以滓。", "有美者伊人，平昔嘗自謂。", "此身敢自輕，實與劉向類。", "孰如同姓憂，斧扆況忠對。", "與我盛蘇門，何人忍棄背。", "顧彼蒼蠅姿，須臾來附驥。", "附驥只須臾，沒身有臭嗜。", "國中起四顧，誰門復擅勢。", "前日既居貨，今日宜入市。", "市王誠何知，多賤而少貴。", "懦劣既先奔，强梁亦晚至。", "俄然欣解榻，倐爾勇投袂。", "烈烈參貔貅，堂堂得英衛。", "雲朔土即復，悝于頸當繫。", "如或騎豬歸，鐵甲遮羞愧。", "功成麒麟閣，丹青更何視。", "莫能爲爾言，擊指血迸潰。", "況我本小人，西京仍已亟。", "所得果幾何，作詩深自勵。"]'),
('6f72dd05-a183-4025-9309-f56446f91ba3','記夢','晁說之','宋','宋诗','song-poetry','','[]','山上多曲木，澗底有勁草。',84,'全唐诗/poet.song.68000.json','["山上多曲木，澗底有勁草。", "乃知窮達性，多隨勢所到。", "此語自夢中，景物殊浩浩。", "頗逢平生人，歎息老非少。", "獨不偶貴勝，昔見非吾好。", "語類紫芝歌，敢不勉蹈道。", "孰能憔悴予，著之視同袍。"]'),
('2cd1632c-8ae2-40ab-9b4b-fdd34054b5fe','謀歸寄陽翟李九呂十四兄','晁說之','宋','宋诗','song-poetry','','[]','着身到雍隙，故人在陽翟。',144,'全唐诗/poet.song.68000.json','["着身到雍隙，故人在陽翟。", "白髮何冉冉，清夢徒歷歷。", "有美李将軍，詩是萬人敵。", "家封異姓王，身老二千石。", "呂侯幾世來，蟬冕必踵跡。", "如何此孫賢，早饑而晏食。", "門前潁水流，屋上嵩山色。", "天以延二老，世人何用識。", "祇應爾日來，爲我長歎息。", "我嘗從之遊，何難此投幘。", "籬下菊黄時，鴈背俯可即。", "嶽寺講時鐘，婆娑且連屐。"]'),
('19659596-5e0e-41b0-b05d-3c4b3615ed82','聞圓機累日病酒戲作存問之','晁說之','宋','宋诗','song-poetry','','[]','善人有怒而無嗔，美酒何曾病着人。',96,'全唐诗/poet.song.68000.json','["善人有怒而無嗔，美酒何曾病着人。", "夫君自是愁鬼着，愁鬼一勺百氣振。", "夫君何以致愁鬼，十年一官冷於水。", "況令復似未第時，酩酊長編痛料理。", "君言不覺身無聊，西家醪勝東家醪。", "是中有米亦可飽，枉費東坡歌小槽。"]'),
('f0644315-f2d8-41b1-be1e-f030e594075c','屈原石板上見圓機題詩因和之','晁說之','宋','宋诗','song-poetry','','[]','門掩自閒閒，樽空寧薄薄。',48,'全唐诗/poet.song.68000.json','["門掩自閒閒，樽空寧薄薄。", "妙語知杜美，剛腸識雷惡。", "饒花人豈貧，多竹地不薄。", "最道長官難，只愁里胥惡。"]'),
('b97e1682-f376-4167-bcf1-48b0cd976d8c','次韻邵子文書夢','晁說之','宋','宋诗','song-poetry','','[]','先生有道無寸田，長歌擊壤醉伊川。',368,'全唐诗/poet.song.68000.json','["先生有道無寸田，長歌擊壤醉伊川。", "今式玄冢高嵩巒，嗣子詩禮老益端。", "少從父友學其難，一書百讀口角涎。", "父友寸步簡策邊，聲名九州四海寛。", "時有狂瀾匯怒湍，百媸安肯一着妍。", "獨樂園中往復還，蝴蝶沼上青草煙。", "書成硯穴氣桓桓，蒼生屬望十九年。", "聖時未肯誤儒冠，倐見佩玉朝珊珊。", "汴洛迎送路接連，急急政如渴赴泉。", "跛者釋杖瘠肥羶，兵偃不用盧重環。", "貨利去若風中幡，抉蔀一發天下言。", "白髮舊德殿中間，經行求士趨傳餐。", "先生之子難鬱盤，綠衣春色行度關。", "羣賢並進讓後先，山摧棟折何茫然。", "人間此夢白日前，況乃枕簞夜穩眠。", "仙山塵絕遠囂煎，雲樓煙閣白鶴閒。", "若嚬若笑玉女顔，我欲並之無因緣。", "傍意若謂堪憫憐，是間有汝世之賢。", "此公不死神常全，王僑偓佺不及肩。", "汝曹蟻輩徒攻堅，欲子見之駭衆仙。", "子色不平羞青山，我爲子往問彼天。", "誰敢少弄天公權，蘧蘧夢斷目鰥鰥。", "但覺毛骨輕且便，賦詩不怕衆險艱。"]'),
('b5aa368c-f374-419c-9770-fd4f4e7b880d','月','晁說之','宋','宋诗','song-poetry','','[]','真月夜夜滿，妄見有盈虧。',48,'全唐诗/poet.song.68000.json','["真月夜夜滿，妄見有盈虧。", "譬如匣中鏡，一成豈合離。", "腥蟆與狡兔，謬及丹桂枝。", "我今盡掃蕩，庶識真月爲。"]'),
('dae458fa-dca5-4efc-bd67-b00ee531f96d','送曹資深受代還京兼簡劉養正','晁說之','宋','宋诗','song-poetry','','[]','韓王孫子何楚楚，不用根源論魏武。',64,'全唐诗/poet.song.68000.json','["韓王孫子何楚楚，不用根源論魏武。", "讀書射獵固自如，劇談大笑能爾汝。", "爲君相遇在東州，與我中分萬斛愁。", "我歸未得君歸去，風流應復屬曹劉。"]'),
('91c0dd2f-2a64-444f-85eb-0132f7598715','和二十二弟不相遇之作','晁說之','宋','宋诗','song-poetry','','[]','秋雲欲遘雨，惱此山河涼。',48,'全唐诗/poet.song.68000.json','["秋雲欲遘雨，惱此山河涼。", "柴門試一出，矯目歎林光。", "孔鸞勢自遠，鴻雁意亦長。", "先後日雲間，俗眼安得常。"]'),
('ea6b6ff3-d62b-4a9c-9dc8-44c9bc57d12c','秋吟','晁說之','宋','宋诗','song-poetry','','[]','友生吾所畏，言貌凛秋威。',48,'全唐诗/poet.song.68000.json','["友生吾所畏，言貌凛秋威。", "崔子稻畦晚，楊公玉田饑。", "階除昨夜霜，鐘鳴尚依稀。", "吾友豈憔悴，西山空崔巍。"]'),
('18689a34-a621-4ecb-b48b-d03d53332a62','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其一','晁說之','宋','宋诗','song-poetry','','[]','布種無多寡，收穫幾豐凶。',48,'全唐诗/poet.song.68000.json','["布種無多寡，收穫幾豐凶。", "老農知歲異，遠賈務日同。", "孰是勉無德，莫非矜有功。", "君何謝事早，兩世有四公。"]'),
('7bbbe8ea-d23a-4695-92a7-ab2881d6ac87','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其二','晁說之','宋','宋诗','song-poetry','','[]','念公多疾病，使我頻驚愕。',48,'全唐诗/poet.song.68000.json','["念公多疾病，使我頻驚愕。", "可恃膽氣大，何憂腠理薄。", "九丹詎淩空，八石聊扶弱。", "無煩問安否，冘冘亦自若。"]'),
('ecaeca2e-2538-4bbc-ab54-137ee4fb67da','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其三','晁說之','宋','宋诗','song-poetry','','[]','潁川美鳯凰，淮陽盛股肱。',48,'全唐诗/poet.song.68000.json','["潁川美鳯凰，淮陽盛股肱。", "皇恩既布濩，清羸亦作興。", "自知同涇渭，孰覺異鷃鵬。", "巍巍君子堂，而我得先登。"]'),
('788251d0-1a25-419c-ad5d-cfac5849cb5a','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其四','晁說之','宋','宋诗','song-poetry','','[]','人間陳五鼎，天上應三台。',48,'全唐诗/poet.song.68000.json','["人間陳五鼎，天上應三台。", "顧我幽居人，卒歲事田萊。", "首種既已薄，時雨又復乖。", "身事尚如此，與世宜不諧。"]'),
('6363c57b-ad1a-460e-8110-b39f9947bcde','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其五','晁說之','宋','宋诗','song-poetry','','[]','衮冕有人妖，鐘鼓成國蠧。',48,'全唐诗/poet.song.68000.json','["衮冕有人妖，鐘鼓成國蠧。", "可憐淩霜幹，不作濟川具。", "三易朝吾車，六詩暮吾輔。", "豈亦不自娛，菊徑而蘭畝。"]'),
('faa8c4d9-b1f4-4693-b6d4-963a572b729d','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其六','晁說之','宋','宋诗','song-poetry','','[]','末宦從遠投，沈痾得此心。',48,'全唐诗/poet.song.68000.json','["末宦從遠投，沈痾得此心。", "願言麯神降，何用官鬼臨。", "幽興落醴浦，清夢繞崧岑。", "使我既慚昔，奈何復愧今。"]'),
('e02d7057-a921-41ad-b393-a9018a6e4de6','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其七','晁說之','宋','宋诗','song-poetry','','[]','迷行常坎壈，守道自熙怡。',48,'全唐诗/poet.song.68000.json','["迷行常坎壈，守道自熙怡。", "伐蛟不恃力，刺虎寜用機。", "華屋非所尚，茅楹豈不宜。", "未覺覆盂安，詎知累卵危。"]'),
('9e1dc1ff-b356-4841-8dee-1653e506d569','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其八','晁說之','宋','宋诗','song-poetry','','[]','渡江慎且無，登樓戒亦莫。',48,'全唐诗/poet.song.68000.json','["渡江慎且無，登樓戒亦莫。", "有如鶴乘軒，便類燕巢幕。", "此君如寶玉，百火不一爍。", "又復如衢樽，醉不謝所酌。"]'),
('40c7b371-ffc5-40f1-a642-867656d6d9db','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其九','晁說之','宋','宋诗','song-poetry','','[]','君少我十歲，憐我空老大。',48,'全唐诗/poet.song.68000.json','["君少我十歲，憐我空老大。", "期君到雲霄，遺我餘謦欬。", "忽先辭漢禄，孰從仰周賚。", "顧惟神所勞，何論心乎愛。"]'),
('8c448c17-c3a0-4ab3-88fa-08b2ee1ceb15','說之方憂韓公表大夫疾遽致仕乃蒙傳視送陳州王樞密詩十首意典辭麗忻喜輒次韻和呈以公若登台輔臨危莫愛身爲韻  其一○','晁說之','宋','宋诗','song-poetry','','[]','能老彼形骸，孰疲此精神。',48,'全唐诗/poet.song.68000.json','["能老彼形骸，孰疲此精神。", "繄其抱病客，只是苦吟身。", "少出便十首，高興感五辰。", "嗟予强屬和，汲思如井輪。"]'),
('40ddf4b1-ac4a-4aa9-92bd-fc1b64862998','南門','晁說之','宋','宋诗','song-poetry','','[]','今上元年九月初，正南門鏁澀關樞。',184,'全唐诗/poet.song.68000.json','["今上元年九月初，正南門鏁澀關樞。", "城上日出三丈餘，城下戢戢人嗟吁。", "最憐縱横荷菜夫，欲殺青蒨成蔫菸。", "驢駝嚙膝聚不驅，羣雞孤鵝鳴相呼。", "邈然不數半與豬，客子四散别門趨。", "逐臣過焉問何如，知者不告色不舒。", "或言上皇帝有符，北門不開留翠輿。", "金人忽屯城北隅，方今明日達聰俱。", "司門郎官上奏無，未幾金人來坦塗。", "城南鐵騎柴奚車，焚蕩輔郡陵别都。", "衣冠南下滿江湖，白頭辭臣思獻書。", "洪範災異信豈誣。"]'),
('8254fd1c-c52d-4168-a6d6-d3facf6ac298','送蘇季升出守明州','晁說之','宋','宋诗','song-poetry','','[]','四明白髮船司空，喘息使君如不容。',144,'全唐诗/poet.song.68000.json','["四明白髮船司空，喘息使君如不容。", "自爾怕道四明守，問今何人休嚇儂。", "丹陽丞相蘇公子，氣和體正如家公。", "坐令山水生清思，雲南雲北揮毫中。", "江瑤海扇不入筯，肯以腥醎水驛供。", "百家之産歸一器，詔下掃除勤耕農。", "皇威海外讋蛟蜃，麗人大舶安得通。", "元年新政見此守，丞相蘇公真有後。", "過家上冢問阿兄，四海澄清眼明否。"]'),
('4bf8833f-2e2f-4d09-801f-776bd510f1c8','送陜西運使陸郎中','晁說之','宋','宋诗','song-poetry','','[]','二十年來關內客，眼明太華高太白。',112,'全唐诗/poet.song.68000.json','["二十年來關內客，眼明太華高太白。", "今日前驅使者旌，雞舌香餘新日月。", "春初敵騎逼王城，公在城頭佐天策。", "将兹膽略撫西戎，蕭關遠爾無堅敵。", "便使秦人不告饑，軺車與爾同休戚。", "惟應拂拭舊題名，幾人身在空相憶。", "爲我寄謝錢都統，鬢間不許霜雪積。"]'),
('6f08dfc9-85ea-4f80-99c4-20eacfeaedc2','今年暑氣甚劇六月二十八日初伏之末風雨甚横既而便晴有感作','晁說之','宋','宋诗','song-poetry','','[]','庚暑既云初，甲運将復浹。',240,'全唐诗/poet.song.68000.json','["庚暑既云初，甲運将復浹。", "正當相火行，如持溽土□。", "炎熾及雲霄，煩燠況僕妾。", "皇天不勝毒，一日思自愜。", "箕畢靡遑舍，巢穴徒更讋。", "兩脚壓嶙峋，風威振巀嶫。", "滂沲驅鬼神，庭除覓舟楫。", "扶搖百年木，斬馘一瞬捷。", "豈容壺蟻蠧，諒搜芥龍厭。", "我屋茅何支，彼田禾已躐。", "簡編恨枯槁，縱横恣涾浥。", "泉酌便無情，湯餅誰爲饁。", "亟欲撝絺綌，從此正經蹀。", "矯首凌鶴翔，奮身脱鳶跕。", "寧知不亹亹，俄覺復燁燁。", "强陰難節制，衰陽易威脅。", "藴隆增幾倍，怫鬱起重疊。", "蝗陣暫侜張，穀根自安貼。", "蜩狂噪百尺，鳩慚勞兩頰。", "我亦悶賦詩，欲語而膽怯。"]'),
('86eca322-854e-4e00-b22c-2dfdcc397812','柳集亡食蝦蟆詩因有作','晁說之','宋','宋诗','song-poetry','','[]','我讀柳侯詩，不見蝦蟆篇。',240,'全唐诗/poet.song.68000.json','["我讀柳侯詩，不見蝦蟆篇。", "所亡諒非一，撫卷爲慨然。", "不應流落人，吟咏亦不前。", "問爾胸中奇，何以能棄捐。", "湯湯柳之水，漁無魴與鱣。", "背脊得蝦蟆，樽俎薦春鮮。", "莫言形貌惡，素蛾與嬋娟。", "柳侯比豢豹，賴以韓詩傳。", "如聞大呂方，乃無黄鐘圓。", "問之州鳩氏，政令恐不宣。", "我嘗求元唱，其深在九淵。", "侯詩蝦蟆美，人人垂饞涎。", "蝦蟆竊自懼，子孫将不延。", "奈此文字何，偷攘付蜿蜒。", "蜿蜒與蝦蟆，腥介每相憐。", "遂令連璧孤，不知今幾年。", "念我少年日，未識侯詩妍。", "晚見海上老，口誦盡殘編。", "因之得揚搉，今古共周旋。", "此老可補亡，已矣淚潺湲。"]'),
('1f7f4812-4f3b-47b0-aafc-193b8b6e7f94','舟子語','晁說之','宋','宋诗','song-poetry','','[]','晁子被放逐，四方何所止。',252,'全唐诗/poet.song.68000.json','["晁子被放逐，四方何所止。", "隨衆到淮口，脱身亂兵裏。", "長淮歲暮風，舟楫不得艤。", "因之狂雨來，青山白浪底。", "風雨與波浪，三者酷鬬靡。", "北客怖未嘗，波神得自喜。", "舟子言勿怖，此是衝風爾。", "前風衝後風，縱神雜横鬼。", "吼怒夜潮落，倐忽熟風起。", "衝風如小人，熟風若君子。", "明日復衝風，又非前之比。", "舟子言可賀，此風即當死。", "盛大不死者，從何睹神理。", "京貫黼攸輩，萬貨他手委。", "官知其然歟，幾年干天紀。", "神降與人言，化酒幻桃李。", "上真怒中華，實錫羯胡祉。", "破我諸州鎮，胡陣風從指。", "漢兵遂喜北，不走即降矣。", "風伯不祐我，豈獨在兹水。", "舟子語可書，聊以視知已。"]'),
('11f58647-5c6c-4b31-97f0-a34c0ff29131','十二月十六日立春','晁說之','宋','宋诗','song-poetry','','[]','今年立春常年殊，要乘生氣克胡雛。',96,'全唐诗/poet.song.68000.json','["今年立春常年殊，要乘生氣克胡雛。", "鐵騎一歲再渡河，青帝寧不行天誅。", "相公廟略託諸天，亞輔割地甘丘墟。", "天窮地蹙否極泰，王城門開陽光舒。", "天子當陽朝萬國，不擊土牛擊群狐。", "青青原野無横斂，四民安樂祖宗初。"]'),
('14e129d9-decc-4795-b383-9fbfdbc951d0','旅次大風','晁說之','宋','宋诗','song-poetry','','[]','臘尾春頭難作客，借書數帙共徘徊。',128,'全唐诗/poet.song.68000.json','["臘尾春頭難作客，借書數帙共徘徊。", "洛陽東風遠尋我，水波參折馮陵來。", "可憐難問洛陽事，念我邑墓有餘哀。", "漢兒辮髪益胡軍，望望都門何日開。", "勤王之師未肯發，怒飈激起無摧頹。", "黄河高浪大岯山，金賊欲遁不得回。", "吳檣楚柁日千里，大府有粟寧待催。", "朝廷號令必偃物，我得歸到孝王臺。"]'),
('67f65b2c-0948-400b-ac1e-6a590bf75cc3','曹仁熙畫水壁','晁說之','宋','宋诗','song-poetry','','[]','夫子在川上，悠然嘆所逝。',168,'全唐诗/poet.song.68000.json','["夫子在川上，悠然嘆所逝。", "見逝不見水，身與水不二。", "天維及地軸，去矣不可制。", "日月徒勞勞，出入丈赤地。", "莫言此身微，久圍待經濟。", "或指波濤觀，姑在蹄涔內。", "後人不及門，有口安足議。", "劣得蒙荘周，動與呂梁會。", "肇公識前波，不共後波繫。", "龐公橋柱流，奔湍是誰事。", "熟誇觀濤者，八月吳儂戲。", "瞪目不敢瞬，睫軟蛟鼉噬。", "多謝曹仁熙，筆端落妙意。", "欲採甓社珠，於此觀粲翠。"]'),
('1ebdde59-38a1-42b6-a8d7-0a011915bd7f','張平叔家絲糕','晁說之','宋','宋诗','song-poetry','','[]','君家絲糕何處絲，三月晴天蕩漾時。',48,'全唐诗/poet.song.68000.json','["君家絲糕何處絲，三月晴天蕩漾時。", "繭頭越女繰不得，却煩素手與晨炊。", "客子千頭萬緒苦，方寸五紽誰得知。"]'),
('e650a896-47cb-45b0-b3e4-e3e977d3f6b0','次韻謝人惠詩','晁說之','宋','宋诗','song-poetry','','[]','東郊久不開，春風宜斷絕。',120,'全唐诗/poet.song.68000.json','["東郊久不開，春風宜斷絕。", "梅信豈得芳，何處香芬烈。", "徒令湖海士，借論古人傑。", "奈我貧病何，蕭寺多積雪。", "終天不出門，圖史欣羅列。", "欲上皇帝書，廟堂誰稷契。", "遊魚清且直，飛鷺遠更潔。", "顧彼四輪車，禦侮難結轍。", "一朝叩旅舍，問我來何說。", "再拜謝之子，我正如子拙。"]'),
('2b81fc7a-00ba-41e9-a990-77b55f9623d6','謁嶽廟','晁說之','宋','宋诗','song-poetry','','[]','吳楚江淮接海濤，百龍有職驅黿鼇。',128,'全唐诗/poet.song.68000.json','["吳楚江淮接海濤，百龍有職驅黿鼇。", "空中甍桷森然見，天上雲霓不得高。", "穆穆冕旒嚴帝制，紛紛牲幣自神臯。", "不知嶽帝從何帝，要是天曹各有曹。", "南極祝融炎劍戟，東方太皥却旌旄。", "若容羲仲篡羲叔，亦許帝舜囚帝堯。", "牛斗吾鄉如失位，奎婁魯野豈専朝。", "人間職分已顛倒，願正天紀尊嶤嶤。"]'),
('8ace62f1-1970-4af2-8b69-d3ac573310cc','淮南王','晁說之','宋','宋诗','song-poetry','','[]','淮南王，解燒金，胡爲黄葉落故林。',64,'全唐诗/poet.song.68000.json','["淮南王，解燒金，胡爲黄葉落故林。", "神仙鼎氣覆千里，草木姿媚鐘磬音。", "誇誕之語恐難信，儻然安得我登臨。", "即今巨盜處處起，天子不貪淮南地。"]'),
('be649a6b-050a-42a8-809d-51b16e594c25','贈陸遠大夫','晁說之','宋','宋诗','song-poetry','','[]','顧陸筆墨森威儀，身後猶爲道子師。',96,'全唐诗/poet.song.68000.json','["顧陸筆墨森威儀，身後猶爲道子師。", "欲觀道子觀顧陸，陸孫定自有天資。", "或言苦學龍眠者，不頌世德誇義兒。", "肯爲俗人落吾筆，王許支公實我知。", "倘非從容接笑語，安得生氣今如兹。", "湖光萬丈明珠滿，對此佳客申愁眉。"]'),
('55773966-3e46-4def-894a-716cba8b00bc','又題陸大夫畫逸少遠遊道林','晁說之','宋','宋诗','song-poetry','','[]','會稽內史勤筆墨，遠遊中坐無一物。',64,'全唐诗/poet.song.68000.json','["會稽內史勤筆墨，遠遊中坐無一物。", "何事支公愛神駿，團揭鼻齒映頂足。", "拄杖圓笠如意負，蓬髪著巾俱肅肅。", "相向忘言在何許，望斷高山空翠麓。"]'),
('125b33b5-7502-48f8-81b2-e23b3d0e6589','再題王許支圖','晁說之','宋','宋诗','song-poetry','','[]','海嶽登臨許遠遊，上乘雲氣下扁舟。',64,'全唐诗/poet.song.68000.json','["海嶽登臨許遠遊，上乘雲氣下扁舟。", "可憐畢竟不聞道，妙翰神騅却得留。", "右軍憤世猶懷古，何事一朝得支許。", "馬足不動羣奴癡，感深絕俗俱無語。"]'),
('a2659980-da31-4614-ac7b-a2b4931e6768','積善堂','晁說之','宋','宋诗','song-poetry','','[]','我家得姓自衛史，文王之昭鍾厥美。',320,'全唐诗/poet.song.68000.json','["我家得姓自衛史，文王之昭鍾厥美。", "西京御史府大夫，父慈子忠不惜死。", "至今墓上無曲棘，潁川歲時虔廟祀。", "中原喪亂厭風塵，南渡不及渡遼水。", "晚惟道武攬英雄，遼東之晁同興起。", "世封潁川刺濟州，子孫嬋媛冠劍偉。", "唐有賢良如漢初，名動集賢爲學士。", "是時海內圖書家，一晁未議張與李。", "忠實文華入本朝，三祖百孫同一體。", "中祖潁川襲遠封，東祖西祖復於濟。", "自從決策罷兵來，平進不厭百寮底。", "即今門戶益衰微，攬古懷今情曷已。", "上恩坱圠播無垠，宿莽心存春藿靡。", "漳州有母行百齡，疏封鈿服明光裏。", "夫人眼力尚針縷，拜恩不易從稚齒。", "初惟夫人有子賢，曰此布濩敢不俾。", "何勞夢帝血面論，直以微誠動旒扆。", "華堂白髮喜更新，即看青袍子高第。", "壽斝千場日未央，膝下曾玄扶且倚。", "中眷有孫不能鳴，東眷孫文刊燁煒。"]'),
('aca1a3a2-1a82-49a3-adf8-c5bc0253fcf6','送懶散先生東歸','晁說之','宋','宋诗','song-poetry','','[]','先生身幹若浮查，舌響霜鐘激水車。',112,'全唐诗/poet.song.68000.json','["先生身幹若浮查，舌響霜鐘激水車。", "平生樂逐胡鴈起，倐遊吳會忽京華。", "公卿到門問窮達，未易可置吾齒牙。", "今我何事亦青衫，掉頭棄擲如泥沙。", "數術因之爲道術，浄居與世不交加。", "一醉十日醒五日，雙環粧罷覓新花。", "沙塵滿眼獨不怕，此非浄居之勝耶。"]'),
('67a1c8fe-c0da-46ee-a62a-b22948859b6c','題兩馬圖','晁說之','宋','宋诗','song-poetry','','[]','前馬去駸駸，年少意有餘。',24,'全唐诗/poet.song.68000.json','["前馬去駸駸，年少意有餘。", "後馬追馳驟，喘殺肥髯奴。"]'),
('64268c00-f557-426f-b112-b7f2c4cbe18d','二十二弟自常州寄翦刀及筆來作長句','晁說之','宋','宋诗','song-poetry','','[]','弟書毗陵來，有同股分刃之刀，綠管白毫之筆。',128,'全唐诗/poet.song.68000.json','["弟書毗陵來，有同股分刃之刀，綠管白毫之筆。", "刀是寶公錫上之所懸，筆亦江淹夢中之所得。", "江南刀筆有如此，不比豐沛吏蕭曹而興鋒鏑。", "顧惟二物大有恨，不蒙獨孤府君一言之飾。", "使君惠山延陸羽，文章不落翰墨迹。", "及今有用正勞勞，破賊露布征兵檄。", "小楷帖黄奏北闕，念弟未歸空歎息。"]'),
('d4fdc7e1-918f-47f9-a08a-804c08af582c','錢德載以臨江朱玠筆見贈以詩謝之德載與李先之亦相善','晁說之','宋','宋诗','song-poetry','','[]','清江長官空書來，朱玠妙筆空悠哉。',32,'全唐诗/poet.song.68000.json','["清江長官空書來，朱玠妙筆空悠哉。", "恐是怕上萬言書，惡嫌並命憎不才。"]'),
('64c0e103-30ab-48ea-8fb1-8bc8ef186494','實紀二十韻','晁說之','宋','宋诗','song-poetry','','[]','雙廟之前扁舟艤，太原失守胡塵起。',320,'全唐诗/poet.song.68000.json','["雙廟之前扁舟艤，太原失守胡塵起。", "鐵馬渡河京城閉，堤上奔亡如磨螘。", "不是清河早腹兵，千艫萬舳去何已。", "百家相逢不相識，同聲嘆言有如此。", "閹貫梟顱一日間，地下未應有餒鬼。", "董卓燈臍照傕氾，禄山腸流盛安使。", "京不及刑家自全，黼弗顯誅恩尚委。", "楊炎終報元載讎，微之實同宗閔恥。", "政刑既棄胡虜盛，中國不尊招訕毁。", "尊名重器假狗彘，公卿何人是知理。", "嗟予老病豈樂生，實抱忠謀難須死。", "亦嘗奏對明光殿，寒饑徒步荆棘裏。", "面風背日若有待，前有戎車後妻子。", "戎車不斷頓都城，元戎一言左右以。", "遙有人家投宿無，骨肉夜飯無鈍齒。", "不嗟五日不頮面，但憐一夜燈花喜。", "庶幾明發脱盜手，復見皇威振遐邇。", "廟堂再見謝太傅，奕棋未罷風塵弭。", "前夜客投佛寺晚，全家凍泣木魚底。", "我今朝夕幸已多，聞見紛紛聊實紀。"]'),
('196e8e79-2c94-45e2-8ec0-66ff46cba079','靈璧石有未上供者狼藉兩岸','晁說之','宋','宋诗','song-poetry','','[]','鳳凰山石與石殊，敕使督貢傾舳艫。',64,'全唐诗/poet.song.68000.json','["鳳凰山石與石殊，敕使督貢傾舳艫。", "擎空不數碧菡萏，媚日寧顧女珊瑚。", "但識天囿簫韶底，豈期汴岸沙礫餘。", "煬帝錦帆幾來往，曾不得汝恨何如。"]'),
('cf0d7c9a-2a74-4a22-bee2-6c7e6c4a0523','枕上聞蛩忽久不鳴','晁說之','宋','宋诗','song-poetry','','[]','促織復促織，爾實借我職。',96,'全唐诗/poet.song.68000.json','["促織復促織，爾實借我職。", "語我以詩書，覺我以道德。", "胡然久不鳴，似知不如默。", "默而如見容，實惟已失則。", "不見容而疑，豈不云大惑。", "智或神於蓍，夢有不待卜。", "秋風日已高，太白光如植。", "予豈默默時，殺身徇吾國。"]'),
('8574fffa-e901-4ed8-90f8-6fa1fd91ec88','連日與性之王君談遽來告别因作','晁說之','宋','宋诗','song-poetry','','[]','許州秀才周若蒙，星官占罷淚無從。',176,'全唐诗/poet.song.68000.json','["許州秀才周若蒙，星官占罷淚無從。", "歐陽公死不過夏，天上文星已告凶。", "常秩王回暨姚闢，排斥先儒不少容。", "回第曰向竊笑之，問學文章衆所同。", "識此二事王氏孫，酸棗先生稱祖翁。", "先生易老凈肇樂，晚奏象繫明光中。", "清淨之化浹百年，寡欲愛民自祖宗。", "潛仁蓄德流必遠，譬如喬嶽生寒松。", "天之生材弗浪與，不世其美安得雄。", "君之積學萬石簴，筆力仍關千石鐘。", "遑遑欲談誰聽此，秋江好渡多柔風。"]'),
('02d88f31-fee2-4f92-9160-81e522a8c7ad','舟中倦甚','晁說之','宋','宋诗','song-poetry','','[]','櫓聲出入如謳發，晝長夜短睡蛇絕。',64,'全唐诗/poet.song.68000.json','["櫓聲出入如謳發，晝長夜短睡蛇絕。", "紅窗跼蹐天地隘，出向船頭望寒月。", "月寒不照孤征人，自與紅鑪得意親。", "何日有田吾意得，躬耕壠首待陽春。"]'),
('2a74e725-8e5b-4d0d-bf11-ef8ca5ffbdb0','曉霽','晁說之','宋','宋诗','song-poetry','','[]','沈痾春夜客，風雨送愁來。',84,'全唐诗/poet.song.68000.json','["沈痾春夜客，風雨送愁來。", "曉雲收風雨，一瞬静九垓。", "東皇太一人，盜賊何有哉。", "上使四門闢，豈但桃李開。", "下使小人退，即日大輅回。", "昭昭負帝德，汲汲掞天才。", "白頭見太平，酒醒豁所懷。"]'),
('5672678f-69c7-4209-a0b8-2f50c66881da','說之有庭珪真墨一爲儀真賊所焚伏蒙二十二叔特以真墨見惠因喜出意表輒賦詩申謝','晁說之','宋','宋诗','song-poetry','','[]','黄瓜忌三摘，吾臂醫九折。',120,'全唐诗/poet.song.68000.json','["黄瓜忌三摘，吾臂醫九折。", "有如老商胡，何言問折閲。", "兒藏廷珪墨，賊火出烈烈。", "是時干戈起，髑髏積不血。", "寧復有此物，硯北伴白髮。", "叔父曰賜汝，可憂百如結。", "矧此微物者，戲劇論巧拙。", "拜吾叔父賜，理亂聞一轍。", "再拜叔父賢，世珍視不屑。", "百拜叔父意，兒學安得輟。"]'),
('a77e8583-fb94-48c4-aa7a-793c2939ee21','謝藴文水仙花','晁說之','宋','宋诗','song-poetry','','[]','飄零塵俗客，再見水仙花。',24,'全唐诗/poet.song.68000.json','["飄零塵俗客，再見水仙花。", "清芬二十載，饒殺蘭杜家。"]'),
('0589d721-8ad8-44e2-b2e6-c00022f9363f','王性之自揚州遷路相訪於海陵荷其意厚非平日比贈詩以别','晁說之','宋','宋诗','song-poetry','','[]','九死性命存，乃到海陵倉。',288,'全唐诗/poet.song.68000.json','["九死性命存，乃到海陵倉。", "海陵何所有，麋鹿晝成行。", "多倉多麋鹿，今也恨難忘。", "爰從本朝來，人物上國光。", "容我迹其間，性之因翺翔。", "性之篤忠信，又復能文章。", "一世所趨附，在眼獨不忙。", "困於州縣吏，斂翼弗許張。", "蹉跎誰識之，心膽空堂堂。", "我不自揆者，薦之三府傍。", "相公意似順，衆口極雌黄。", "我斥不得容，爲子增慨慷。", "子行羣賊中，妻孥道路長。", "掛帆揚州灣，聞我病在床。", "不尋枉渚來，或謂子不剛。", "活我以簡策，飽我非稻粱。", "告别閩嶺去，波浪春風狂。", "既欲殺風母，又欲射天狼。", "四海俱已震，何處一身藏。", "揮淚與之子，關雎哀不傷。", "禄山傾社稷，朱泚侮君王。", "於今無此孽，但可正皇綱。", "文章出號令，忠信被農桑。", "之子抱此器，用之斯民康。"]'),
('c40a5507-d898-4b04-9e18-4996d53cf8e5','陳情','晁說之','宋','宋诗','song-poetry','','[]','春風到來久，今日令得行。',120,'全唐诗/poet.song.68000.json','["春風到來久，今日令得行。", "蛙聲曲池滿，柳色深巷明。", "負痾老客子，徜徉難爲情。", "豈不懷故隱，盜賊間徂征。", "近得望行在，氣祲夜峥嶸。", "諒待賢者出，一偃天下兵。", "四夷堡障静，三農田野耕。", "雞豚飽故老，廉恥責後生。", "我雖素餐者，自謂能頌聲。", "此情誰與同，有公仍有卿。"]'),
('c2bfbd88-2a9b-481c-97ca-b22f53f32ffb','次韻和馬子虚學士感事見贈','晁說之','宋','宋诗','song-poetry','','[]','與君中山時，心樂得樂土。',120,'全唐诗/poet.song.68000.json','["與君中山時，心樂得樂土。", "未始厭耳聞，寧或刺眼睹。", "風雨喜分散，樂事亡難補。", "看君青雲編，翅墮不得舉。", "榮滯正相半，田園餘幾許。", "前年白馬亂，不保使君詛。", "去從竟陵謫，竟陵人何慕。", "妻兒思北歸，耕桑失寒暑。", "邂逅怪我存，魂招來奚數。", "强欲布露之，愧君健能賦。"]'),
('8ccfb47e-d152-4b3e-9701-556d65f2ced5','流寓海陵半年忽得周元仲分寧書欣慰與常日不同輒有作代書','晁說之','宋','宋诗','song-poetry','','[]','海陵士子江東客，我到海陵無主人。',96,'全唐诗/poet.song.68000.json','["海陵士子江東客，我到海陵無主人。", "蒼波知君到何處，直待書來消息真。", "與君相去歲月久，世事茫茫誰出手。", "桑田欲變仙人去，鶴駕雲軒安得取。", "愁腸出淚付滄波，江上秋風奈我何。", "何處雲山君待我，更煩先寄綵雲歌。"]'),
('4ff0fa53-ce64-4173-8097-e4a5f087ab22','秋感','晁說之','宋','宋诗','song-poetry','','[]','鄰雞鳴已過，吾雞一何懶。',132,'全唐诗/poet.song.68000.json','["鄰雞鳴已過，吾雞一何懶。", "要穩土人眠，高視清秋晏。", "惜哉清秋時，留客久異縣。", "莫謂兹荒陬，千令洿畿甸。", "黄屋在揚州，江山被恩幸。", "肥羜翻吳羮，宮粧驚楚練。", "雖云胡馬陣，敢敵水龍鑑。", "有事郊三年，神降樂六變。", "萬國走玉帛，兩京鎖宮殿。", "明發迎歸路，兹夕淚如霰。", "孤旅愁思絕，一身幾憂患。"]'),
('230d77b0-82da-41f6-8869-a8e37c944ffe','秋適','晁說之','宋','宋诗','song-poetry','','[]','今日秋光遠，吾意亦以閒。',60,'全唐诗/poet.song.68000.json','["今日秋光遠，吾意亦以閒。", "置此清羸身，茄菼薏苡間。", "一别嵩陽縣，二紀不得還。", "幾處逢新秋，幽夢著舊山。", "木落淮南舊，水流日柴關。"]'),
('cd091a7f-b78e-43f4-b553-d4857cd2ae4d','閒極','晁說之','宋','宋诗','song-poetry','','[]','閒極忘羈旅，秋色爲我深。',48,'全唐诗/poet.song.68000.json','["閒極忘羈旅，秋色爲我深。", "牛卧樹外影，雞鳴堂中心。", "自言身已隱，人道尚官箴。", "明趨傍海郡，適我梁甫吟。"]'),
('2b732521-e72f-440f-9db2-851773ad3f9d','謝季左司筆墨','晁說之','宋','宋诗','song-poetry','','[]','韓揚州，蕭劍州，相忘終日夢悠悠。',48,'全唐诗/poet.song.68000.json','["韓揚州，蕭劍州，相忘終日夢悠悠。", "何如微季掾三府，國譽鄉評坐以收。", "不忘筆墨高人興，爲道明珠無昧不。"]'),
('eefbfa45-3256-49fe-b1e6-5cc35bf80195','且遽告行求題其父所作夢記之後','晁說之','宋','宋诗','song-poetry','','[]','前身嵩陽老道士，今日京東蔡秀才。',32,'全唐诗/poet.song.68000.json','["前身嵩陽老道士，今日京東蔡秀才。", "杜門藏書萬餘卷，不知何身得之哉。"]'),
('5be64705-7d6a-4028-b45d-b58abb5aeea8','雪中懷水雲館','晁說之','宋','宋诗','song-poetry','','[]','六出花頭萬疊波，水雲館前不肯過。',32,'全唐诗/poet.song.68000.json','["六出花頭萬疊波，水雲館前不肯過。", "玉鸞素面如相語，人間清興今如何。"]'),
('e82ec8ad-635b-497a-88db-e73c07627dd7','無客','晁說之','宋','宋诗','song-poetry','','[]','嗟予少好客，今老客棄予。',72,'全唐诗/poet.song.68000.json','["嗟予少好客，今老客棄予。", "忽忽飄流來，不知歲又除。", "良愧彼黄鵠，千里無修塗。", "江東賊强臣，淮南盜名都。", "鍾阜被朔雪，暫與我何娛。", "明當雲夢去，已發又何如。"]'),
('d5c0db5a-822f-478e-9fa3-05b353732602','将爲枝江之行','晁說之','宋','宋诗','song-poetry','','[]','北斗垂几尺，東京路幾千。',108,'全唐诗/poet.song.68000.json','["北斗垂几尺，東京路幾千。", "大江復幾深，臘尾難放船。", "豈無彫胡飯，疾病相後先。", "波濤日夜起，高枕相與眠。", "春風明日來，爲我添華顛。", "沅湘盛春風，蘭茝爲人妍。", "沅湘無故人，耕釣異雲煙。", "沅湘有故人，避地于我前。", "彼美媚學子，共講中庸篇。"]'),
('d1cdda35-718d-4d72-b564-ffd8d5d8ef67','呈華藏密印','晁說之','宋','宋诗','song-poetry','','[]','華藏有主人，百界轉纖埃。',24,'全唐诗/poet.song.68000.json','["華藏有主人，百界轉纖埃。", "主人順喚客，低頭不敢來。"]'),
('0208dbcb-c44c-4ae1-9363-54c27d33db32','秋陰','晁說之','宋','宋诗','song-poetry','','[]','漠漠秋陰好，遙空見故鄉。',48,'全唐诗/poet.song.68000.json','["漠漠秋陰好，遙空見故鄉。", "可堪高葉病，無賴晚花香。", "枕靜泉聲細，簾疏風影長。", "肯教容易雨，吟興動何郎。"]'),
('6413e189-5a14-4207-a68e-1e9d5363ea32','和斯立夜校試卷呈同舍十二韻','晁說之','宋','宋诗','song-poetry','','[]','校藝來從魯，聞韶昔在齊。',144,'全唐诗/poet.song.68000.json','["校藝來從魯，聞韶昔在齊。", "幸容葭倚樹，驩會食甘藜。", "禮數延文士，雄豪動武奎。", "嚴凝池上雪，燦爛谷中霓。", "喜見雙頭錦，爭求獨角犀。", "化金思點竈，畫酒願分篦。", "氣壯如觀海，言危擬去梯。", "且思竭馬力，焉敢效牛蹊。", "蕭統聞香臭，劉郎善品題。", "鉛黄方晏集，風雨惜分攜。", "永遣愁城破，休教眉宇低。", "故鄉吾自樂，歸去逐羣鷄。"]'),
('938659ee-6cea-44eb-8f50-f93861215482','再和資道','晁說之','宋','宋诗','song-poetry','','[]','佳山陪四絕，名士出三齊。',144,'全唐诗/poet.song.68000.json','["佳山陪四絕，名士出三齊。", "芬馥生蘭茞，荒蕪去菉藜。", "光華深北斗，氣象到西奎。", "靜思如含露，揮毫若吐霓。", "美求鮮鯉鱠，珍訪辟塵犀。", "出衆青錢士，翻經白玉篦。", "高張射鵰手，穩步上天梯。", "吾友由斯道，狂生不識蹊。", "淮南書有作，商隱賦無題。", "慷慨簪頻擊，吟哦手屢攜。", "寒廳簾帟淺，深夜笑言低。", "慎莫嘲雕虎，從來學木雞。"]'),
('8d968936-de49-4ded-a36d-f7ee98d96950','再和','晁說之','宋','宋诗','song-poetry','','[]','何事謝玄暉，臨巒且悵齊。',144,'全唐诗/poet.song.68000.json','["何事謝玄暉，臨巒且悵齊。", "想非逢錦繡，應祗見蒿藜。", "今日三千牘，昭天十六奎。", "煌煌鳴佩璐，燦燦動旌霓。", "服衆稱擒虎，超羣許拔犀。", "品輕龍尾硯，時様鳳頭篦。", "棄若文公席，危如墨子梯。", "只宜馳大路，爭可訪幽蹊。", "我亦慚强韻，君能出巨題。", "笑言容委曲，良宴幸招攜。", "黄菊開應滿，清霜壓莫低。", "誰人傾魯酒，更復噉韓雞。"]'),
('e38ee3c7-22b1-4f98-96b0-59bb0777f3f5','和斯立重賦','晁說之','宋','宋诗','song-poetry','','[]','是非真未定，楚客莫咻齊。',144,'全唐诗/poet.song.68000.json','["是非真未定，楚客莫咻齊。", "侈美珍炰鼈，粗疏鄙飯藜。", "評文歸藻鑒，得寶應参奎。", "蕭洒裛塵雨，清明避日霓。", "露華鳴老鶴，月魄射靈犀。", "儒雅元簪筆，風流且带篦。", "辛勤無黑突，騰躍有丹梯。", "自顧迷轅駕，焉能識路蹊。", "從容金谷集，酬唱漢江題。", "好是頻徴策，相看便解攜。", "塵埃隨日起，窮悴使人低。", "桀犬驚堯犬，家鷄笑野鷄。"]'),
('5051babe-1ab3-42ec-bdee-b6e90290631a','和資道登岱頂回','晁說之','宋','宋诗','song-poetry','','[]','藹藹天孫作曉嵐，爲嫌俗骨遣教還。',32,'全唐诗/poet.song.68000.json','["藹藹天孫作曉嵐，爲嫌俗骨遣教還。", "仙兒墮處真堪惜，只在含眸一笑間。"]'),
('cd911ac6-66bc-405f-9d38-85fb27096647','近作小池頗有野意日晚臨流吟柳渾獨不見慨然有作','晁說之','宋','宋诗','song-poetry','','[]','無波枉渚若堪凭，白露青蘋更可陵。',32,'全唐诗/poet.song.68000.json','["無波枉渚若堪凭，白露青蘋更可陵。", "過盡秋風獨不見，此時腸斷柳吳興。"]'),
('851410f5-7bb9-452b-a7e5-8d72782a3807','十月初七日入郡塗中作','晁說之','宋','宋诗','song-poetry','','[]','棄臣悠悠朱墨筆，凋年忽忽道塗衣。',32,'全唐诗/poet.song.68000.json','["棄臣悠悠朱墨筆，凋年忽忽道塗衣。", "博崔趙李久寂寞，乙馬甲班誰是非。"]'),
('a40fe9f9-1671-4a16-9725-ae8709b18e7f','覽冀亭榴花','晁說之','宋','宋诗','song-poetry','','[]','長夏清江倚碧岑，人間塵土莫相侵。',32,'全唐诗/poet.song.68000.json','["長夏清江倚碧岑，人間塵土莫相侵。", "榴花不得春工力，顔色何如桃杏深。"]'),
('ebba110c-1da1-42c4-8c1e-6bb28179bf76','寄侍講呂原明七丈','晁說之','宋','宋诗','song-poetry','','[]','悠悠客子京華遠，只把清秋淚濯纓。',64,'全唐诗/poet.song.68000.json','["悠悠客子京華遠，只把清秋淚濯纓。", "黄葉風前身亦老，白雲影外世還輕。", "書來舊德知無恙，夢斷疏鐘恨有情。", "昔日諸生今在不，丈人因爲話平生。"]'),
('269cf606-fa55-4661-9e92-1d42db1cdb5f','讀韓退之詩有作','晁說之','宋','宋诗','song-poetry','','[]','萬樹殘英委泥滓，柳花成絮獨高飛。',32,'全唐诗/poet.song.68000.json','["萬樹殘英委泥滓，柳花成絮獨高飛。", "自憐纖質無人賞，宛轉還從洛浦歸。"]'),
('421139ee-f7a4-4d06-944e-e1c11bd01028','贈吳僧','晁說之','宋','宋诗','song-poetry','','[]','驅馳疲朔馬，邂逅見吳僧。',48,'全唐诗/poet.song.68000.json','["驅馳疲朔馬，邂逅見吳僧。", "便覺秋容凈，彌憐客恨澄。", "青山尋舊賞，白社語新燈。", "他日扁舟去，儂家一笑能。"]'),
('8e6d378d-ac4e-421a-a7db-e2c924d455a7','狂風','晁說之','宋','宋诗','song-poetry','','[]','十日狂風不偶然，未教桃李鬬嬋娟。',32,'全唐诗/poet.song.68000.json','["十日狂風不偶然，未教桃李鬬嬋娟。", "關西將士曾如此，直入齊宮斬小憐。"]'),
('b9366cf4-e44a-4da0-95c6-1e5f874bfa6e','次韻答澗上丈人見寄','晁說之','宋','宋诗','song-poetry','','[]','丈人一别今何闊，菊雨蘭風自歲年。',64,'全唐诗/poet.song.68000.json','["丈人一别今何闊，菊雨蘭風自歲年。", "茅屋歸來思叙舊，繩床老去不談禪。", "世無孔子徒爲爾，今媿孫登重惘然。", "幸有陽城山水在，更留佳處待夤緣。"]'),
('bd772866-31fc-4623-bbc7-35ac053a3f0b','和陳叔易見寄','晁說之','宋','宋诗','song-poetry','','[]','終日焚香卻袢暑，只此於君媿典刑。',32,'全唐诗/poet.song.68000.json','["終日焚香卻袢暑，只此於君媿典刑。", "莫怪慇懃問元朗，此心要自渴滄溟。"]'),
('71f7b81c-6e0d-4ed3-88d6-72484b274f5e','次韻澗上丈人見寄','晁說之','宋','宋诗','song-poetry','','[]','有懷南澗老，月冷夢魂賒。',48,'全唐诗/poet.song.68000.json','["有懷南澗老，月冷夢魂賒。", "煙閉金丹竈，雲迷玉斧家。", "高雲嗟縹緲，醉墨喜傾斜。", "明日秋風起，愁看菊蘂花。"]'),
('c7c0f828-9be8-4375-bd7f-b8727a8d7c9e','再和班字三首  其一','晁說之','宋','宋诗','song-poetry','','[]','丈人在何許，箕外潁中間。',48,'全唐诗/poet.song.68000.json','["丈人在何許，箕外潁中間。", "明映波心月，清餘雨面山。", "短衣非舊甯，陋巷是今顔。", "不解湟州去，平超十八班。"]'),
('dff935dc-fb06-4486-a01d-f1b932b5b30f','再和班字三首  其二','晁說之','宋','宋诗','song-poetry','','[]','公來前有約，更望少微閒。',48,'全唐诗/poet.song.68000.json','["公來前有約，更望少微閒。", "爛醉新醅酒，能忘舊隱山。", "瓊瑤雖並質，塵土會凋顔。", "永夜陶陶語，令人愧尹班。"]'),
('d027ed68-d7fb-4320-8c5e-107c03b2afdb','再和班字三首  其三','晁說之','宋','宋诗','song-poetry','','[]','高躅人難解，當求古哲閒。',48,'全唐诗/poet.song.68000.json','["高躅人難解，當求古哲閒。", "韓康多在市，陶令懶游山。", "念我可憎面，無兄得解顔。", "公乎來早晚，荆坐要須班。"]'),
('2da38428-f231-48df-a4d7-d3cc9059b71f','次韻久雨甲子日喜晴之作','晁說之','宋','宋诗','song-poetry','','[]','愁霖開霽忽今朝，摩撫爲魚鱗甲消。',64,'全唐诗/poet.song.68000.json','["愁霖開霽忽今朝，摩撫爲魚鱗甲消。", "竈下黽蛙歸枉渚，簷邊雲霧起叢霄。", "已驚病眼能明朗，更喜新詩慰寂寥。", "莫把陰晴論甲子，請從根本問黎苖。"]'),
('11cf0126-890e-4bd4-bc2c-57c9d24eeca0','聞叔易隱居被召二首','晁說之','宋','宋诗','song-poetry','','[]','處士何人爲作牙，盡攜猿鶴到京華。',32,'全唐诗/poet.song.68000.json','["處士何人爲作牙，盡攜猿鶴到京華。", "故山巖壑應惆悵，六六峰前只一家。"]'),
('1a5cc217-2cff-4726-b77a-4eb3412ff5c9','雨霽聞溪流作','晁說之','宋','宋诗','song-poetry','','[]','山前霖雨霽，流水興何長。',72,'全唐诗/poet.song.68000.json','["山前霖雨霽，流水興何長。", "曲澗通蘭若，餘音到草堂。", "龍鱗應已備，魚尾得令狂。", "奏凱入關陣，尋仙泛海航。", "月添波蕩漾，風共影瀰茫。", "不作羈臣淚，明朝涸復常。"]'),
('07c4ecea-308e-421b-bca7-a82d492a5a51','峻極上院','晁說之','宋','宋诗','song-poetry','','[]','山下青青春已歸，百花山上正芳菲。',32,'全唐诗/poet.song.68000.json','["山下青青春已歸，百花山上正芳菲。", "人間顔色易零落，百萬千年雲錦衣。"]'),
('4f2f802c-25f2-474b-8c64-2d4b14a19950','節孝處士徐先生','晁說之','宋','宋诗','song-poetry','','[]','莫怪先生身上貧，眼看外物似浮雲。',32,'全唐诗/poet.song.68000.json','["莫怪先生身上貧，眼看外物似浮雲。", "房中除却琴棋後，更有門前鶴一羣。"]'),
('3d3c4340-9f54-447e-ac79-13d7d602a640','政和元年正月一日作','晁說之','宋','宋诗','song-poetry','','[]','元年元日日甲子，從自漢曆來有三。',32,'全唐诗/poet.song.68000.json','["元年元日日甲子，從自漢曆來有三。", "總把皇恩調玉燭，今朝獨更覺春酣。"]'),
('095daf23-6898-4778-8c58-1f3b94b9d7bd','癸未歲余與開封解安行同知定州外縣赴二帥上元之集今辛卯明州燈夕公會上見邸報解以大夫知嘉州感舊作寄','晁說之','宋','宋诗','song-poetry','','[]','伊昔中山勝事賒，初當三五便開花。',64,'全唐诗/poet.song.68000.json','["伊昔中山勝事賒，初當三五便開花。", "君能選色沉醉倒，我自傷心深感嗟。", "聚散十年逢節序，窮通百態各天涯。", "使君綺席誰同樂，莫遣燈花照鬢華。"]'),
('f32e4304-d80b-4aa6-b5d8-e5898ce8f869','早春','晁說之','宋','宋诗','song-poetry','','[]','日日江頭騁望頻，東風去歲舊相親。',32,'全唐诗/poet.song.68000.json','["日日江頭騁望頻，東風去歲舊相親。", "庾郎欲作披香賦，未有花開未是春。"]'),
('b8b75063-ec62-4586-adb1-4e30becfb770','聞四明人不喜鞦韆因作','晁說之','宋','宋诗','song-poetry','','[]','思歸未得恨深年，時節清明最可憐。',32,'全唐诗/poet.song.68000.json','["思歸未得恨深年，時節清明最可憐。", "越女腰支勝趙女，平生不敢賽鞦韆。"]'),
('78d53172-69c8-41de-b6de-af9e45e4592c','愁  其一','晁說之','宋','宋诗','song-poetry','','[]','雲暗花寒春在否，煙波漠漠不禁愁。',32,'全唐诗/poet.song.68000.json','["雲暗花寒春在否，煙波漠漠不禁愁。", "此愁肯逐楊花散，常與幽人種白頭。"]'),
('20dc0aa2-9764-4cfe-a184-0a1ace76ea5b','愁  其二','晁說之','宋','宋诗','song-poetry','','[]','無奈愁來欲解攜，春光何事亦如迷。',32,'全唐诗/poet.song.68000.json','["無奈愁來欲解攜，春光何事亦如迷。", "只應自有人行樂，枉是多情王會稽。"]'),
('e8892eec-0766-4dd3-aedb-e8c202d5cd6f','寒食書事','晁說之','宋','宋诗','song-poetry','','[]','冷官不易逢寒食，海角風霜剩作寒。',32,'全唐诗/poet.song.68000.json','["冷官不易逢寒食，海角風霜剩作寒。", "杏粥榆羮渾不見，蓬池春色夢中看。"]'),
('faa14f5e-6fef-4fcf-b132-9e67f23fa3f7','戲作','晁說之','宋','宋诗','song-poetry','','[]','終日一杯終日醉，看潮初上看潮回。',32,'全唐诗/poet.song.68000.json','["終日一杯終日醉，看潮初上看潮回。", "自疑前世陶貞白，乘興閑遊鄮縣來。"]'),
('6ad6902d-7ce7-4907-b1ff-be76e95333da','昏昏','晁說之','宋','宋诗','song-poetry','','[]','昏昏非所志，忽忽是何時。',48,'全唐诗/poet.song.68000.json','["昏昏非所志，忽忽是何時。", "客恨潮聲起，春愁柳色知。", "何煩連日雨，要劇故鄉思。", "自顧囊中術，黄金未可爲。"]'),
('619d42bc-e8fd-4ee5-b6d5-20e0a181557d','有感','晁說之','宋','宋诗','song-poetry','','[]','日日蒼黄出畏塗，自憐何事得虚除。',32,'全唐诗/poet.song.68000.json','["日日蒼黄出畏塗，自憐何事得虚除。", "天教豺虎露齒爪，好是哥奴不讀書。"]'),
('b13ee980-cb4b-4b02-b45c-4c7b58d9c74b','西渡','晁說之','宋','宋诗','song-poetry','','[]','西渡幾回送客，春風今日思家。',28,'全唐诗/poet.song.68000.json','["西渡幾回送客，春風今日思家。", "我亦歸期可數，休言此是天涯。"]'),
('de13c3e9-750f-4d68-b3ce-1be199e015bb','予今春多入城戲作村裏來絕句村裏來是蛺蝶名滕王所畫者','晁說之','宋','宋诗','song-poetry','','[]','蝴蝶催花一夜開，却愁春盡重徘徊。',32,'全唐诗/poet.song.68000.json','["蝴蝶催花一夜開，却愁春盡重徘徊。", "我身亦使滕王恨，日日隨渠春裏來。"]'),
('5c139461-edbf-4e17-9531-0dc09ecbb30b','依韻和蔡天啟任四明絕句三首時暫來四明便還丹陽頗不樂此後篇爲四明解嘲  其一','晁說之','宋','宋诗','song-poetry','','[]','行盡三江失所誇，便教信美豈吾家。',32,'全唐诗/poet.song.68000.json','["行盡三江失所誇，便教信美豈吾家。", "却回揚子江頭去，看種瓜洲子母瓜。"]'),
('54ff7c3d-f8c8-403d-8f08-9ab06c90cfaf','依韻和蔡天啟任四明絕句三首時暫來四明便還丹陽頗不樂此後篇爲四明解嘲  其二','晁說之','宋','宋诗','song-poetry','','[]','真隱閒從鄮縣來，三山仙蘂眼中開。',32,'全唐诗/poet.song.68000.json','["真隱閒從鄮縣來，三山仙蘂眼中開。", "此身自有華陽洞，肯學秉陽歎老槐。"]'),
('1b212c95-55fd-4d19-96b8-186f9aa45c7e','依韻和蔡天啟任四明絕句三首時暫來四明便還丹陽頗不樂此後篇爲四明解嘲  其三','晁說之','宋','宋诗','song-poetry','','[]','未識凉風寶殿西，寧驚海角有遺黎。',32,'全唐诗/poet.song.68000.json','["未識凉風寶殿西，寧驚海角有遺黎。", "玉箏無日嘗瑤柱，金馬何人賞木犀。"]'),
('2210d867-fc86-4a21-8d93-69fae3131213','見諸公唱和暮春詩軸次韻作九首  其一','晁說之','宋','宋诗','song-poetry','','[]','何處留春意，歌殘燭半紅。',48,'全唐诗/poet.song.68000.json','["何處留春意，歌殘燭半紅。", "柳斜雙舞破，花落獨書空。", "欲作經年别，先驚昨夜風。", "烏衣多勝概，此際恨難窮。"]'),
('ed417985-56e9-4034-9188-c314a81ab069','見諸公唱和暮春詩軸次韻作九首  其二','晁說之','宋','宋诗','song-poetry','','[]','那識春將暮，山頭躑躅紅。',48,'全唐诗/poet.song.68000.json','["那識春將暮，山頭躑躅紅。", "潮生芳草遠，鳥滅夕陽空。", "烏賊家家飯，槽船面面風。", "三吳窮海地，客恨極難窮。"]'),
('4209a93e-3773-4c87-946b-9a73b988d147','見諸公唱和暮春詩軸次韻作九首  其三','晁說之','宋','宋诗','song-poetry','','[]','歎惜芳菲盡，香腮越女紅。',48,'全唐诗/poet.song.68000.json','["歎惜芳菲盡，香腮越女紅。", "簾垂啼鳥散，鏡掩舞鸞空。", "梅短嬌含雨，蓴絲懶倚風。", "高歌君輩在，老子奈途窮。"]'),
('7074551e-bca3-4195-be63-637445fb6a14','見諸公唱和暮春詩軸次韻作九首  其四','晁說之','宋','宋诗','song-poetry','','[]','留春留不得，怯去舞衣紅。',48,'全唐诗/poet.song.68000.json','["留春留不得，怯去舞衣紅。", "那昔河陽暮，唯驚洛浦空。", "丹成人奔月，金就鶴乘風。", "此恨何能已，盧郎百計窮。"]'),
('0c1b0e59-e520-4aa4-98ee-0dbee11d872b','見諸公唱和暮春詩軸次韻作九首  其五','晁說之','宋','宋诗','song-poetry','','[]','五字留春句，如開蜀錦紅。',48,'全唐诗/poet.song.68000.json','["五字留春句，如開蜀錦紅。", "幽香知不滅，宿恨望來空。", "婉娩能揮日，綢繆擬割風。", "江淹方思苦，慎莫道才窮。"]'),
('5ecf44e6-05aa-41cf-b821-e7141314e2d7','見諸公唱和暮春詩軸次韻作九首  其六','晁說之','宋','宋诗','song-poetry','','[]','春殘留幾日，越女笑蠶紅。',48,'全唐诗/poet.song.68000.json','["春殘留幾日，越女笑蠶紅。", "江盡愁何盡，牀空夢不空。", "燕多知近海，蝶少爲饒風。", "底事吟詩健，吟詩正待窮。"]'),
('c24bdca4-8418-4194-8de0-147779153286','見諸公唱和暮春詩軸次韻作九首  其七','晁說之','宋','宋诗','song-poetry','','[]','芳草搖輕碧，薔薇著小紅。',48,'全唐诗/poet.song.68000.json','["芳草搖輕碧，薔薇著小紅。", "肯嫌桃葉薄，只恨柳枝空。", "夢斷三千里，愁生五兩風。", "四時顧家好，作底却言窮。"]'),
('17535050-a857-4988-b01e-dba63a50bbb4','見諸公唱和暮春詩軸次韻作九首  其八','晁說之','宋','宋诗','song-poetry','','[]','上苑羣芳外，娑羅二月紅。',48,'全唐诗/poet.song.68000.json','["上苑羣芳外，娑羅二月紅。", "妖饒秦女妬，淡蕩越江空。", "敢夢鵷鸞侣，徒披草木風。", "傳家緗帙在，百巧愧千窮。"]'),
('17bc1ea0-7aeb-44fd-801d-ad85db9606b3','見諸公唱和暮春詩軸次韻作九首  其九','晁說之','宋','宋诗','song-poetry','','[]','令公頭皓白，執拂妓殷紅。',48,'全唐诗/poet.song.68000.json','["令公頭皓白，執拂妓殷紅。", "綺席千觴醉，芳塵一夕空。", "顛狂援北斗，飄蕩怨東風。", "得意傷春甚，癯儒况路窮。"]'),
('73dfa351-875c-47c6-bdf9-0319141aedbc','秋日有感因誦王元之送文元公詩云追思元白在江東不似晁丞今獨步之句戲作','晁說之','宋','宋诗','song-poetry','','[]','三吳山水喜秋風，白蟹青蝦甬水東。',32,'全唐诗/poet.song.68000.json','["三吳山水喜秋風，白蟹青蝦甬水東。", "獨步晁丞孫子到，誰憐憔悴衆人中。"]'),
('6042f23e-0dc9-449d-afeb-8c38755e0367','引伴宣事惠詩六首過有褒稱且及其叔子文之舊輒次韻爲詩  其一','晁說之','宋','宋诗','song-poetry','','[]','白髪蕭條到海濵，秋風邂逅故園人。',64,'全唐诗/poet.song.68000.json','["白髪蕭條到海濵，秋風邂逅故園人。", "三千紅錦巧爲帳，百萬黄金肯買鄰。", "漢節陸離驚遠俗，商歌窈窕會相親。", "男兒躍馬横戈志，收入詩壇更絕塵。"]'),
('2c698c19-ef62-4018-a156-b1c5c55208a9','引伴宣事惠詩六首過有褒稱且及其叔子文之舊輒次韻爲詩  其二','晁說之','宋','宋诗','song-poetry','','[]','一世凄凉朋友恨，九原涕淚歲時深。',64,'全唐诗/poet.song.68000.json','["一世凄凉朋友恨，九原涕淚歲時深。", "逢君若自傳家法，顧我寧堪話此心。", "却喜雞鳴藏麗句，遙看鳳閣散層陰。", "幾多故舊問衰悴，說似羸師不足擒。"]'),
('9641e79b-1645-4bd2-925a-b8aaa335bff9','九日戲作','晁說之','宋','宋诗','song-poetry','','[]','無高可登無節序，無菊與泛無酒罇。',64,'全唐诗/poet.song.68000.json','["無高可登無節序，無菊與泛無酒罇。", "歸計知時凌海岳，傷心成醉迷乾坤。", "冥冥烟雨翻愁思，急急風霜若苦言。", "安得北人來見我，會須暮出水東門。"]'),
('bc845d72-0fc8-46c9-a360-e948df85745a','偶見司馬公休陳無己書簡感舊作絕句','晁說之','宋','宋诗','song-poetry','','[]','卓行高文司馬陳，當年簡牘拂埃塵。',32,'全唐诗/poet.song.68000.json','["卓行高文司馬陳，當年簡牘拂埃塵。", "身名暫振久青冢，見在凄凉海畔身。"]'),
('2608bfed-698a-4c3d-8a94-25d367ed6155','書事呈中令長老','晁說之','宋','宋诗','song-poetry','','[]','憶昔中華年少壯，相逢海角意何如。',32,'全唐诗/poet.song.68000.json','["憶昔中華年少壯，相逢海角意何如。", "驚人老境便如此，還解同嘗橄欖無。"]'),
('f9bd3a8a-09e6-463e-8bfe-6e2223128797','枕上作','晁說之','宋','宋诗','song-poetry','','[]','年華又已暮，客恨更難裁。',48,'全唐诗/poet.song.68000.json','["年華又已暮，客恨更難裁。", "寒鴈背潮去，鐘聲隨雨來。", "離騷今我讀，時命昔人哀。", "但喜歸期近，寧論白髪催。"]'),
('b4257deb-a772-4d60-aae3-58a7ee250911','有感','晁說之','宋','宋诗','song-poetry','','[]','天邊鴻鴈會高飛，白髪婆娑敢庶幾。',64,'全唐诗/poet.song.68000.json','["天邊鴻鴈會高飛，白髪婆娑敢庶幾。", "哭子淚乾心尚折，還山計就事仍非。", "交遊幾處聞捐玦，巖阜何人自採薇。", "海角再逢殘歲雨，懶將梅葉洗征衣。"]'),
('c986e0d6-e769-4889-b588-db849ea53f0d','書懷二絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','老境才來便輒留，龍門勝韻去悠悠。',32,'全唐诗/poet.song.68000.json','["老境才來便輒留，龍門勝韻去悠悠。", "此懷京洛愁無限，更對滄江煙雨愁。"]'),
('7c21f717-e78b-4fd1-8384-a33fc18efbee','書懷二絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','古木江亭懶不開，書空自笑興悠哉。',32,'全唐诗/poet.song.68000.json','["古木江亭懶不開，書空自笑興悠哉。", "蒼苔一徑淺深遍，知道無人向此來。"]'),
('e2c8aa9f-ef2a-4da4-877f-9af1acf1c382','疊後','晁說之','宋','宋诗','song-poetry','','[]','病眼終朝更懶開，難輸心曲語悠哉。',32,'全唐诗/poet.song.68000.json','["病眼終朝更懶開，難輸心曲語悠哉。", "從教苔徑無人到，日日潮聲自上來。"]'),
('17dad130-a151-4475-89ed-7b1211a664ac','年年至日常爲客','晁說之','宋','宋诗','song-poetry','','[]','年年至日常爲客，只此凄凉似古人。',64,'全唐诗/poet.song.68000.json','["年年至日常爲客，只此凄凉似古人。", "忍傍寒江望京國，難將旅鴈與心親。", "天涯誰解觀雲物，弟輩遙憐面玉宸。", "自料明年猶俗駕，南京不到到西秦。"]'),
('f20a8b69-996b-4243-b180-a13faa5cfef6','無那','晁說之','宋','宋诗','song-poetry','','[]','無那客愁翻作樂，尋常閉目暫時開。',64,'全唐诗/poet.song.68000.json','["無那客愁翻作樂，尋常閉目暫時開。", "沉沉月向波心出，渺渺人從天際來。", "莫道一山無積雪，誰家千樹落寒梅。", "洛陽故舊吾憐汝，愁絕終朝泥酒杯。"]'),
('dd22a087-1475-4e52-91e1-fbfe8cba3e2e','次韻和周大書事絕句','晁說之','宋','宋诗','song-poetry','','[]','終日寒齋咏小招，故人軒檻俯谿橋。',32,'全唐诗/poet.song.68000.json','["終日寒齋咏小招，故人軒檻俯谿橋。", "可憐不得宣城郡，白日消來恨未消。"]'),
('f93a9a9b-fbe5-459a-a394-41ede3825a1a','無題','晁說之','宋','宋诗','song-poetry','','[]','身世何如薦福碑，浮沉聊學弄潮兒。',64,'全唐诗/poet.song.68000.json','["身世何如薦福碑，浮沉聊學弄潮兒。", "清風一日令心盡，黄卷三冬漫手披。", "夢寐無煩征錦段，笑談誰敢犯湯池。", "周侯鳳德寧减少，所謂春陽或减之。"]'),
('5a0048e8-57a9-4a2e-bc51-56c79f020fda','鄧掾知言再和暮春詩見視過形推奬有意論詩報作三首  其一','晁說之','宋','宋诗','song-poetry','','[]','駘蕩殘春恨，霞餘散綺紅。',48,'全唐诗/poet.song.68000.json','["駘蕩殘春恨，霞餘散綺紅。", "遊絲能四塞，落葉劇三空。", "思苦欲留夜，愁多却喜風。", "參軍真俊逸，好是念文窮。"]'),
('6d5943a0-2b6e-49c0-b39c-22c71bc98971','鄧掾知言再和暮春詩見視過形推奬有意論詩報作三首  其二','晁說之','宋','宋诗','song-poetry','','[]','君侯哦苦淡，雅不愛深紅。',48,'全唐诗/poet.song.68000.json','["君侯哦苦淡，雅不愛深紅。", "冷眼看春盡，愁腸欲海空。", "近尋山谷體，遠到建安風。", "只恐妨高步，令君似我窮。"]'),
('7de65f50-8f29-4ba8-b9f2-2f0fb862d0b5','鄧掾知言再和暮春詩見視過形推奬有意論詩報作三首  其三','晁說之','宋','宋诗','song-poetry','','[]','江左多才士，君詩醉玉紅。',82,'全唐诗/poet.song.68000.json','["江左多才士，君詩醉玉紅。", "幾篇愁客恨，九畹任春空。", "便欲傾家釀，誰知出谷風。", "劉楊名一代，可惜義山窮。", "西崑體方盛時，梨園伶人作一窮士。", "云是李商隱，襤縷甚，云近日爲人偷盡。"]'),
('cef37964-a07c-424b-9e29-4509f9b2b2e2','答恂闍黎乞漿','晁說之','宋','宋诗','song-poetry','','[]','白頭破褐恂闍黎，硬白高談豈昜知。',32,'全唐诗/poet.song.68000.json','["白頭破褐恂闍黎，硬白高談豈昜知。", "却喜粟漿如北客，從教薄相笑無奇。"]'),
('88221af1-00df-453b-a2ec-2d27d0aa23c3','謝錢掾','晁說之','宋','宋诗','song-poetry','','[]','論思獻納方自代，海舶鮹人豈識渠。',32,'全唐诗/poet.song.68000.json','["論思獻納方自代，海舶鮹人豈識渠。", "長嘯清風含雪語，憐儂不解讀新書。"]'),
('e81c6571-4198-4cf5-8670-9256ac64035e','江暮','晁說之','宋','宋诗','song-poetry','','[]','何能浣客愁，長夏暮江頭。',48,'全唐诗/poet.song.68000.json','["何能浣客愁，長夏暮江頭。", "嵐遠疑無象，潮平似不流。", "須臾雲送雨，蕩颺鳥隨舟。", "明年北歸去，談話未應休。"]'),
('958836cc-ae59-40ca-8eac-d245ab271923','江上獨坐','晁說之','宋','宋诗','song-poetry','','[]','少時曾識京華樂，老得江山懷抱開。',32,'全唐诗/poet.song.68000.json','["少時曾識京華樂，老得江山懷抱開。", "風月不談辜此夕，恨隨潮去與潮回。"]'),
('89e9cf91-c1f7-4a2f-91a4-d14289ea55ba','偶書','晁說之','宋','宋诗','song-poetry','','[]','京華可望無高樓，聞道故人多白頭。',32,'全唐诗/poet.song.68000.json','["京華可望無高樓，聞道故人多白頭。", "此身却似城東柳，惜别傷離不自愁。"]'),
('63f63cab-590e-45ba-a413-227c1dcae8f6','秋','晁說之','宋','宋诗','song-poetry','','[]','長年何事不悲秋，今日天涯愁復愁。',64,'全唐诗/poet.song.68000.json','["長年何事不悲秋，今日天涯愁復愁。", "故國老槐空寂寂，半天歸鴈自悠悠。", "故知庾信多清淚，何事陶潛亦白頭。", "前日家人带楸葉，求身强健更何求。"]'),
('9593f570-d8db-4d0d-9c5f-6fbfb3dbe428','西風','晁說之','宋','宋诗','song-poetry','','[]','秋風幾日過秋關，直訪畸孤海上山。',32,'全唐诗/poet.song.68000.json','["秋風幾日過秋關，直訪畸孤海上山。", "爲報故山都是舊，可憐留滯不知還。"]'),
('8f818eef-b326-4796-ae86-72f0cee3250f','因誦張司業無事焚香坐有時尋竹行之句擬其體作','晁說之','宋','宋诗','song-poetry','','[]','寂寞江邊舍，欹斜架上書。',48,'全唐诗/poet.song.68000.json','["寂寞江邊舍，欹斜架上書。", "焚香一童子，尋竹衆雞雛。", "更甚昔人懶，寧論今世疏。", "但慚爲吏在，不得跨鯨魚。"]'),
('d5a397f6-f12b-41fc-983f-238bd96cf1c1','自詠','晁說之','宋','宋诗','song-poetry','','[]','椶籬蕉落貯秋陰，睡足蕭然學越吟。',64,'全唐诗/poet.song.68000.json','["椶籬蕉落貯秋陰，睡足蕭然學越吟。", "懶似嵇康初不鍛，閒於陶令更無琴。", "兒童亦習南朝事，風月應憐北客心。", "五世圖書幸相逐，鬢毛未許雪霜侵。"]'),
('7cfc5861-1dff-45ec-a14c-b1dccb3239ca','江亭晚望','晁說之','宋','宋诗','song-poetry','','[]','秋色日駸駸，江亭敞宿陰。',48,'全唐诗/poet.song.68000.json','["秋色日駸駸，江亭敞宿陰。", "殘霞沉浦口，新月出波心。", "客恨此時薄，歸懷晚歲深。", "鄰僧數來往，未肯愧南金。"]'),
('96cae71c-404a-4847-a282-c5124d5e9528','興盡','晁說之','宋','宋诗','song-poetry','','[]','興盡未歸增寂寞，却嗟初興到江城。',64,'全唐诗/poet.song.68000.json','["興盡未歸增寂寞，却嗟初興到江城。", "春愁不逐楊花散，秋恨還同桂影生。", "孤學敢期人晤語，危檣何事日崢嶸。", "弟兄遊宦俱還舍，朝馬驂驔禁漏聲。"]'),
('ff63b611-b6ef-4c82-9e71-92d5ed7cb103','偶作二首  其一','晁說之','宋','宋诗','song-poetry','','[]','病目書滛歇，江干絕往來。',48,'全唐诗/poet.song.68000.json','["病目書滛歇，江干絕往來。", "不才寧嫁樹，有意尚移山。", "玉府書名久，南山種豆閒。", "只應終夜氣，不共鬢毛班。"]'),
('bd209861-2b21-495f-ada7-2a7df3eb2c1c','偶作二首  其二','晁說之','宋','宋诗','song-poetry','','[]','聞道花都發，狂風故作讎。',48,'全唐诗/poet.song.68000.json','["聞道花都發，狂風故作讎。", "春心先自薄，客恨更難收。", "不免饑寒甚，永同埋璸休。", "何須問詹尹，雅意在丹丘。"]'),
('460c924e-f642-4818-b2fd-7577f771d0f4','有感','晁說之','宋','宋诗','song-poetry','','[]','吏隱兩非空百感，塗窮浪跡亦何哉。',64,'全唐诗/poet.song.68000.json','["吏隱兩非空百感，塗窮浪跡亦何哉。", "波濤遠引月華去，風雨常將月色來。", "孤學有誰同慷慨，獨愁無地重徘徊。", "漫談景德祥符際，幾許辭源賦八哀。"]'),
('e7922956-08de-4264-9b8b-6a7da23204f6','戲呈通叟年兄索其近詩','晁說之','宋','宋诗','song-poetry','','[]','歸期若可數，何事此時情。',48,'全唐诗/poet.song.68000.json','["歸期若可數，何事此時情。", "春色雨中盡，客愁天際生。", "離騷煩爾傳，月旦莫余評。", "早韭周妻厭，因因不肯鳴。"]'),
('66ce44fc-dca2-4dd7-aae0-1b0976f1e13f','落花學義山','晁說之','宋','宋诗','song-poetry','','[]','春來脉脉去輪囷，滿地飛英委玉塵。',64,'全唐诗/poet.song.68000.json','["春來脉脉去輪囷，滿地飛英委玉塵。", "荀令香殘端有意，石家錦碎更堪珍。", "目成霄漢星前石，腸斷驪駒掌上人。", "我久飄零本憔悴，爲君今日恨輪巾。"]'),
('ecfae903-7616-4f0c-9285-522eeaad1137','花開未幾忽已落盡戲作','晁說之','宋','宋诗','song-poetry','','[]','天涯花信誤心期，狼藉殘紅只往時。',32,'全唐诗/poet.song.68000.json','["天涯花信誤心期，狼藉殘紅只往時。", "怪底小憐渾不睡，夜深惆悵夢周師。"]'),
('0e85c59d-5ee2-4dd9-b09b-95e902f0c076','通叟年兄視以柳侯廟詩三首輒亦有作所謂增來章之美也  其一','晁說之','宋','宋诗','song-poetry','','[]','平昔柳侯廟，拾君詩興餘。',48,'全唐诗/poet.song.68000.json','["平昔柳侯廟，拾君詩興餘。", "帝閽誰掌制，天步此貞符。", "敢恨初沈佩，惟慚再索車。", "羅池聊自戲，况復已榛蕪。"]'),
('25150824-fa3f-481d-ab90-03724b88bcf0','通叟年兄視以柳侯廟詩三首輒亦有作所謂增來章之美也  其二','晁說之','宋','宋诗','song-poetry','','[]','何處乘駒去，空庭荔子垂。',48,'全唐诗/poet.song.68000.json','["何處乘駒去，空庭荔子垂。", "韓詞方走奠，柳廟久徂饑。", "既恨謀身誤，仍嗟報國隳。", "羅池便如此，不復問愚池。"]'),
('dd5df56a-f06d-448b-a9ef-69cd9a05e6ca','通叟年兄視以柳侯廟詩三首輒亦有作所謂增來章之美也  其三','晁說之','宋','宋诗','song-poetry','','[]','當世容讒賊，他年奈我何。',48,'全唐诗/poet.song.68000.json','["當世容讒賊，他年奈我何。", "文編興舊學，詩價重東坡。", "木檞開能幾，子規啼漫多。", "羅池碑字滅，猶解徹庭莎。"]'),
('86f2098f-6b77-4c58-b781-43be524bfc1b','贈柳三解  其一','晁說之','宋','宋诗','song-poetry','','[]','莫道垂楊管别離，與春離别自依依。',32,'全唐诗/poet.song.68000.json','["莫道垂楊管别離，與春離别自依依。", "若教兼有征人恨，只恐鴉兒不肯歸。"]'),
('e26492a4-6e7d-4c1c-8098-15d1da382da7','贈柳三解  其二','晁說之','宋','宋诗','song-poetry','','[]','海角那知有宮柳，故園春思尚依依。',32,'全唐诗/poet.song.68000.json','["海角那知有宮柳，故園春思尚依依。", "可憐風韻去人遠，一日花開天際飛。"]'),
('16c04dc4-a25d-4ea8-9eb3-9cf153400f5d','贈柳三解  其三','晁說之','宋','宋诗','song-poetry','','[]','桃李那知楊柳恨，故時風雨不依依。',32,'全唐诗/poet.song.68000.json','["桃李那知楊柳恨，故時風雨不依依。", "自從彭澤無人後，青眼雖開心事非。"]'),
('bd9a367c-eea7-434e-84a2-34a33f8279ce','悠悠','晁說之','宋','宋诗','song-poetry','','[]','悠悠知作吏，泯泯送年華。',48,'全唐诗/poet.song.68000.json','["悠悠知作吏，泯泯送年華。", "勉强對殘客，慇懃惜落花。", "敦行慚不聖，潮汐恨空賒。", "却怕梁園去，家人問海涯。"]'),
('1d289546-a001-409f-b0aa-9035dc222d3d','題明王打毬圖','晁說之','宋','宋诗','song-poetry','','[]','閶闔千門萬戶開，三郎沈醉打毬回。',32,'全唐诗/poet.song.68000.json','["閶闔千門萬戶開，三郎沈醉打毬回。", "九齡已去韓休死，無復明朝諫疏來。"]'),
('a2c3bea0-da53-4a19-be74-02be80985f2a','從教','晁說之','宋','宋诗','song-poetry','','[]','從教病着探葵减，未放愁攻白髪添。',32,'全唐诗/poet.song.68000.json','["從教病着探葵减，未放愁攻白髪添。", "欲看落花時入戶，風高盡日不垂簾。"]'),
('e1db39fc-4962-483f-9f60-38622bbca19f','何事','晁說之','宋','宋诗','song-poetry','','[]','何事千憂自惘然，且看節物異鄉邊。',64,'全唐诗/poet.song.68000.json','["何事千憂自惘然，且看節物異鄉邊。", "鶯來昨日猶多吃，柳到今朝第幾眠。", "上巳清明徒頡頏，流觴蹴踘豈周旋。", "故知白髪因渠得，忍更貪愁憶往年。"]'),
('8065c9e1-5fc7-4949-bf20-6373c314578d','還諸唱和雪詩次韻作二首  其一','晁說之','宋','宋诗','song-poetry','','[]','蕭散人間阮始平，輕盈雲外董雙成。',64,'全唐诗/poet.song.68000.json','["蕭散人間阮始平，輕盈雲外董雙成。", "飛英試比休爭麗，連璧驩言與共明。", "黄竹異時徒思苦，幽蘭同調得心傾。", "何須灞岸蹇驢夜，更學幽人老婢聲。"]'),
('d79a178a-46d8-491f-8df0-deaabe85ccae','還諸唱和雪詩次韻作二首  其二','晁說之','宋','宋诗','song-poetry','','[]','胸中塊磊若爲平，今日相如雪賦成。',64,'全唐诗/poet.song.68000.json','["胸中塊磊若爲平，今日相如雪賦成。", "廣野喜逢三得白，高山真遇四邊明。", "瑤音顧我何能和，玉色煩君幾見傾。", "形穢由來慚獨目，自憐猶識佩環聲。"]'),
('a24bdea0-f436-40d8-a4cf-7ec004bc8405','咋舌','晁說之','宋','宋诗','song-poetry','','[]','咋舌何堪妾一鳴，三年如夢寄江城。',32,'全唐诗/poet.song.68000.json','["咋舌何堪妾一鳴，三年如夢寄江城。", "春江細雨添清思，漸近歸期更有情。"]'),
('42db4e11-163a-41a5-9465-e53956e5fe81','暮江','晁說之','宋','宋诗','song-poetry','','[]','南潮勝韻此間無，醉本蘭亭强學書。',32,'全唐诗/poet.song.68000.json','["南潮勝韻此間無，醉本蘭亭强學書。", "人物本朝還可恨，誰傳燕老暮江圖。"]'),
('09847e06-2b8b-4472-a8ba-637119411496','自和因思國史燕穆之傳稱其知明州革輕悍鬬爭之俗及今海潮圖作','晁說之','宋','宋诗','song-poetry','','[]','燕公未肯祖虛無，悍俗歸仁舉國書。',32,'全唐诗/poet.song.68000.json','["燕公未肯祖虛無，悍俗歸仁舉國書。", "莫道邦人都背德，壁間猶有海潮圖。"]'),
('05242410-c243-42a7-adb3-a75e0f908908','欲談','晁說之','宋','宋诗','song-poetry','','[]','欲談無應莫吾容，悔不居身可否中。',32,'全唐诗/poet.song.68000.json','["欲談無應莫吾容，悔不居身可否中。", "盡日小齋何所樂，芭蕉宜雨竹宜風。"]'),
('34710e29-70c9-4c5a-99d4-da87cf0e7879','王順之得子寄二絕次韻報之  其一','晁說之','宋','宋诗','song-poetry','','[]','賓客能談少傅兒，海中仙果得生遲。',32,'全唐诗/poet.song.68000.json','["賓客能談少傅兒，海中仙果得生遲。", "自今一落人間後，即見新枝壓舊枝。"]'),
('54e1e49a-b18e-433c-a94b-38a38215c9fb','王順之得子寄二絕次韻報之  其二','晁說之','宋','宋诗','song-poetry','','[]','茂弘不用長年悲，淮水東流本與期。',32,'全唐诗/poet.song.68000.json','["茂弘不用長年悲，淮水東流本與期。", "一日名駒驚俗眼，奔雲老驥敢言衰。"]'),
('509682cf-06db-4192-811d-012780b94aec','水仙','晁說之','宋','宋诗','song-poetry','','[]','水仙踰月駐芳馨，人物誰堪眼共青。',32,'全唐诗/poet.song.68000.json','["水仙踰月駐芳馨，人物誰堪眼共青。", "白傅有詩皆入律，腥鹹聲裏亦須聽。"]'),
('c95beea2-42f0-4731-8674-7010ae6a58ef','春初','晁說之','宋','宋诗','song-poetry','','[]','春初未有象，幽興一何深。',48,'全唐诗/poet.song.68000.json','["春初未有象，幽興一何深。", "細雨能輸酒，輕風不隔琴。", "無煩問北信，且强學南音。", "白髪寧欺客，愁來處處侵。"]'),
('a4b3e02a-29cb-442d-bd1b-f8ceacdb84fd','風雪','晁說之','宋','宋诗','song-poetry','','[]','風雪三冬北，江潮二月時。',24,'全唐诗/poet.song.68000.json','["風雪三冬北，江潮二月時。", "怪今阿那事，不得作春詩。"]'),
('fae5d9de-8aab-4c01-944b-94931fe5623f','病目作近體詩五首  其一','晁說之','宋','宋诗','song-poetry','','[]','病目經旬作夢中，只應天意欲教傭。',64,'全唐诗/poet.song.68000.json','["病目經旬作夢中，只應天意欲教傭。", "詩成願作瞎太祝，位極耻爲盲老公。", "不用千憂徒畫足，何妨一笑漫書空。", "頗不如喜見人志，好在春來六六峰。"]'),
('88994a47-86e9-4dfc-b47b-a784690ee4b4','病目作近體詩五首  其二','晁說之','宋','宋诗','song-poetry','','[]','何事蘭成酷愛愁，借愁爲樂總宜休。',64,'全唐诗/poet.song.68000.json','["何事蘭成酷愛愁，借愁爲樂總宜休。", "天涯二月無新曆，京國三年誤舊遊。", "忽接家書迷遠近，欲爲客難却沉浮。", "道人猶喜頻相遇，話盡丹丘更虎丘。"]'),
('70bdd571-4a56-4712-a4cd-8481032c5bdb','病目作近體詩五首  其三','晁說之','宋','宋诗','song-poetry','','[]','江頭未省逢春事，風雨朝朝夜夜深。',64,'全唐诗/poet.song.68000.json','["江頭未省逢春事，風雨朝朝夜夜深。", "皎潔一生餘白髪，辛勤百計只丹心。", "不疑鄭默世能怨，敢恨虞翻論所侵。", "明日逢人添俛首，會催歸興到山林。"]'),
('3f2dedd0-228d-4a31-a1a7-67bf5f9033ac','病目作近體詩五首  其四','晁說之','宋','宋诗','song-poetry','','[]','沉沉何處有春柔，目極無垠風雨秋。',64,'全唐诗/poet.song.68000.json','["沉沉何處有春柔，目極無垠風雨秋。", "底事須登七尺劍，要當自掖千金裘。", "圖書雖滿愧黄絹，桃李縱開嘲白頭。", "事與願違宜泯泯，願違於事更悠悠。"]'),
('7953c233-09fe-4cf2-abaa-98f402b2af64','病目作近體詩五首  其五','晁說之','宋','宋诗','song-poetry','','[]','愁極猶知吾道尊，尚煩幾許北堂萱。',64,'全唐诗/poet.song.68000.json','["愁極猶知吾道尊，尚煩幾許北堂萱。", "善人在疚鄉評减，老物可憎天意存。", "漫使楚囚臨澧浦，難教漢使識河源。", "著書昔日年猶少，老意今朝欲絕言。"]'),
('bf16a766-dccb-4e14-8609-dc489b1f6405','惜春','晁說之','宋','宋诗','song-poetry','','[]','待得鶯來花已落，斷難料理漫咿嚘。',32,'全唐诗/poet.song.68000.json','["待得鶯來花已落，斷難料理漫咿嚘。", "便如前哲亦非敵，八斗才當萬斛愁。"]'),
('11444a6e-902e-44cf-8487-63a21f988836','春色','晁說之','宋','宋诗','song-poetry','','[]','春色真無賴，羈人自慨慷。',48,'全唐诗/poet.song.68000.json','["春色真無賴，羈人自慨慷。", "鶯能嘲客語，花解笑人忙。", "腰衱休含睇，欄干枉斷腸。", "明當元幾日，何處有流觴。"]'),
('acb7e718-b881-43ff-be7b-37f5336e268b','贈道光','晁說之','宋','宋诗','song-poetry','','[]','老僧講罷結茅廬，憶昔鳴琴着意餘。',32,'全唐诗/poet.song.68000.json','["老僧講罷結茅廬，憶昔鳴琴着意餘。", "一曲風前三百遍，十年不作作如初。"]'),
('40dbdbe1-a9a4-4d21-a001-0659cc532d72','即事','晁說之','宋','宋诗','song-poetry','','[]','自言愚似醉，休道醉如愚。',48,'全唐诗/poet.song.68000.json','["自言愚似醉，休道醉如愚。", "不耻小盤食，寧慚掘筆書。", "九原懷往淚，萬里夢同途。", "政恐能知我，何妨更罵予。"]'),
('fd1459e8-bbd9-453c-a696-578e93951797','感舊寄上芸叟侍郎','晁說之','宋','宋诗','song-poetry','','[]','於越茫茫羈旅久，函秦落落笑談中。',64,'全唐诗/poet.song.68000.json','["於越茫茫羈旅久，函秦落落笑談中。", "曲江煙月新春夢，寒食人家故國風。", "此際一罇曾邂逅，他時相見更從容。", "丈人筆力知强健，何事書來不吐虹。"]'),
('161842af-1cc3-44cd-9153-e37e83127056','寄韓君表','晁說之','宋','宋诗','song-poetry','','[]','别離何用愁天涯，塵世來由百感賒。',64,'全唐诗/poet.song.68000.json','["别離何用愁天涯，塵世來由百感賒。", "白雪恨難逢柳絮，東風悔不識梅花。", "詩書異戶余何有，將相同時君莫誇。", "聞道近還思卜築，好來嵩少共煙霞。"]'),
('381a9322-6be4-49d2-922f-c687f1401881','感舊','晁說之','宋','宋诗','song-poetry','','[]','林梢接手百花浮，昔與王孫倚小樓。',64,'全唐诗/poet.song.68000.json','["林梢接手百花浮，昔與王孫倚小樓。", "風物無情常自若，男兒何處不堪愁。", "蘭成只憶江南老，丞相難忘洛下游。", "今日天涯送春淚，不堪更爲種瓜侯。"]'),
('73b0ab7d-f96c-487f-b0df-d372177c973b','偶見張天貺奉議書策後題跋感舊作絕句','晁說之','宋','宋诗','song-poetry','','[]','軒軒衆藝張天貺，翰墨悲凉二絕餘。',32,'全唐诗/poet.song.68000.json','["軒軒衆藝張天貺，翰墨悲凉二絕餘。", "今日無人知姓字，史官他日若爲書。"]'),
('139d6665-e6e1-48ab-8ddf-b68f95be9a32','春盡  其一','晁說之','宋','宋诗','song-poetry','','[]','春盡天涯恨最長，啼鶯不識紫遊韁。',32,'全唐诗/poet.song.68000.json','["春盡天涯恨最長，啼鶯不識紫遊韁。", "空驚綠葉成尖髪，何處殘英伴落妝。"]'),
('e98f864f-e48d-4666-b27b-94605095b3b5','春盡  其二','晁說之','宋','宋诗','song-poetry','','[]','何曾有夢到瑤池，但見狂風落海陂。',32,'全唐诗/poet.song.68000.json','["何曾有夢到瑤池，但見狂風落海陂。", "簾外飄英紛不識，誰人尚復憶辛夷。"]'),
('79f426ab-e12e-4d4e-8678-5973f7885368','恨同','晁說之','宋','宋诗','song-poetry','','[]','恨同枉渚頻潮汐，情與游絲鬬短長。',32,'全唐诗/poet.song.68000.json','["恨同枉渚頻潮汐，情與游絲鬬短長。", "垂釣蠻童緣底泣，難將心事問何郎。"]'),
('67ed8580-4fca-4cfb-8802-44394b226f30','二十六弟寄和江子我竹夫人詩一首愛其巧思戲作二首  其一','晁說之','宋','宋诗','song-poetry','','[]','莫愁嫵媚主人盧，纖質交竿巧得模。',64,'全唐诗/poet.song.68000.json','["莫愁嫵媚主人盧，纖質交竿巧得模。", "綠粉敢爭紅粉麗，魚軒休比鶴軒疏。", "女英漫對湘君泣，子政徒青天禄書。", "夾膝得名何不韻，秋來卧病竟何如。"]'),
('ce1cf003-847d-458e-a315-2197298c6709','二十六弟寄和江子我竹夫人詩一首愛其巧思戲作二首  其二','晁說之','宋','宋诗','song-poetry','','[]','寥寥故國漫玄盧，內子可憐殊不模。',64,'全唐诗/poet.song.68000.json','["寥寥故國漫玄盧，內子可憐殊不模。", "擬比封君寧有實，欲爲節婦亦何疏。", "且休深妬斫桃樹，枉是多愁織錦書。", "貧士一妻常不飽，更煩譏謫幾人如。"]'),
('e46e171f-1154-4e64-a880-a43cd15ac161','復次韻寄子我四首  其一','晁說之','宋','宋诗','song-poetry','','[]','柴門僅付一寒盧，不內不妻深有模。',64,'全唐诗/poet.song.68000.json','["柴門僅付一寒盧，不內不妻深有模。", "每與篔簹同繾綣，好來箕箒共蕭疏。", "謝娘莫道能聯句，鄭婢無煩亦讀書。", "前日㛹娟今不見，頭槌眼臼却能如。"]'),
('5eeb7a58-eaea-49b4-8533-84ade7a6f25c','復次韻寄子我四首  其二','晁說之','宋','宋诗','song-poetry','','[]','何須晚嫁獨傷盧，雲母無媒自納模。',64,'全唐诗/poet.song.68000.json','["何須晚嫁獨傷盧，雲母無媒自納模。", "虹斷美人情不競，雨回神女分還疏。", "敢同孫壽巧爲態，頗稱江淹懶著書。", "歎息火籠俱麗質，當年風韻本何如。"]'),
('74f3be8c-4e40-4784-8f41-94ff731ed512','復次韻寄子我四首  其三','晁說之','宋','宋诗','song-poetry','','[]','當年配馬莫嘲盧，今日化龍還寑模。',64,'全唐诗/poet.song.68000.json','["當年配馬莫嘲盧，今日化龍還寑模。", "麈尾雖長君不妬，搔頭漫短我能疏。", "夜寒青女難攜手，海闊麻姑肯寄書。", "五色筆歸空婉娩，幽篁殘夢自常如。"]'),
('5d06497b-a978-4fbc-abd9-2ec133abe9c4','復次韻寄子我四首  其四','晁說之','宋','宋诗','song-poetry','','[]','汾陽勳業重彤盧，凉霍同封不世模。',64,'全唐诗/poet.song.68000.json','["汾陽勳業重彤盧，凉霍同封不世模。", "貧士豈知燕玉暖，幽眠莫共膩香疏。", "從容恥與石爲弟，寤寐欣逢仙降書。", "若是雙流參六貴，錦圍繡被又焉如。"]'),
('716cf92f-faed-453a-a63b-b7b8d0dc59f7','次韻和韓君表懷歸見寄','晁說之','宋','宋诗','song-poetry','','[]','旅夢何爲喜别嵩，移雲當日自栽松。',64,'全唐诗/poet.song.68000.json','["旅夢何爲喜别嵩，移雲當日自栽松。", "公孫勳業忽垂意，逋客煙霞豈不容。", "笑語若同遊下澤，雞豚亦共卧高舂。", "莫誇有力先歸去，恐愧朝蟬與暮虹。"]'),
('461b720b-4738-4408-8e63-63e4c7b9574b','留别延慶明智','晁說之','宋','宋诗','song-poetry','','[]','傍海嗟爲客，傾心欣所知。',48,'全唐诗/poet.song.68000.json','["傍海嗟爲客，傾心欣所知。", "煙霞威鳳老，岐路斷猿悲。", "夢亦西方近，談休南本遲。", "行行招隱意，嵩岫解相思。"]'),
('1cfa6e2d-d8e3-4954-8e4e-0e73c57d1885','余寄和冲弟竹夫人詩并寄子我六首後征其類自貺','晁說之','宋','宋诗','song-poetry','','[]','風流何處有崔盧，委曲此君爲我模。',64,'全唐诗/poet.song.68000.json','["風流何處有崔盧，委曲此君爲我模。", "草夢枕仙幽意在，燭奴燈婢故情疏。", "偶人飄蕩泥何恨，居士神通木漫書。", "葉可作冠聊復爾，恨爲如意亦何如。"]'),
('132be9f9-12a5-49b9-afcd-0dbf448843b1','還通叟年兄詩卷','晁說之','宋','宋诗','song-poetry','','[]','白頭從事未抛詩，無奈才何復苦饑。',32,'全唐诗/poet.song.68000.json','["白頭從事未抛詩，無奈才何復苦饑。", "我易吟愁歸樂土，因君腸斷鄴中詩。"]'),
('761076c4-105d-405c-8eca-40581641b05a','謝景修惠洞庭春色','晁說之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭春色何年賦，越國王孫幾種愁。',32,'全唐诗/poet.song.68000.json','["洞庭春色何年賦，越國王孫幾種愁。", "今日忽親鸚鵡杓，當家餘韻落芳洲。"]'),
('e542d56d-05a0-46d5-8cbf-db7bf3d373cc','贈童子蚍蜉','晁說之','宋','宋诗','song-poetry','','[]','拂拭方山帽，安排一複巾。',24,'全唐诗/poet.song.68000.json','["拂拭方山帽，安排一複巾。", "春秋書滿架，整整莫因循。"]'),
('b9136365-7450-4776-b842-fb7a7bdc9e42','答童','晁說之','宋','宋诗','song-poetry','','[]','何敢愛筋力，無勞戒勵重。',24,'全唐诗/poet.song.68000.json','["何敢愛筋力，無勞戒勵重。", "但當知諱字，聞說是雅中。"]'),
('c94ab68b-9366-4119-a8a3-0996fceed393','題畫扇','晁說之','宋','宋诗','song-poetry','','[]','秦秦何處樂，獨自託孤枝。',24,'全唐诗/poet.song.68000.json','["秦秦何處樂，獨自託孤枝。", "玉粒知無分，清風也自戲。"]'),
('461b577f-a953-4b36-8eb6-bd5e68420c36','寄昭德兄弟  其一','晁說之','宋','宋诗','song-poetry','','[]','莫言無合亦何傷，旅雁卑飛怯稻粱。',32,'全唐诗/poet.song.68000.json','["莫言無合亦何傷，旅雁卑飛怯稻粱。", "南畝荒蕪嵩少遠，却來檝口祭勾芒。"]'),
('f75ed8d2-9e1b-4a7f-8a02-1d9c0ec4d140','寄昭德兄弟  其二','晁說之','宋','宋诗','song-poetry','','[]','甬東羈旅情何託，江北蒼芒恨不收。',32,'全唐诗/poet.song.68000.json','["甬東羈旅情何託，江北蒼芒恨不收。", "靜夜櫓聲來枕上，猶疑身在木蘭舟。"]'),
('6d236dbd-bc9d-4119-aa67-d5f05ca48681','哭程伯威','晁說之','宋','宋诗','song-poetry','','[]','程子音書歲月賒，幾年泉下始咨嗟。',64,'全唐诗/poet.song.68000.json','["程子音書歲月賒，幾年泉下始咨嗟。", "孤忠曾奏三千牘，絕藝寧論十四家。", "白髪父號無淚絕，青箱兒恨有塵遮。", "人生到此成何事，第二碑成亦漫誇。"]'),
('57d39eac-afec-4a00-90a8-554ef1428405','觀明道先生桃花菊詩作','晁說之','宋','宋诗','song-poetry','','[]','歎息天工暫醉時，重陽物色艶陽姿。',32,'全唐诗/poet.song.68000.json','["歎息天工暫醉時，重陽物色艶陽姿。", "便生春思兼秋緒，當日董生宜一窺。"]'),
('b288bfc6-703e-4e83-b3bd-f1ca9d65658d','疊前','晁說之','宋','宋诗','song-poetry','','[]','董生今日窺園圃，幾許傷心涕淚垂。',32,'全唐诗/poet.song.68000.json','["董生今日窺園圃，幾許傷心涕淚垂。", "金令不行呈木怪，無端災異樂哀爲。"]'),
('6fc667dc-c3c8-434f-8526-f955a173fd77','題大年閣路逢僧圖','晁說之','宋','宋诗','song-poetry','','[]','關深羈思滿，風斷綠陰單。',24,'全唐诗/poet.song.68000.json','["關深羈思滿，風斷綠陰單。", "一遇空門侣，那知行路難。"]'),
('d6ef61fb-61b3-477d-8895-f53e482e0ce6','次韻任伯再領宗學長句','晁說之','宋','宋诗','song-poetry','','[]','幾重墨守豈難攻，歎息儒珍亦易窮。',64,'全唐诗/poet.song.68000.json','["幾重墨守豈難攻，歎息儒珍亦易窮。", "轇轕八紘騷遠邇，凄凉一代賦幽通。", "喜君再戴長安日，顧我頻驚沙朔風。", "莫恨官曹太清冷，宮花時醉上林中。"]'),
('c39042fc-ee3b-4478-ab59-1474c687043f','又和西捷','晁說之','宋','宋诗','song-poetry','','[]','西州五帥議多攻，决策曾聞利不窮。',64,'全唐诗/poet.song.68000.json','["西州五帥議多攻，决策曾聞利不窮。", "今日一乘能必取，異時重譯要皆通。", "明光喜霽甲兵雨，沙磧恩搖草木風。", "自顧腐儒何所補，騎豬難在虎狼中。"]'),
('6fb376fd-f2d5-4b9f-8755-1f83309f9868','赴鄜州京鄭間途中作','晁說之','宋','宋诗','song-poetry','','[]','園林葉落丹丘遠，坂路霜寒白髪侵。',32,'全唐诗/poet.song.68000.json','["園林葉落丹丘遠，坂路霜寒白髪侵。", "不是關西將家子，也無詩思著秦音。"]'),
('4d4009ec-c30f-4eba-81e0-e64484eb985b','頃客解梁有詩云中條山下讀周易定是前身關子明是時頻與張芸叟侍郎通書亦嘗寄此詩呈視今再過此郡遇芸叟之客王六東起感懷而作','晁說之','宋','宋诗','song-poetry','','[]','坂路十年塵坱身，不知何事往來頻。',64,'全唐诗/poet.song.68000.json','["坂路十年塵坱身，不知何事往來頻。", "敢言上國非吾土，自許中條是故人。", "志在韋編徒寡與，人亡陸海漫多珍。", "龍門有客暫相值，頗話年來亦苦辛。"]'),
('d03abaad-1c03-4bb8-a052-40a2133d7673','河中府追懷亡二兄及思永興十二弟','晁說之','宋','宋诗','song-poetry','','[]','表裏山河季布州，我家兄弟憶同遊。',64,'全唐诗/poet.song.68000.json','["表裏山河季布州，我家兄弟憶同遊。", "芸香寂寞空青冢，絳帳飄零欲白頭。", "羈旅即今無好語，登臨自古有高樓。", "頗聞酬唱西巖在，闕里諸孫添我愁。"]'),
('167df719-301e-450a-92f1-3fbff531d7c2','河中戲作絕句','晁說之','宋','宋诗','song-poetry','','[]','人物英雄異姓王，山河生氣尚光芒。',32,'全唐诗/poet.song.68000.json','["人物英雄異姓王，山河生氣尚光芒。", "可憐只解誇佳麗，花落春空更斷腸。"]'),
('e65848cd-dfaa-4233-b181-e6e6f2bab3f9','途中','晁說之','宋','宋诗','song-poetry','','[]','十年未就歸山計，一日歸爲保障翁。',64,'全唐诗/poet.song.68000.json','["十年未就歸山計，一日歸爲保障翁。", "無奈征衣中散虱，可堪行道庶人風。", "悠悠秦晉山河在，漠漠金張冢墓空。", "回首江湖二三子，長亭寒夢亦匆匆。"]'),
('caf232a9-9172-4b47-b990-be0fa3b6fc6c','途中寄高仲詔','晁說之','宋','宋诗','song-poetry','','[]','飄零誰惜别，不賦送行詩。',48,'全唐诗/poet.song.68000.json','["飄零誰惜别，不賦送行詩。", "獨有悲秋客，難忘上壠時。", "素心慚錦段，清淚濕瓊枝。", "塞馬寒來健，夫君莫我思。"]'),
('fe8d0976-a2e5-45f7-9b8d-5b412b14a894','過荆軻冢四絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','過華踰河勢北傾，何人來此葬荆卿。',32,'全唐诗/poet.song.68000.json','["過華踰河勢北傾，何人來此葬荆卿。", "千金匕首安知在，易水寒來尚有情。"]'),
('7e9b3e27-1c71-4537-910d-bb1d9cb61970','過荆軻冢四絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','太子當年計不疏，虎狼有劍斷頭顱。',32,'全唐诗/poet.song.68000.json','["太子當年計不疏，虎狼有劍斷頭顱。", "逡巡不血荆軻手，自要輼輬費鮑魚。"]'),
('938879a8-2cfb-4e27-982e-a2b0778bbabc','過荆軻冢四絕句  其三','晁說之','宋','宋诗','song-poetry','','[]','刺客傳中軻絕倫，後來尫怯寂無人。',32,'全唐诗/poet.song.68000.json','["刺客傳中軻絕倫，後來尫怯寂無人。", "秦人更甚燕人恨，不葬燕臺留葬秦。"]'),
('ca7b09d6-e54b-433a-bde6-e9398a9169d8','過荆軻冢四絕句  其四','晁說之','宋','宋诗','song-poetry','','[]','貫日白虹可奈何，書生容易笑荆軻。',32,'全唐诗/poet.song.68000.json','["貫日白虹可奈何，書生容易笑荆軻。", "美新伾黨臨遺冢，慚愧絕無狐兔過。"]'),
('87207faa-6354-488a-923a-83ec8104aad2','將至鄜州','晁說之','宋','宋诗','song-poetry','','[]','平生心迹笑元龍，今日城邊比蔡邕。',32,'全唐诗/poet.song.68000.json','["平生心迹笑元龍，今日城邊比蔡邕。", "豈是白頭著書地，聊當涕泣自從容。"]'),
('ca5d3c14-5bf7-4fce-94d5-a4e891d15d3a','初至鄜州見月','晁說之','宋','宋诗','song-poetry','','[]','此是鄜州月，人間應更無。',24,'全唐诗/poet.song.68000.json','["此是鄜州月，人間應更無。", "欲垂清夜淚，桂影莫扶疏。"]'),
('1d176ab8-c815-470f-abe1-231d691ccbd8','延安江漢堂上懷范五丈龍圖堂是五丈所建','晁說之','宋','宋诗','song-poetry','','[]','煌煌斗柄垂南北，浩浩斯人江漢堂。',64,'全唐诗/poet.song.68000.json','["煌煌斗柄垂南北，浩浩斯人江漢堂。", "横吹三川秋月遠，雅歌九姓暮天長。", "頗間病後精神好，最是秋來飰食强。", "誰識得名因伯氏，飛鴻送盡更茫茫。"]'),
('121ac0da-4157-42d1-b0db-77740d5be706','自延還鄜懷京師親舊','晁說之','宋','宋诗','song-poetry','','[]','羈旅無歸不自任，重重白髪巧相尋。',64,'全唐诗/poet.song.68000.json','["羈旅無歸不自任，重重白髪巧相尋。", "扁舟前歲江湖客，匹馬今朝關塞心。", "攬古豈無王霸略，窮途只有短長吟。", "故人憔悴多如此，誰解多情送好音。"]'),
('169f6af1-d707-4dd7-a2f0-f22e1f09549f','行縣途中讀柳子厚詩','晁說之','宋','宋诗','song-poetry','','[]','征衣窮塞暮冬時，讀盡龍城太守詩。',32,'全唐诗/poet.song.68000.json','["征衣窮塞暮冬時，讀盡龍城太守詩。", "若使生平詩盡在，濯纓無淚爲君垂。"]'),
('b75cd768-3920-4095-a9e8-17e7537816ec','直羅縣三絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','縈回頡頏亂山河，目眩心搖到直羅。',32,'全唐诗/poet.song.68000.json','["縈回頡頏亂山河，目眩心搖到直羅。", "待得羅川平直處，晚來荀令恨如何。"]'),
('516ca816-5275-498c-ad3e-0d5238a2363b','直羅縣三絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','人生不合出都城，百坂千坡異縣情。',32,'全唐诗/poet.song.68000.json','["人生不合出都城，百坂千坡異縣情。", "勃勃當年聖人道，如今狐兔不勝行。"]'),
