('44d402e7-61c7-40dd-a619-82979380a208','在邉','晁說之','宋','宋诗','song-poetry','','[]','在邉有底適予懷，舒慘無時亦異哉。',64,'全唐诗/poet.song.68000.json','["在邉有底適予懷，舒慘無時亦異哉。", "醉到月前如失去，愁從騷裏却招來。", "素心偶向三花盡，孤憤難教貳負催。", "好覓羌村殘夜燭，待將何語與徘徊。"]'),
('f29778f9-4c43-4ddc-bdc4-b4315d7563ed','次韻和完翁謝墨二絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','池水澄輝散曉烟，定無墨色使名傳。',32,'全唐诗/poet.song.68000.json','["池水澄輝散曉烟，定無墨色使名傳。", "幾螺付與能詩客，免更書空重惘然。"]'),
('2b2c351b-6080-4194-a063-7eac63d367c4','次韻和完翁謝墨二絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','寸寸曉松計已迂，更憐百步扇垂珠。',32,'全唐诗/poet.song.68000.json','["寸寸曉松計已迂，更憐百步扇垂珠。", "幾年費盡坐曹手，千卷書生又却無。"]'),
('2a32d01d-8d85-444f-9aef-6ea3eec9273a','聞角','晁說之','宋','宋诗','song-poetry','','[]','邉城百感漫興嗟，客底令人警歲華。',32,'全唐诗/poet.song.68000.json','["邉城百感漫興嗟，客底令人警歲華。", "多謝何郎有新句，誰聞夜夜小梅花。"]'),
('0fae73b0-6cb3-4485-9842-120e45e6faec','迎客道中','晁說之','宋','宋诗','song-poetry','','[]','匆匆中夜轡，候館若爲容。',48,'全唐诗/poet.song.68000.json','["匆匆中夜轡，候館若爲容。", "山轉時藏月，河分不割風。", "憑誰能警夢，總自解書空。", "省內吾難倚，詩書更使慵。"]'),
('69735c4e-cfbe-47b1-9617-95e239c6883f','九日','晁說之','宋','宋诗','song-poetry','','[]','日日無堪只嘆嗟，誰教九日事豪華。',64,'全唐诗/poet.song.68000.json','["日日無堪只嘆嗟，誰教九日事豪華。", "寂寥難落方山帽，爛熳先開野菊花。", "聞道鵷鸞趨鎬燕，忍將鴻雁聽邊笳。", "古來感慨今朝甚，苦雨凄風助我賒。"]'),
('544ed475-adae-4db6-b96a-8488aadcc0bc','贈鄜州田玘','晁說之','宋','宋诗','song-poetry','','[]','前世能歌田順郎，今身追悔太昌昌。',32,'全唐诗/poet.song.68000.json','["前世能歌田順郎，今身追悔太昌昌。", "戲泥巧盡羣兒態，休憶小姑初倚床。"]'),
('780d8cab-f869-4f8f-8bc2-23e64250b87a','次韻任伯途中見寄  其一','晁說之','宋','宋诗','song-poetry','','[]','命駕關東千里餘，拂衣前去未勤渠。',64,'全唐诗/poet.song.68000.json','["命駕關東千里餘，拂衣前去未勤渠。", "自憐病客料秦虎，共學騷人憶郢閭。", "賦就句奇輕惡道，詩成意遠欲閒居。", "此生辛苦君能識，不向他人道看書。"]'),
('c7684365-3a17-499d-b9f2-6da64526caee','次韻任伯途中見寄  其二','晁說之','宋','宋诗','song-poetry','','[]','白頭青簡負三餘，得喪窮通不問渠。',64,'全唐诗/poet.song.68000.json','["白頭青簡負三餘，得喪窮通不問渠。", "但恐風霜侵爾稼，敢期盗賊避吾閭。", "秋蟬冬蝶空離恨，渭水秦山政索居。", "何日離合南北史，倩君成就一家書。"]'),
('1da58a13-90e2-4c10-9444-d71000bd9f0e','感事詩寄韓侍郎','晁說之','宋','宋诗','song-poetry','','[]','去年過却京塵裏，今日無煩嘆白頭。',64,'全唐诗/poet.song.68000.json','["去年過却京塵裏，今日無煩嘆白頭。", "且喜歸來收客夢，何妨無酒破春愁。", "閒鳴庭樹鳥聲樂，遠使疏泉山影浮。", "晚得花開逢歲閏，可容結侣到丹丘。"]'),
('bf936dea-030c-4582-ab10-996effd1d0aa','贈韓侍郎','晁說之','宋','宋诗','song-poetry','','[]','僕射陂頭鷺宿秋，使君行色曉雲浮。',96,'全唐诗/poet.song.68000.json','["僕射陂頭鷺宿秋，使君行色曉雲浮。", "幾章乞得閒歸去，平日將何事絆留。", "久幸沃心舒讜議，暫堪俯首貶忠謀。", "黄金帯念多人有，烏角巾憐獨自休。", "談笑弟兄從此樂，杯盤賓客莫言愁。", "慚予本是山中士，可復魂勞隴上舟。"]'),
('c6118cfc-39aa-4d74-99be-33a8d528b797','偶題','晁說之','宋','宋诗','song-poetry','','[]','一室蕭然懶傍書，角巾孤嘯問何如。',64,'全唐诗/poet.song.68000.json','["一室蕭然懶傍書，角巾孤嘯問何如。", "夕陽能使山遠近，秋色巧隨人慘舒。", "苔漬碧花行不到，香殘篆字睡應餘。", "自憐得計歸雲晚，前日人間漫畏途。"]'),
('23160b4c-7257-40ce-a424-b39a176d3265','和季弟秋日即事','晁說之','宋','宋诗','song-poetry','','[]','五世衣冠盛本朝，寧論妻織與兒樵。',32,'全唐诗/poet.song.68000.json','["五世衣冠盛本朝，寧論妻織與兒樵。", "顧予始就山居樂，未放詩書便泬寥。"]'),
('d1ae093c-5041-49e5-b722-90445cf4081f','寄謝任伯察院','晁說之','宋','宋诗','song-poetry','','[]','終日小園何所爲，忘言不讀國風詩。',64,'全唐诗/poet.song.68000.json','["終日小園何所爲，忘言不讀國風詩。", "閒來却覺呻吟好，老去仍知疾病宜。", "月在鄜州能到此，人遊梁苑誤行期。", "徒憐宋玉無秋思，既識清高又可悲。"]'),
('e90d2f17-9caa-4d91-9ea2-37684a63259a','初至京作','晁說之','宋','宋诗','song-poetry','','[]','七年去園今還歸，僅有身存心事微。',64,'全唐诗/poet.song.68000.json','["七年去園今還歸，僅有身存心事微。", "下客但能存故事，高門誰許著褒衣。", "難將白髪語年少，忍使紅塵負釣磯。", "不解征驂却歸去，策雖非是亦非非。"]'),
('9d1a5f71-b958-4304-b681-c68c103a7900','以扇求馮元禮覲畫山水','晁說之','宋','宋诗','song-poetry','','[]','高人能畫山中趣，凉吹曉從天際來。',32,'全唐诗/poet.song.68000.json','["高人能畫山中趣，凉吹曉從天際來。", "移畫此情紈扇上，人間何處有塵埃。"]'),
('69b2185b-e68b-4b6a-a5d3-c385d14c0b78','趣景升太尉畫孫登像','晁說之','宋','宋诗','song-poetry','','[]','契闊王孫魂夢勞，京華一日重遊遨。',64,'全唐诗/poet.song.68000.json','["契闊王孫魂夢勞，京華一日重遊遨。", "圖書不惜黄金費，歌舞何妨籙佩高。", "月到南樓卧吹笛，花殘曲几醉揮毫。", "如何愛著須臾懶，不使蘇門對楚騷。"]'),
('6f6cbf46-4561-4cfc-a75d-68af88269149','留題景升北窗','晁說之','宋','宋诗','song-poetry','','[]','南樓吹笛何人怨，北窗垂楊永日閒。',32,'全唐诗/poet.song.68000.json','["南樓吹笛何人怨，北窗垂楊永日閒。", "何用綠楊高百尺，詩情筆趣總相關。"]'),
('6392bf37-b190-45dc-a291-05b260b85435','夏祭日感事','晁說之','宋','宋诗','song-poetry','','[]','盛典千年出寶圖，佩環方澤影縈紆。',64,'全唐诗/poet.song.68000.json','["盛典千年出寶圖，佩環方澤影縈紆。", "中天月護黄琮色，出海雲騰赤帝符。", "已慣龜鼉呈上瑞，不驚風雨解前驅。", "侍臣自有揚雄賦，擊壤何妨此鄙夫。"]'),
('67876413-85d6-447d-b46c-1d1c8cff9ebc','謝曾廸功松皮冠','晁說之','宋','宋诗','song-poetry','','[]','松皮冠贈松山客，慚愧紅塵赤日中。',32,'全唐诗/poet.song.68000.json','["松皮冠贈松山客，慚愧紅塵赤日中。", "好向浮雲傍歸路，定應賸聽入琴風。"]'),
('f5e06432-e334-4906-b6d0-13a9b44bb243','次韻和張次應龍圖松皮冠子','晁說之','宋','宋诗','song-poetry','','[]','儒冠何事貴松皮，一歲寒來特自奇。',32,'全唐诗/poet.song.68000.json','["儒冠何事貴松皮，一歲寒來特自奇。", "髪盡著霜相稱得，歌酬白雪即非宜。"]'),
('cf6861b8-d494-4ea9-a346-f09555cf98ca','代馮元禮次韻辭張次應畫山水扇','晁說之','宋','宋诗','song-poetry','','[]','女鸞寶扇漫稱工，誰識嵐漪縹香蹤。',32,'全唐诗/poet.song.68000.json','["女鸞寶扇漫稱工，誰識嵐漪縹香蹤。", "何事晚來慵落筆，爲嗔不說妙高峰。"]'),
('1bc66b71-e3df-4bac-9ed4-ec08f7115bb8','代馮元禮次韻送畫山水扇與張次應','晁說之','宋','宋诗','song-poetry','','[]','五日十日豈爲工，萬壑千巖自絕蹤。',32,'全唐诗/poet.song.68000.json','["五日十日豈爲工，萬壑千巖自絕蹤。", "在握已能霄漢上，更須羣玉占前峰。"]'),
('2cdb386e-cb52-4466-aad8-25dae4ddae65','次韻和大理吳子偉寺丞久留滯絕句','晁說之','宋','宋诗','song-poetry','','[]','之子婆娑幾許年，衆人遷後獨稀遷。',32,'全唐诗/poet.song.68000.json','["之子婆娑幾許年，衆人遷後獨稀遷。", "即今便上青雲上，巳愧開爐白日仙。"]'),
('e74c38a7-7e87-498b-8bf0-ad79878fdda4','再和','晁說之','宋','宋诗','song-poetry','','[]','官共狐裘三十年，紛紛南北笑鶯遷。',32,'全唐诗/poet.song.68000.json','["官共狐裘三十年，紛紛南北笑鶯遷。", "未施雲外射鵰手，且作山中騎虎仙。"]'),
('99475a7d-f318-425d-a346-bc0f6c2a91ad','京居五更聞鐘','晁說之','宋','宋诗','song-poetry','','[]','慣聽山頭五夜鐘，忽驚孤枕景陽風。',32,'全唐诗/poet.song.68000.json','["慣聽山頭五夜鐘，忽驚孤枕景陽風。", "明朝樂事知何限，定自無人拜德公。"]'),
('0dd8f81a-eeb8-409e-9b97-9d5254d5c485','七月五日立秋','晁說之','宋','宋诗','song-poetry','','[]','故廬歸客不勝愁，可是人間晚立秋。',32,'全唐诗/poet.song.68000.json','["故廬歸客不勝愁，可是人間晚立秋。", "收潦水清如可待，無窮蛭螾看沈浮。"]'),
('6d119e7b-d945-47c9-be3e-763e1f34b282','病卧聞韓公表雨中出謁','晁說之','宋','宋诗','song-poetry','','[]','綠陰飛雨作秋容，衰病呻吟高枕中。',32,'全唐诗/poet.song.68000.json','["綠陰飛雨作秋容，衰病呻吟高枕中。", "何事公孫健騎馬，黄金帯客好相從。"]'),
('fd0b5a7d-a4c5-413d-8439-09bac57e5358','韓二十七詩來云已束歸鞍逐去鴻令人欣喜愧嘆輒次韻和','晁說之','宋','宋诗','song-poetry','','[]','此身重滯愧征鴻，况對庭前郢樹風。',32,'全唐诗/poet.song.68000.json','["此身重滯愧征鴻，况對庭前郢樹風。", "暫至京師便歸去，敢期今日有黄公。"]'),
('4eb9cc42-b8ee-491d-ac85-d403de8dfd24','即事謝公表二絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','碧嵩青潁肯相從，萬事茅堂醉夢中。',32,'全唐诗/poet.song.68000.json','["碧嵩青潁肯相從，萬事茅堂醉夢中。", "出到人前羞欲死，歸輪不必問何從。"]'),
('d30424e6-1b5d-43ca-b512-4e16f25c7dab','即事謝公表二絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','留君談笑且從容，白髮紅塵阿那中。',32,'全唐诗/poet.song.68000.json','["留君談笑且從容，白髮紅塵阿那中。", "踉蹌行藏莫相笑，枯魚垂淚恨無從。"]'),
('c549d04c-b23e-4ce9-81f7-af1532f3266e','即事謝子之二絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','何妨少日不能容，詎玷山公啟事中。',32,'全唐诗/poet.song.68000.json','["何妨少日不能容，詎玷山公啟事中。", "庭下秋風收不得，欲彫瓊樹未聽從。"]'),
('c72b507e-9654-4b1b-be9a-85737b3c0109','即事謝子之二絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','悅己曾增巧笑容，舞鸞歸歇鑑花中。',32,'全唐诗/poet.song.68000.json','["悅己曾增巧笑容，舞鸞歸歇鑑花中。", "人間遇樂便作樂，何用行軍問所從。"]'),
('d32fa0da-36cc-4670-bab9-ba2eb373fd7f','送韓七十赴澶淵舊任所爲士掾','晁說之','宋','宋诗','song-poetry','','[]','不樂予何甚，非關未策勳。',48,'全唐诗/poet.song.68000.json','["不樂予何甚，非關未策勳。", "秋燈逢積雨，客淚送離羣。", "身事千年鶴，心期萬里雲。", "煩君經廢廟，嗚咽當家文。"]'),
('ef2a1dd0-1463-45ee-86c1-2a1faade226f','選部中作','晁說之','宋','宋诗','song-poetry','','[]','白髪來遊宦，山公不我聞。',48,'全唐诗/poet.song.68000.json','["白髪來遊宦，山公不我聞。", "邪猶在中等，政不占微分。", "孤淚滄溟感，微言上帝勳。", "何妨貧且賤，嵩嶺有高雲。"]'),
('dca0b330-f762-4872-9876-57f9b592fbb0','明仲約七月晦集屬抱病先以此見意猶并以申謝','晁說之','宋','宋诗','song-poetry','','[]','秋日在長安，多悲對極歡。',48,'全唐诗/poet.song.68000.json','["秋日在長安，多悲對極歡。", "栗疏肥木落，芡觜瘠池寒。", "居室清樽健，羈人白石殫。", "慚君過繾綣，扶病强盤桓。"]'),
('0bc17c5f-fe42-4ee2-afd8-c3c19840b0f0','送邢子强還洛','晁說之','宋','宋诗','song-poetry','','[]','行樂洛城爲第一，暫勞使節持還家。',64,'全唐诗/poet.song.68000.json','["行樂洛城爲第一，暫勞使節持還家。", "橋頭鋪遍中秋月，樓上吹殘九日花。", "誰聽高談擒虎豹，且容濁酒傲烟霞。", "從君一笑知無分，短髪長途倍嘆嗟。"]'),
('0d362a0a-63bb-4dd3-8ca8-e19bbab2ac2c','送李先之歸南','晁說之','宋','宋诗','song-poetry','','[]','夫子聲名大，凄凉三十年。',48,'全唐诗/poet.song.68000.json','["夫子聲名大，凄凉三十年。", "晚交彌好易，夙志自覃玄。", "泰華冰霜潔，江湖鴻雁邉。", "别期不相假，吾道信茫然。"]'),
('d1bc1c75-8edb-49d5-816f-fad1da5062b5','再送先之','晁說之','宋','宋诗','song-poetry','','[]','君家父子真國器，棄逐那知上苑春。',64,'全唐诗/poet.song.68000.json','["君家父子真國器，棄逐那知上苑春。", "嵐障城中尤自樂，浦珍市裏本來貧。", "曾憐濁俗排閶闔，慚屈清江縱羽鱗。", "我老相逢便相别，劇談易象亦何因。"]'),
('6defb874-d314-46d6-abd2-d66d3513767a','三送先之','晁說之','宋','宋诗','song-poetry','','[]','相逢無酒恨如酣，九市三玄俱不談。',32,'全唐诗/poet.song.68000.json','["相逢無酒恨如酣，九市三玄俱不談。", "秋雨迢迢催客别，别情雨色已江南。"]'),
('1601ca3c-4751-433b-9592-5609960054e0','京居秋感五絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','快雨薄寒一夕間，胡爲百役自間關。',32,'全唐诗/poet.song.68000.json','["快雨薄寒一夕間，胡爲百役自間關。", "秋懷更讀甘陵賦，始信人人庾子山。"]'),
('46491da7-406a-4bc3-b6d0-e17b3e2be14c','京居秋感五絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','雨助風聲燕欲歸，誰教我尚著征衣。',32,'全唐诗/poet.song.68000.json','["雨助風聲燕欲歸，誰教我尚著征衣。", "自憐未讀愍征賦，霜雪鬢間猶庶幾。"]'),
('806d9f5f-7055-4c1c-8eff-de4b93472754','京居秋感五絕句  其三','晁說之','宋','宋诗','song-poetry','','[]','隨蝶求官秋緒多，自甘老罷樂婆娑。',32,'全唐诗/poet.song.68000.json','["隨蝶求官秋緒多，自甘老罷樂婆娑。", "枕邉風雨五更夢，聲在長衢朝馬過。"]'),
('44f4d0bf-8a0b-4072-843b-cf9b10fa6a7f','京居秋感五絕句  其四','晁說之','宋','宋诗','song-poetry','','[]','江上高人未肯來，京華秋鬢獨徘徊。',32,'全唐诗/poet.song.68000.json','["江上高人未肯來，京華秋鬢獨徘徊。", "饒渠看取潮頭月，莫戀林香待放梅。"]'),
('cda106b4-df50-4891-8890-4f2b6bb6d890','京居秋感五絕句  其五','晁說之','宋','宋诗','song-poetry','','[]','河滣依棹得風期，秦樹湘雲枉夢思。',32,'全唐诗/poet.song.68000.json','["河滣依棹得風期，秦樹湘雲枉夢思。", "也好歸來君富貴，未容言語我悲傷。"]'),
('fa269ecd-e166-464b-b31e-e445cfbe18b1','即事','晁說之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','幾歲田園得隱淪，忍將秋淚濕紅塵。',32,'全唐诗/poet.song.68000.json','["幾歲田園得隱淪，忍將秋淚濕紅塵。", "一麾不得廬山去，何用他州寄此身。"]'),
('50ff39fa-cd5f-4649-99eb-953d97172e72','歸到','晁說之','宋','宋诗','song-poetry','','[]','歸到故廬同逆旅，人生本自怕牢愁。',64,'全唐诗/poet.song.68000.json','["歸到故廬同逆旅，人生本自怕牢愁。", "雨聲豈有京華態，羈思仍多澧浦秋。", "久禁令人類疾病，新聞向汝重咿喔。", "顧無道義論輕重，何處王公門可遊。"]'),
('35ccb8fc-fa66-4cd7-b635-47d520831742','乞酒','晁說之','宋','宋诗','song-poetry','','[]','積雨深秋與恨翻，悠悠何力勝朝昏。',64,'全唐诗/poet.song.68000.json','["積雨深秋與恨翻，悠悠何力勝朝昏。", "久同下里饒詩句，乍學高人傍酒樽。", "徑醉便知能傲世，狂吟更覺解招魂。", "頗憐陶令徒全美，只肯丁寧乞食言。"]'),
('43f4bc07-2619-443a-b42e-1316d7c444f0','辟穀','晁說之','宋','宋诗','song-poetry','','[]','辟穀終無術，求田早自慵。',48,'全唐诗/poet.song.68000.json','["辟穀終無術，求田早自慵。", "病能添旅思，雨善起秋容。", "本色官猶阻，非時好孰從。", "封侯如可覓，要自愧長公。"]'),
('27d8c2b1-7fcb-4b0f-b789-3756f1508896','依韻和卲太子文兄八月總章朝歸長句','晁說之','宋','宋诗','song-poetry','','[]','東皇受籙增嘉運，曉坐明堂夜拜章。',64,'全唐诗/poet.song.68000.json','["東皇受籙增嘉運，曉坐明堂夜拜章。", "玉燭千年承瑞露，金龍萬國鎮青霜。", "風來紫極簫聲静，人在丹臺珮影凉。", "與子飄零逢盛旦，獨無藻思頌瑤光。"]'),
('f58a662f-3976-4533-81bd-674fcbfc824e','八月十五戲作','晁說之','宋','宋诗','song-poetry','','[]','稱意中秋月滿樓，只嫌歌扇遏雲浮。',32,'全唐诗/poet.song.68000.json','["稱意中秋月滿樓，只嫌歌扇遏雲浮。", "不如風雨連天起，要得伊人也解愁。"]'),
('10043d82-456c-43fe-bc9a-c1f6e5fe6078','聞三十六丈乞西京留臺輒成長句時先之七兄已拜北京留臺','晁說之','宋','宋诗','song-poetry','','[]','門地何人論甲乙，碧梧丹鳯重徘徊。',64,'全唐诗/poet.song.68000.json','["門地何人論甲乙，碧梧丹鳯重徘徊。", "前時五相繼三相，此日西臺望北臺。", "器業雲霄能我有，功名鍾鼎待時來。", "重言四海宮師德，季子白頭誰識哉。"]'),
('11ae4d82-6165-4df3-90bb-7659318dc6ad','伏蒙三十六丈大夫寵視長句輒次韻和','晁說之','宋','宋诗','song-poetry','','[]','千仞愁城託寸陰，可堪疾病更頻侵。',64,'全唐诗/poet.song.68000.json','["千仞愁城託寸陰，可堪疾病更頻侵。", "烟霞舊友能相遇，鷗鷺前盟不待尋。", "羮飯東西慚白髮，功勳遠邇負丹心。", "明朝重九登高處，約訪高人支道林。"]'),
('fed40aa5-5023-4a1e-a13a-df97bc26c4f4','德麟留詩相别輒次韻賀送','晁說之','宋','宋诗','song-poetry','','[]','安穩王孫一葉舟，朅來京國淡無求。',64,'全唐诗/poet.song.68000.json','["安穩王孫一葉舟，朅來京國淡無求。", "任生白髪曾料虎，分絕紅塵自狎鷗。", "桓笛不堪留往恨，膺門誰復憶同遊。", "重陽無酒仍分袂，雨作黄花淚未休。"]'),
('7fb09b70-d43d-49a6-bae4-f2e0130b35d1','德麟夜相過用前韻作','晁說之','宋','宋诗','song-poetry','','[]','王孫未放木蘭舟，憶别親知與訪求。',64,'全唐诗/poet.song.68000.json','["王孫未放木蘭舟，憶别親知與訪求。", "軟語斗牛迷後雁，傷心波浪没浮鷗。", "燈前有喜新佳句，泉下無慚舊俊遊。", "潁尾可居鄰可卜，白蘋紅蓼共君休。"]'),
('e0a22715-0b36-47e7-be5b-2a2451f0b147','九日宴李德充中大家次韓三十六丈韻作','晁說之','宋','宋诗','song-poetry','','[]','重陽風雨每凄凄，物色今年得所期。',64,'全唐诗/poet.song.68000.json','["重陽風雨每凄凄，物色今年得所期。", "賜第好賢多驥子，三山酌酒過鵝兒。", "紅樓尚想吹簫夕，碧樹今誇出日枝。", "我與韓公殊輩行，門闌感舊淚俱垂。"]'),
('1ca185cb-9dfc-4ea5-b8ae-60484f0da3b3','九日陪韓三十六丈大夫集李德充家再蒙賦詩相似謹次韻攀和','晁說之','宋','宋诗','song-poetry','','[]','丈人邂逅共悲凄，九日芳樽敢有期。',64,'全唐诗/poet.song.68000.json','["丈人邂逅共悲凄，九日芳樽敢有期。", "感慨既能追壯士，懽欣復自學羣兒。", "菊憎紫蘂侵黄蘂，萸憤南枝勝北枝。", "蕭史高樓幸登眺，但慚清唱手空垂。"]'),
('044d4006-62d2-4aa1-a70f-2bad3f70464b','李德充再賦九日期字韻詩輒亦復作','晁說之','宋','宋诗','song-poetry','','[]','多才公子莫凄凄，九日不嘲風雨期。',64,'全唐诗/poet.song.68000.json','["多才公子莫凄凄，九日不嘲風雨期。", "清酒玉腴浮盞底，黄花金蘂粲鈴兒。", "百年歌吹驂鸞地，萬里旌幢鳴鳯枝。", "前後楊劉是賓客，聲名孰敢與争垂。"]'),
('25c4a239-1905-4034-aae7-27a9071c2265','重蒙三十六丈大夫德充中大賦九日詩期字韻詩輒復以致謝遂及閣筆之域','晁說之','宋','宋诗','song-poetry','','[]','平陽樓上重陽日，周覧悲歡孰與期。',64,'全唐诗/poet.song.68000.json','["平陽樓上重陽日，周覧悲歡孰與期。", "盛德不應無隱者，大豪寧復有屠兒。", "未舒鸑鷟青天翼，難識珊瑚碧海枝。", "莫擬吹花多繼筆，羸兵易衂槖仍垂。"]'),
('a220ed95-dfa1-4d8b-b75a-fe076577f5a4','即事呈德麟','晁說之','宋','宋诗','song-poetry','','[]','學得浮雲往復還，里中不出孰追攀。',64,'全唐诗/poet.song.68000.json','["學得浮雲往復還，里中不出孰追攀。", "九秋自與物情樂，一日須教我輩閒。", "敢料都城有詩句，故應魂夢在山間。", "今朝車上瓶無分，更可憐哉我阻艱。"]'),
('51dec710-b4d3-46f2-a5da-d1002bc50256','次韻和德麟過希道作','晁說之','宋','宋诗','song-poetry','','[]','笠澤人閒書已叢，分甘寂寞與誰同。',64,'全唐诗/poet.song.68000.json','["笠澤人閒書已叢，分甘寂寞與誰同。", "故人相遇白頭日，往事獨悲黄葉風。", "去國貴遊驚灞岸，浮家公子樂湘中。", "此情繾綣思朝夕，百仞寒巖飲水虹。"]'),
('2baba834-c76a-4095-9924-730ee8e31def','思歸','晁說之','宋','宋诗','song-poetry','','[]','忽有故園夢，秋冬恨不勝。',48,'全唐诗/poet.song.68000.json','["忽有故園夢，秋冬恨不勝。", "菊難月掩映，梅耐雪馮陵。", "客鬭南唐墨，僧禪後夜燈。", "如何不歸去，京國腳騰騰。"]'),
('c4dad6f2-8ea3-4a03-9913-58c858b06d7c','感事','晁說之','宋','宋诗','song-poetry','','[]','人物今朝何寂寞，我思前輩太峥嶸。',64,'全唐诗/poet.song.68000.json','["人物今朝何寂寞，我思前輩太峥嶸。", "仙才難測趙周翰，俗眼聊窺石曼卿。", "鸞鳯騰輝何處在，珪璋振德是人斯。", "怪來高論空無騐，可是岐公作宰衡。"]'),
('fcd82dd5-b313-4d4b-8f7a-b88e658dfc98','早於城北逢御馬','晁說之','宋','宋诗','song-poetry','','[]','天街未見瞳矓日，御馬來朝馺騀宮。',32,'全唐诗/poet.song.68000.json','["天街未見瞳矓日，御馬來朝馺騀宮。", "不許暫時超倒暴，欲將何事騐真龍。"]'),
('6a96be53-5fed-4e57-ba1d-41c5b55ddad7','十月七日夜夢中作兩長句覺而忘之别成長句視李師民','晁說之','宋','宋诗','song-poetry','','[]','冬來羈旅更迢迢，撫枕燈殘百感饒。',64,'全唐诗/poet.song.68000.json','["冬來羈旅更迢迢，撫枕燈殘百感饒。", "饑鼠翻空疑有鬼，驚烏誤曉尚中宵。", "詩成與夢俱零落，劍出低眉亦寂寥。", "無分京華居老境，江湖高隱幸相招。"]'),
('8e122b2d-9bb6-4c81-a4f4-6a302d19931a','慚愧','晁說之','宋','宋诗','song-poetry','','[]','神邑凡才日抗塵，早年聞道晚因循。',64,'全唐诗/poet.song.68000.json','["神邑凡才日抗塵，早年聞道晚因循。", "腦能充溢無華髪，心得休閒不老身。", "種種已慚爲客子，悠悠更愧作官人。", "吾言可復終歸去，何處桃源可問津。"]'),
('f7d0455e-c522-4e27-8a07-ec164da80ae9','偶見夏英公與文莊公書云秋序始凉師門尚遠又一書云念其出自師門賜一善地輒成絕句','晁說之','宋','宋诗','song-poetry','','[]','前輩終身知學植，今人得意諱師門。',32,'全唐诗/poet.song.68000.json','["前輩終身知學植，今人得意諱師門。", "如新幾帖英公字，可但吾家禮數尊。"]'),
('59691622-0359-40f4-bde9-31b678c3a274','天寧節後二日集英殿賜燕輒成長句','晁說之','宋','宋诗','song-poetry','','[]','誕彌陽月播陽春，萬壽杯餘燕豆申。',64,'全唐诗/poet.song.68000.json','["誕彌陽月播陽春，萬壽杯餘燕豆申。", "殿角垂虹天意喜，壁緹交鳯日華新。", "星迴畢雨金沙浄，書發狄封玉甑陳。", "何事昇平樓寂寞，要將銀嶽共璘珣。"]'),
('a1827601-480b-4c3d-bce4-73fcdd4c9051','寄李輔之  其一','晁說之','宋','宋诗','song-poetry','','[]','嫁樹裁花待上元，一燈明熖照山樊。',32,'全唐诗/poet.song.68000.json','["嫁樹裁花待上元，一燈明熖照山樊。", "香爐下烟霞客，此夜皇州亦掩門。"]'),
('0dca1f03-0a34-4c21-b7ff-de459357b836','寄李輔之  其二','晁說之','宋','宋诗','song-poetry','','[]','布裘菜飯久忘言，糲食粗衣過上元。',32,'全唐诗/poet.song.68000.json','["布裘菜飯久忘言，糲食粗衣過上元。", "怪底狂風迷四野，榮光自滿濯龍門。"]'),
('68c6daf3-18e6-428a-a0a2-c55643c346ff','庚子至前二日韓德全李師民相繼而至聊書一時之事','晁說之','宋','宋诗','song-poetry','','[]','先後客無約，寒窗注夕陽。',48,'全唐诗/poet.song.68000.json','["先後客無約，寒窗注夕陽。", "縱談香柏子，孤興飲松黄。", "不道仇池遠，唯迎至日長。", "於焉豈易得，回首即他鄉。"]'),
('48f38bfc-4562-4e2d-a464-883b217e7012','對雪','晁說之','宋','宋诗','song-poetry','','[]','念昔幽居久，幽懷劇歲殘。',48,'全唐诗/poet.song.68000.json','["念昔幽居久，幽懷劇歲殘。", "茅亭因雪過，沙渚與鷗寒。", "暫喜凉塵息，將愁秦樹單。", "六花如結子，孤客鬢邉看。"]'),
('f2147bfb-3a87-4d8a-9dad-85a1a46fb876','次韻江子我見戲長句','晁說之','宋','宋诗','song-poetry','','[]','江家宅在多文史，兄弟論文詎我遺。',64,'全唐诗/poet.song.68000.json','["江家宅在多文史，兄弟論文詎我遺。", "長逝不來荒馬鬛，後生亦老倦車帷。", "契成自賣寧無恨，詩到相嘲雅見知。", "山水尚憐天付與，暮年漂薄向仇池。"]'),
('89e3a36d-6795-43b7-8de1-2723a8883f6a','對雪懷淮安郡王郊居','晁說之','宋','宋诗','song-poetry','','[]','六出花開郊野興，王居不數沈休文。',64,'全唐诗/poet.song.68000.json','["六出花開郊野興，王居不數沈休文。", "洞房窈窕玉簫遠，綺席徘徊瓊糈醺。", "大藥定應須火候，佳人可復悮行雲。", "自憐收拾征衣客，白眼寒空送雁羣。"]'),
('82d12cad-ac79-46e1-8508-b9a714249f47','别親舊','晁說之','宋','宋诗','song-poetry','','[]','歲暮征裘返故園，愀然去國亦難論。',64,'全唐诗/poet.song.68000.json','["歲暮征裘返故園，愀然去國亦難論。", "獨尋碧草日三徑，誰在紅蓮夜五門。", "久分雲霄能割席，乍驚繿縷有離尊。", "即看短髪邉城去，風雨仇池役夢魂。"]'),
('b9d6b88f-5674-4dfb-8831-06f2366b3ee2','出京感事','晁說之','宋','宋诗','song-poetry','','[]','晚歲長途俱寂寞，傷今懷古總飄零。',64,'全唐诗/poet.song.68000.json','["晚歲長途俱寂寞，傷今懷古總飄零。", "韓彭豈是無三窟，管葛元非守一經。", "白髪任渠從此出，朱絃於世許誰聽。", "猶憐去國恨能釋，已見燈龍出北溟。"]'),
('17c5278b-3f9b-489f-b3ff-b2e3a38d4bec','出見京華之盛而作','晁說之','宋','宋诗','song-poetry','','[]','飄零羈客尚驚魂，乍見王居白玉城。',64,'全唐诗/poet.song.68000.json','["飄零羈客尚驚魂，乍見王居白玉城。", "三市盡迷南北嚮，八騶争禁短長行。", "花移陸海春常在，樓接神山月不傾。", "安得白頭居此樂，關河垂淚復孤征。"]'),
('e357dff9-7f47-460d-85ec-1c033a8a549b','過洛陽贈親舊','晁說之','宋','宋诗','song-poetry','','[]','古來無奈洛陽塵，興屬今朝誰與親。',64,'全唐诗/poet.song.68000.json','["古來無奈洛陽塵，興屬今朝誰與親。", "河岳新秋初過雁，園林曉月遠行人。", "波聲有喜咸通汴，雲影相隨直到秦。", "白笋紫薑勤故舊，公孫出仕獨堪嗔。"]'),
('101ce2b5-4416-4d5a-8fe9-c214d1b150d6','過陜州贈蘇儀掾仲滋  其一','晁說之','宋','宋诗','song-poetry','','[]','老去情懷誰與謀，壞壁無蛩更益愁。',64,'全唐诗/poet.song.68000.json','["老去情懷誰與謀，壞壁無蛩更益愁。", "收覧雨聲來枕上，飛揚馬鬛在岡頭。", "欒城孫子何來此，華國文章肯漫休。", "邂逅關山論家世，更期信息在西州。"]'),
('b8748742-1858-45e0-9905-bbad7f134914','過陜州贈蘇儀掾仲滋  其二','晁說之','宋','宋诗','song-poetry','','[]','河擁秋聲客恨新，誰能出語共輪囷。',32,'全唐诗/poet.song.68000.json','["河擁秋聲客恨新，誰能出語共輪囷。", "信知五采生丹穴，不許文章屬外人。"]'),
('3eb45b29-8cb3-452a-9a8a-b5433ed492d9','題長安趙氏園','晁說之','宋','宋诗','song-poetry','','[]','長安池館欝峥嶸，此地偏多客子情。',64,'全唐诗/poet.song.68000.json','["長安池館欝峥嶸，此地偏多客子情。", "秋晚寒藤侵石痩，夜深熟果落池驚。", "後生解識南山趣，先德元高戎夏聲。", "感時暫來添白髪，南山曾見漢公卿。"]'),
('9f31b2d2-f606-4fe6-922b-4d60ca336a55','鹿鳴席上送諸先輩詩','晁說之','宋','宋诗','song-poetry','','[]','周室賓興綺席陳，漢家勸駕禮還申。',64,'全唐诗/poet.song.68000.json','["周室賓興綺席陳，漢家勸駕禮還申。", "鸚遷同谷烟霞喜，鯉化瓊林雨露新。", "日御駸駸須六轡，奎文燁燁自三秦。", "先應沉醉換春色，病守狂吟已覺春。"]'),
('50456366-2a7c-4cd8-8b61-434592a3d503','即事戲作五言  其一','晁說之','宋','宋诗','song-poetry','','[]','何處寂寥好，山城太守家。',48,'全唐诗/poet.song.68000.json','["何處寂寥好，山城太守家。", "輕觜木竹筍，大裹白朱砂。", "君與旱蓮比，實非火候賒。", "一官還此是，百務莫淫哇。"]'),
('79048e27-6a8d-4b86-b84e-6d8e7cdaad84','即事戲作五言  其二','晁說之','宋','宋诗','song-poetry','','[]','何處寂寥好，山城太守官。',48,'全唐诗/poet.song.68000.json','["何處寂寥好，山城太守官。", "龍鍾五品服，豹變一還丹。", "舊恐三杯竭，新添兩角寒。", "只應歸去是，無責有餘驩。"]'),
('dbf75fd6-81f5-4467-adb2-c3c7bd3bdd5b','謹次知府經略待制韻','晁說之','宋','宋诗','song-poetry','','[]','制勝奇兵不下堂，鉛刀何敢齒干將。',64,'全唐诗/poet.song.68000.json','["制勝奇兵不下堂，鉛刀何敢齒干將。", "肯誇舞暖嬌回雪，只念琴寒乞履霜。", "此日秦郊黄髪老，當年漢殿綠衣郎。", "徘徊四十年來事，險阻艱難間偹嘗。"]'),
('7f87fd67-bbd3-4866-94e8-d6d8ce5f14e0','郡齋戲句  其一','晁說之','宋','宋诗','song-poetry','','[]','烏髭四皓應無術，沉醉三閭豈有方。',32,'全唐诗/poet.song.68000.json','["烏髭四皓應無術，沉醉三閭豈有方。", "將此衰殘齋戒裏，郡人應笑使君狂。"]'),
('c1edd550-ffe5-487c-9062-01c1d6dca842','郡齋戲句  其二','晁說之','宋','宋诗','song-poetry','','[]','一夫肆力能排闥，萬旅無謀漫仰關。',32,'全唐诗/poet.song.68000.json','["一夫肆力能排闥，萬旅無謀漫仰關。", "成敗是非今有底，忍將鞭扑作威顔。"]'),
('364ded2b-b494-48e8-b348-40014da7c5aa','郡齋戲句  其三','晁說之','宋','宋诗','song-poetry','','[]','雪中獵戶來呈虎，月下田夫走献麛。',32,'全唐诗/poet.song.68000.json','["雪中獵戶來呈虎，月下田夫走献麛。", "諱道山成應不得，關東誰肯有書題。"]'),
('c1fddd3c-b17a-4bee-97ee-5004371961c9','郡齋戲句  其四','晁說之','宋','宋诗','song-poetry','','[]','斗升白米能供酒，暝目紅裠難聽歌。',32,'全唐诗/poet.song.68000.json','["斗升白米能供酒，暝目紅裠難聽歌。", "爲謝黄州王內翰，莫言官職也蹉跎。"]'),
('40afec93-e6ac-46f8-bbb3-35a8f38697f2','郡齋戲句  其五','晁說之','宋','宋诗','song-poetry','','[]','蕭條吏散如堪適，蕭灑詩成亦可娱。',32,'全唐诗/poet.song.68000.json','["蕭條吏散如堪適，蕭灑詩成亦可娱。", "王謝異時同惠我，只慚筆力不能俱。"]'),
('4bcaa156-688c-492f-ac72-bcee20fdebc5','郡齋戲句  其六','晁說之','宋','宋诗','song-poetry','','[]','雜號將軍人所薄，東宮贊善自曾嘲。',32,'全唐诗/poet.song.68000.json','["雜號將軍人所薄，東宮贊善自曾嘲。", "如何今日余爲守，黄獨白𢇲誇大庖。"]'),
('14e2b9d1-abbf-4c8d-9b7a-7cf024b1ed22','郡齋戲句  其七','晁說之','宋','宋诗','song-poetry','','[]','朝困十催何敢飽，暮虞百罰更生寒。',32,'全唐诗/poet.song.68000.json','["朝困十催何敢飽，暮虞百罰更生寒。", "雞山小石鳯山柳，移植庭前少自寛。"]'),
('22456a96-265d-42fd-8d86-9f1a68267bc3','笑','晁說之','宋','宋诗','song-poetry','','[]','笑樂真情豈可無，樂而不笑是何拘。',64,'全唐诗/poet.song.68000.json','["笑樂真情豈可無，樂而不笑是何拘。", "日中無事逢棋局，春後有花兼酒壺。", "輕俠兒前撫手掌，滑稽傳後撫髭鬚。", "江南陸后還安否，乞與笻枝使自扶。"]'),
('7d85bc70-ba8b-4a06-80c5-e8a370c17d1c','次韻郭帥和楊使者張茶馬溪莊詩  其一','晁說之','宋','宋诗','song-poetry','','[]','溪莊吟興浩如神，不似逄時富貴身。',64,'全唐诗/poet.song.68000.json','["溪莊吟興浩如神，不似逄時富貴身。", "雲外黄羊眠竹影，月中赤鯉戲河濵。", "揚雄奇字情宜密，張令清談分自親。", "顧我婆娑徒悵望，柴車霜雪未堪巾。"]'),
('27761116-c7b5-4997-8871-b7c40f84c617','次韻郭帥和楊使者張茶馬溪莊詩  其二','晁說之','宋','宋诗','song-poetry','','[]','才氣雄豪夙會神，暫勞旌斾遠勞身。',64,'全唐诗/poet.song.68000.json','["才氣雄豪夙會神，暫勞旌斾遠勞身。", "使華燦爛高秦嶺，筆陣縱横落渭濵。", "音出瓊瑤疲諷誦，韜輕虎豹貴和親。", "何妨戲作蜂腰句，要看時宜折上巾。"]'),
('871de460-f40b-4363-93e1-a676acc9147a','奉楊公近蒙答四六狀極爲精麗','晁說之','宋','宋诗','song-poetry','','[]','博物張公適聖神，經營佐國不謀身。',64,'全唐诗/poet.song.68000.json','["博物張公適聖神，經營佐國不謀身。", "一槍採擷朝林下，八駿遨遊暮海濵。", "詩就秦州寧獨樂，政成周道要相親。", "敗軍汙衊誰哀念，敢謂勤渠問解巾。"]'),
('baac2e3e-2f06-414e-8f67-c7a38ed71b8b','喜雨一首呈司錄諸公及諸先輩','晁說之','宋','宋诗','song-poetry','','[]','二年七日古人嘆，一雨三時此際心。',64,'全唐诗/poet.song.68000.json','["二年七日古人嘆，一雨三時此際心。", "辛苦禜宗誅大厲，歡欣畢宿散羣陰。", "無煩鐘鼓禽魚樂，便覺來牟波浪深。", "敢恨泥功山下路，且增秀色遍遙岑。"]'),
('8646ffe6-888a-4601-b32a-1e5e87198bff','和蒲君刑曹佳作  其一','晁說之','宋','宋诗','song-poetry','','[]','獨步當年賢士關，青衫初試□官閒。',32,'全唐诗/poet.song.68000.json','["獨步當年賢士關，青衫初試□官閒。", "好憐歸去龍鍾者，五世題名在道山。"]'),
('cf88fe29-af9e-49b2-a1d2-09de7b670d6a','和蒲君刑曹佳作  其二','晁說之','宋','宋诗','song-poetry','','[]','志士何曾恥把關，忠臣本自不言閒。',32,'全唐诗/poet.song.68000.json','["志士何曾恥把關，忠臣本自不言閒。", "策勳他日陣間陣，莫忘今朝山上山。"]'),
('89b31568-16d6-4f0a-8cc2-3b90434accbd','刑曹再賦二絕句彌佳不得不報  其一','晁說之','宋','宋诗','song-poetry','','[]','不肯將身入八關，判司雖屈勝如閒。',32,'全唐诗/poet.song.68000.json','["不肯將身入八關，判司雖屈勝如閒。", "漢庭富貴人何限，畢竟文章屬小山。"]'),
('d2e667bb-c7a7-4be8-835d-d3fde1d5d4aa','刑曹再賦二絕句彌佳不得不報  其二','晁說之','宋','宋诗','song-poetry','','[]','上帝白雲居九關，列仙亭館號蕭閒。',32,'全唐诗/poet.song.68000.json','["上帝白雲居九關，列仙亭館號蕭閒。", "念君未作驂鸞侣，愁殺江南庾子山。"]'),
('c851b798-9242-4eb5-a49a-ee33745cf7ba','南充大兄嘗夢見予作詩見寄次韻和呈','晁說之','宋','宋诗','song-poetry','','[]','仙山能夢我，書帙正思君。',48,'全唐诗/poet.song.68000.json','["仙山能夢我，書帙正思君。", "一德誰榮滯，羣兒謾戚欣。", "過秦何必論，喻蜀却須文。", "未落豐碑筆，唯貪辨惑勤。"]'),
('9a68fbba-e239-4ddb-9eb9-0916a24585a2','復用前韻即事奉寄','晁說之','宋','宋诗','song-poetry','','[]','南充有狂女，何以號仙君。',48,'全唐诗/poet.song.68000.json','["南充有狂女，何以號仙君。", "不食喧愚嗜，忘言聳世欣。", "我常饑亦健，公更默能文。", "鶴駕如相招，應須即日勤。"]'),
('a1819e13-831c-46c6-8e53-0bdbb14dfdba','絕句謝小邵寄柑脯','晁說之','宋','宋诗','song-poetry','','[]','曲肖歐文詩隱秀，山頭仙馭勢爭飛。',32,'全唐诗/poet.song.68000.json','["曲肖歐文詩隱秀，山頭仙馭勢爭飛。", "須知柑脯勝麟脯，更使荷衣笑錦衣。"]'),
('8346b8a5-e5ac-438c-bfa4-d42e3bd8ce1b','感事','晁說之','宋','宋诗','song-poetry','','[]','功名富貴搃愁予，南北東西盡畏途。',32,'全唐诗/poet.song.68000.json','["功名富貴搃愁予，南北東西盡畏途。", "悔不讀書徒語爾，老來悔讀少年書。"]'),
('adba1e91-0931-4cdc-b255-a554abc6966c','書何貢士居','晁說之','宋','宋诗','song-poetry','','[]','吟興隨花發，高簾對雨疏。',48,'全唐诗/poet.song.68000.json','["吟興隨花發，高簾對雨疏。", "人家南郭外，雲出北窗虛。", "笋蕨何時歇，詩書幾世居。", "我來懷舊隱，便擬返柴車。"]'),
('55908417-0946-45ee-a154-1226327d9ea6','乞宮觀報罷作','晁說之','宋','宋诗','song-poetry','','[]','明時不可干，多慮自多艱。',48,'全唐诗/poet.song.68000.json','["明時不可干，多慮自多艱。", "頗謝散班格，徒憐本色官。", "高門寧倚伏，下客强悲懽。", "鄭駟應相念，秦川歲律殫。"]'),
('27be9689-2455-4c4f-914a-3c946b842a2d','宮觀請不遂揀兵戍河朔','晁說之','宋','宋诗','song-poetry','','[]','擬駕柴車反故園，却料甲士倚和門。',32,'全唐诗/poet.song.68000.json','["擬駕柴車反故園，却料甲士倚和門。", "桐孫竹祖俱相笑，欲肖秦音長子孫。"]'),
('415d096a-048f-488f-9543-b2ba7a0c1929','感事','晁說之','宋','宋诗','song-poetry','','[]','短髮猶思沐，修途頗夢歸。',48,'全唐诗/poet.song.68000.json','["短髮猶思沐，修途頗夢歸。", "不慚爲吏拙，但恨讀書非。", "隴上健兒戍，漁陽突騎圍。", "誰能圖戰陣，枉是著朝衣。"]'),
('56b201a2-95d9-47d6-90aa-8f3e0f477da7','訪郭圓機不遇','晁說之','宋','宋诗','song-poetry','','[]','久雨宜新霽，秋光更可憐。',48,'全唐诗/poet.song.68000.json','["久雨宜新霽，秋光更可憐。", "尚嫌鴻鴈近，肯使鹿麑前。", "興矚唯高隱，名談盡昔賢。", "那知忙事在，曳杖行荒田。"]'),
('0df4ac9c-139e-4449-8e48-1c161f8a2596','秋思堙鬰忽蒙圓機寵示祟賦欣然開豁爲惠大矣率草謝之','晁說之','宋','宋诗','song-poetry','','[]','秋霜先著白髯翁，始信讀書未有功。',64,'全唐诗/poet.song.68000.json','["秋霜先著白髯翁，始信讀書未有功。", "幽恨不隨流水去，壯懷每共暮雲空。", "敢嗟落葉留無術，但惜巢危死孰從。", "賴有高才能作賦，筆端除祟是英雄。"]'),
('17fd88ba-92e1-4691-8b0d-e8d60142f32b','謝圓機除祟賦','晁說之','宋','宋诗','song-poetry','','[]','祟鬼當年曾暫解，賦成今日永嘉祥。',64,'全唐诗/poet.song.68000.json','["祟鬼當年曾暫解，賦成今日永嘉祥。", "無煩鑄鼎圖羣象，可笑時儺逐畢方。", "蕩滌辭源能澎濞，誅鋤筆陣更光芒。", "此身强健餘何事，枉是靈均嘆國殤。"]'),
('8cdd4090-e9a8-4504-9c5d-7eb923a5d2af','荔枝送郭玄機戲作  其一','晁說之','宋','宋诗','song-poetry','','[]','禍根妃子嘗珍嗜，今日何須有荔枝。',32,'全唐诗/poet.song.68000.json','["禍根妃子嘗珍嗜，今日何須有荔枝。", "玉樹後庭那結實，也能亡國更堪悲。"]'),
('a2eeb78b-e194-44d1-852c-b20a68d8150c','荔枝送郭玄機戲作  其二','晁說之','宋','宋诗','song-poetry','','[]','荔枝一騎紅塵後，便有漁陽萬騎來。',32,'全唐诗/poet.song.68000.json','["荔枝一騎紅塵後，便有漁陽萬騎來。", "郭令諸孫今得味，却同羯鼓逞詩才。"]'),
('1e1dca21-95fb-4220-a2f2-8e5dfbab165c','趙妹自咸陽寄華州石縫山芋來作絕句二首  其一','晁說之','宋','宋诗','song-poetry','','[]','華州石縫無端芋，同谷齋中有恨翁。',32,'全唐诗/poet.song.68000.json','["華州石縫無端芋，同谷齋中有恨翁。", "卯酒調來家法在，暫時不哭此途窮。"]'),
