('c5eb3636-12e6-4a7f-b116-3406dd8685a2','枕上和圓機絕句梅花十有四首  其五','晁說之','宋','宋诗','song-poetry','','[]','莫道梅花取次開，馨香須待百層臺。',32,'全唐诗/poet.song.68000.json','["莫道梅花取次開，馨香須待百層臺。", "不同碧玉小家女，寶策皇妃元姓梅。"]'),
('ca3cc3d9-8125-46c4-b87d-439707494e48','枕上和圓機絕句梅花十有四首  其六','晁說之','宋','宋诗','song-poetry','','[]','負雪披霜不得依，梅寒恨不出幽詩。',32,'全唐诗/poet.song.68000.json','["負雪披霜不得依，梅寒恨不出幽詩。", "身梁根治荒江介，情調猶輸第一辭。"]'),
('babffa9f-1558-4b02-8822-8fb8ef2e8b2a','枕上和圓機絕句梅花十有四首  其七','晁說之','宋','宋诗','song-poetry','','[]','霜女月娥愁不開，萼君西母宴瑤臺。',32,'全唐诗/poet.song.68000.json','["霜女月娥愁不開，萼君西母宴瑤臺。", "總將芳意傳英彩，下降人間得有梅。"]'),
('e887a930-d194-4d39-91c8-fef35a025f23','枕上和圓機絕句梅花十有四首  其八','晁說之','宋','宋诗','song-poetry','','[]','織女機寒自失依，雲霞扎扎似吟詩。',32,'全唐诗/poet.song.68000.json','["織女機寒自失依，雲霞扎扎似吟詩。", "女兒謝席雪無句，父子庾家梅有辭。"]'),
('941be56a-9e6c-45d6-8062-429e61cbbfaf','枕上和圓機絕句梅花十有四首  其九','晁說之','宋','宋诗','song-poetry','','[]','天馬錦輕誰得開，月兒羅薄掛香臺。',32,'全唐诗/poet.song.68000.json','["天馬錦輕誰得開，月兒羅薄掛香臺。", "屈平宋玉渾無語，後輩何人敢詠梅。"]'),
('4aa5f73f-de19-43d8-95ef-2121303d625a','枕上和圓機絕句梅花十有四首  其一○','晁說之','宋','宋诗','song-poetry','','[]','東皇太一下無依，桂酒椒漿細奠詩。',32,'全唐诗/poet.song.68000.json','["東皇太一下無依，桂酒椒漿細奠詩。", "却問人間梅幾種，郭仙爾有古人辭。"]'),
('9ceef6c7-d5d2-4508-8294-5eabd51674e3','枕上和圓機絕句梅花十有四首  其一一','晁說之','宋','宋诗','song-poetry','','[]','漢騎蜀兵下辯開，今朝惟有鳳凰臺。',32,'全唐诗/poet.song.68000.json','["漢騎蜀兵下辯開，今朝惟有鳳凰臺。", "瑤凰瓊鳳方爲瑞，此地宜多白玉梅。"]'),
('3eac9c63-199e-4b9a-b95c-177ee4ccd1ef','枕上和圓機絕句梅花十有四首  其一二','晁說之','宋','宋诗','song-poetry','','[]','東郭先生誰與依，雪中意氣后夔詩。',32,'全唐诗/poet.song.68000.json','["東郭先生誰與依，雪中意氣后夔詩。", "香添皎潔成梅咏，好視江邊黄絹辭。"]'),
('93426e30-b684-4c4d-b5a8-69e2c3ee6215','枕上和圓機絕句梅花十有四首  其一三','晁說之','宋','宋诗','song-poetry','','[]','未須白眼便嫌開，早晚高低雪作臺。',32,'全唐诗/poet.song.68000.json','["未須白眼便嫌開，早晚高低雪作臺。", "春盡子山梅感嘆，義山未臘已驚梅。"]'),
('6e30b9ca-d7ef-4142-b0f3-6c33dad9a038','枕上和圓機絕句梅花十有四首  其一四','晁說之','宋','宋诗','song-poetry','','[]','雲母屏風只暫依，金鄉公主嫁遲詩。',32,'全唐诗/poet.song.68000.json','["雲母屏風只暫依，金鄉公主嫁遲詩。", "寧論鮑照梅花恨，不及從來不惜辭。"]'),
('aa6cf135-acf9-477f-84ec-449a1e413965','圓機再以梅絕句爲謝復作二絕  其一','晁說之','宋','宋诗','song-poetry','','[]','根冷花難也自開，何須獻納在雲臺。',32,'全唐诗/poet.song.68000.json','["根冷花難也自開，何須獻納在雲臺。", "幾多得意人潛恨，江令傷心幽澗梅。"]'),
('cdbfb161-d94f-4c58-84e6-4adefc966620','圓機再以梅絕句爲謝復作二絕  其二','晁說之','宋','宋诗','song-poetry','','[]','此日梅花剩足依，明年歸只詠公詩。',32,'全唐诗/poet.song.68000.json','["此日梅花剩足依，明年歸只詠公詩。", "不堪霸水匆匆别，待寄越膏重覓辭。"]'),
('c13f0369-d254-4d88-a854-b846af059cb3','亡友陳無己有立春詩云朱門誰送青絲菜下里難酬白雪歌頗爲都下詩人所稱今日立春誦之而作','晁說之','宋','宋诗','song-poetry','','[]','地下修文幾歲郎，尚憐有子已爭行。',64,'全唐诗/poet.song.68000.json','["地下修文幾歲郎，尚憐有子已爭行。", "青絲盤到特揮淚，紅錦詩餘合斷腸。", "安得見予今議論，果誰識子古文章。", "從兹花發知多少，試訪彭門舊講堂。"]'),
('3be15b71-3dca-4f1f-aece-ac8c8d99b29a','招圓機喫槐葉冷淘','晁說之','宋','宋诗','song-poetry','','[]','庭前枯樹庾郎老，馬首垂花太祝愁。',32,'全唐诗/poet.song.68000.json','["庭前枯樹庾郎老，馬首垂花太祝愁。", "槐葉冷淘來急喫，君家醪甕却須休。"]'),
('485207d9-d16a-4c61-816d-c656a477bf11','招圓機喫槐葉冷淘有狐泉之句輒復爲謝','晁說之','宋','宋诗','song-poetry','','[]','野狐泉畔昔人集，朱亥墓南今日豪。',32,'全唐诗/poet.song.68000.json','["野狐泉畔昔人集，朱亥墓南今日豪。", "慚愧曾槐誰細摘，暫抛湯餅屬吾曹。"]'),
('99390944-e0e4-49c3-9b17-ac962be23b02','和圓機題草蟲','晁說之','宋','宋诗','song-poetry','','[]','怒劍無煩起逐蝇，從教小物此馮陵。',64,'全唐诗/poet.song.68000.json','["怒劍無煩起逐蝇，從教小物此馮陵。", "禮加蛙臂何時用，書到蠶頭幾日能。", "半是苔邊徒有感，全收芋處肯生憎。", "如椽大筆么麽落，憤懣今人終拂膺。"]'),
('1b34b8eb-6c26-42b8-abc1-ba760151d30b','再和','晁說之','宋','宋诗','song-poetry','','[]','須臾變物止樊蝇，宛轉迷人下馬陵。',64,'全唐诗/poet.song.68000.json','["須臾變物止樊蝇，宛轉迷人下馬陵。", "何處周公勤小物，幾時孔子又多能。", "堇荼自採還堪喜，菅蒯誰從便可憎。", "一到高堂榮采目，絕勝長道困鈎膺。"]'),
('0fc445ac-fcf9-4651-96d0-4f90f9cd85bf','謝圓機靈山芍藥','晁說之','宋','宋诗','song-poetry','','[]','靈山芍藥誰銷得，我是靈山授記人。',32,'全唐诗/poet.song.68000.json','["靈山芍藥誰銷得，我是靈山授記人。", "貪蝶惏蜂莫來到，更須作供老夫身。"]'),
('a4c3fcca-0d0f-467d-8bdf-1bd196d64e22','圓機遊秦州有詩相寄輒次韻作','晁說之','宋','宋诗','song-poetry','','[]','風雨關心一夢難，欲於何地見征鸞。',64,'全唐诗/poet.song.68000.json','["風雨關心一夢難，欲於何地見征鸞。", "街亭應念貶三等，壠坻須憐持兩端。", "休聽鼓鼙參將幕，已驚鉛槧誤儒冠。", "瑤音有底能相寄，不作龍鍾俗吏看。"]'),
('37c4f000-a25a-43e6-97fd-33f8ee19f815','因借書作呈圓機','晁說之','宋','宋诗','song-poetry','','[]','似隱還如吏，山亭何所宜。',48,'全唐诗/poet.song.68000.json','["似隱還如吏，山亭何所宜。", "遙心回鴈陣，倦意結蕉旗。", "使檄征錢急，鄉書問卜遲。", "近郊有高士，慎莫道三癡。"]'),
('039b171d-9de4-4e06-a85d-3d8f089b9e06','約玄機來喫社飰以雨不果','晁說之','宋','宋诗','song-poetry','','[]','積雨晦滄溟，歸期燕不靈。',24,'全唐诗/poet.song.68000.json','["積雨晦滄溟，歸期燕不靈。", "何能陪社飰，應爲厭侯鯖。"]'),
('23734916-8844-4a6d-8b4e-8b4acfdf7a7a','寄富季申','晁說之','宋','宋诗','song-poetry','','[]','故人風雪知何處，旅夢時時得舊游。',112,'全唐诗/poet.song.68000.json','["故人風雪知何處，旅夢時時得舊游。", "温麥周禾不我飽，秦雲隴水使君愁。", "劉琨數刻歡安在，何遜一筵笑則休。", "賦就思玄塵易絕，詩成述祖淚難收。", "曾窺漢簡和戎策，尚憶津梁禮佛裘。", "大軸丹青猶凛冽，小官孫子太卑陬。", "故園多謝凌霄木，直到丹霄上上頭。"]'),
('794d1232-563c-4300-9d90-43faddfb7d97','圓機寵示覽先人元祐末廷試初考倡和詩編長句不勝感佩降嘆如紳字韻直似劉夢得何幸得之輒復作增來詩之美','晁說之','宋','宋诗','song-poetry','','[]','紛紛既晚宜無恨，尚憶當年獻策人。',64,'全唐诗/poet.song.68000.json','["紛紛既晚宜無恨，尚憶當年獻策人。", "小子何能初躍馬，大臣不肯舊垂紳。", "叔孫處處偏知毁，景監人人總作因。", "格律攄情如夢得，難禁孤淚濕新春。"]'),
('2d0e415a-2270-498a-93e9-5adaeebedceb','說之復兼二公而作圓機既同邪籍之契顯夫又與僕元豐五年登科事相類時曾子固坐失考罰銅三十斤後爲先人語之甚詳','晁說之','宋','宋诗','song-poetry','','[]','波臣好蕩箕風急，浮世誰爲自必人。',64,'全唐诗/poet.song.68000.json','["波臣好蕩箕風急，浮世誰爲自必人。", "顧我高飛摧短翮，念君闊步躓長紳。", "一枝青桂憎兄好，三府丹書重友因。", "近接語言遙夢寐，共將白髪傲芳春。"]'),
('9389a6e7-922c-4230-b7fb-85ef1b2c0567','予既和圓機紳字長句復作寄孫顯夫是初考之最高等也','晁說之','宋','宋诗','song-poetry','','[]','魚龍起伏初無度，下品曾爲第一人。',64,'全唐诗/poet.song.68000.json','["魚龍起伏初無度，下品曾爲第一人。", "鴻藻自甘戎幕掾，青雲誰委玉階紳。", "命微夫子徒哀劇，天遠靈均枉問因。", "觸事思君成苦調，遙憐爛醉剩陽春。"]'),
('70322577-655c-4176-90b9-6b2ae1383168','圓機再賦紳字韻詩深得凄切之格降嘆之餘叙事爲謝','晁說之','宋','宋诗','song-poetry','','[]','軔車邂逅便相親，同是山公啟事人。',64,'全唐诗/poet.song.68000.json','["軔車邂逅便相親，同是山公啟事人。", "短髮何堪臨石鏡，長懷漫自落泉紳。", "談窮漢士三千牘，問盡胡僧十二因。", "茅屋亂山誰復識，當年曾醉上林春。"]'),
('d4ab38e0-d18b-4da2-bcb3-2c302d6e2cc0','七月一日作','晁說之','宋','宋诗','song-poetry','','[]','去秋今復號新秋，要使新愁入舊愁。',64,'全唐诗/poet.song.68000.json','["去秋今復號新秋，要使新愁入舊愁。", "四海元龍霖雨望，一生仲舉國家謀。", "囚冠不脱凋蓬鬢，旅殯何堪敗蒻舟。", "誰與此懷同涕泗，南山朝靄暮烟浮。"]'),
('ce016cdf-b9aa-486a-8d4e-098abee8a6b6','因楊刑曹往荆南代書寄二唐高士','晁說之','宋','宋诗','song-poetry','','[]','二唐今日操，真視二龔多。',48,'全唐诗/poet.song.68000.json','["二唐今日操，真視二龔多。", "不道荆州遠，其如梁苑何。", "魂收蒼壁夢，淚斷綠珠歌。", "顧我非夫甚，嵩山空薜蘿。"]'),
('9a686799-32b1-4649-b6de-9cc04f7eebdf','和圓機佳作','晁說之','宋','宋诗','song-poetry','','[]','官憎詩過好，人亦忌才多。',48,'全唐诗/poet.song.68000.json','["官憎詩過好，人亦忌才多。", "君子自如此，伊人其奈何。", "單裘千日醉，短髮百年歌。", "漫納新愁淚，終慚带女蘿。"]'),
('d4d2a6e1-8aeb-47cf-a037-36fae85504b2','圓機用墨淡甚輒以上色三丸爲好','晁說之','宋','宋诗','song-poetry','','[]','淡墨書名二十年，從軍未許勒燕然。',32,'全唐诗/poet.song.68000.json','["淡墨書名二十年，從軍未許勒燕然。", "只疑淡墨爲君累，故遣陳玄去草玄。"]'),
('5d0b2e9f-2592-4c7d-9ad9-a5934a965c97','至日早雪時郊祀畢  其一','晁說之','宋','宋诗','song-poetry','','[]','客中至日百懷忘，欣喜遙瞻上帝鄉。',64,'全唐诗/poet.song.68000.json','["客中至日百懷忘，欣喜遙瞻上帝鄉。", "雪覆紫壇天意得，風生絳節頌聲長。", "舊遊鵷鷺渾如夢，寂對山河忽若狂。", "罪籍半除猶望赦，漁陽遺種被恩光。"]'),
('de9c08d4-4908-456a-aed3-55dee54a6b51','至日早雪時郊祀畢  其二','晁說之','宋','宋诗','song-poetry','','[]','冬來無雪待佳辰，至日飛霙喜更新。',64,'全唐诗/poet.song.68000.json','["冬來無雪待佳辰，至日飛霙喜更新。", "風偃南郊雲獻瑞，龍騰北陸日潛春。", "壁門仗下千官佩，瑤席歌前萬國珍。", "負亹曾臣符竹冷，屬車目斷不飛塵。"]'),
('ff239d38-e49d-46b1-a9d5-00c76f6228b3','東城外作呈圓機','晁說之','宋','宋诗','song-poetry','','[]','默默專城歲月馳，忽來郊外得心期。',64,'全唐诗/poet.song.68000.json','["默默專城歲月馳，忽來郊外得心期。", "龍蛇起伏知何處，天地圓方在此時。", "更喜風光似江介，可憐飽餉便忘疲。", "即從此路東歸去，他日何能得夢思。"]'),
('fb6fb2f9-f707-4380-b753-c4569ccc705d','謝圓機梅子','晁說之','宋','宋诗','song-poetry','','[]','雲隨枉渚月，依嵐末宦低。',48,'全唐诗/poet.song.68000.json','["雲隨枉渚月，依嵐末宦低。", "頭幾不堪顧，我傖翁宜塞。", "北因君梅子，憶江南君乎。", "學問二劉比，南北該通酸。"]'),
('a8bf99d5-b4e8-4c5a-80a5-a1e8e2b50dc9','自甘讀沈下賢集絕句二呈圓機  其一','晁說之','宋','宋诗','song-poetry','','[]','晚來李杜擅文章，無奈情何憶沈郎。',32,'全唐诗/poet.song.68000.json','["晚來李杜擅文章，無奈情何憶沈郎。", "未掩西施朝薤淚，可堪弄玉暮魂香。"]'),
('c7883d0c-a6f8-440b-9b19-435fb422fd28','自甘讀沈下賢集絕句二呈圓機  其二','晁說之','宋','宋诗','song-poetry','','[]','荷葉拳拳恨未舒，伊人歸興問何如。',32,'全唐诗/poet.song.68000.json','["荷葉拳拳恨未舒，伊人歸興問何如。", "空看蝇鼻燈花喜，不得平安一紙書。"]'),
('e71d77a6-fba6-4e6d-ac98-d2cf775e17ae','聞八弟朝議二十一弟朝奉二十弟廸功與安郎倉部謝郎比部諸人集于葆真宮戲作絕句','晁說之','宋','宋诗','song-poetry','','[]','葆真宮是何年有，游子相將便得真。',32,'全唐诗/poet.song.68000.json','["葆真宮是何年有，游子相將便得真。", "聞道流霞醒不醉，只應人世恨還新。"]'),
('604fbd5d-355f-4727-a2a7-17071fdcbe9d','歲暮絕句四首  其一','晁說之','宋','宋诗','song-poetry','','[]','衛霍功名無素譽，韓彭富貴晚堪悲。',32,'全唐诗/poet.song.68000.json','["衛霍功名無素譽，韓彭富貴晚堪悲。", "梅花引角邊情劇，况復人間歲暮時。"]'),
('f3fb9e9d-f29e-4dab-950a-755ffde73e56','歲暮絕句四首  其二','晁說之','宋','宋诗','song-poetry','','[]','下惠一時行已志，首陽萬古振人倫。',32,'全唐诗/poet.song.68000.json','["下惠一時行已志，首陽萬古振人倫。", "終南不得西山號，歲暮白頭空斷魂。"]'),
('6796cc47-9efe-4334-8a87-c957538e357f','歲暮絕句四首  其三','晁說之','宋','宋诗','song-poetry','','[]','沉沉欲雪岫雲平，月尾年頭此有情。',32,'全唐诗/poet.song.68000.json','["沉沉欲雪岫雲平，月尾年頭此有情。", "童稚歡欣學秦語，不知家世本東京。"]'),
('aab7c400-97cd-4ed7-845d-24d147be6c17','歲暮絕句四首  其四','晁說之','宋','宋诗','song-poetry','','[]','遲遲來日去何疾，六十五見此日除。',32,'全唐诗/poet.song.68000.json','["遲遲來日去何疾，六十五見此日除。", "明發束修能有幾，太平田舍讀殘書。"]'),
('8599245d-bd51-4a44-9382-7d266d99fe0e','聞鄒德久自常來州圩垾得良田數十頃遂可活輒作絕句','晁說之','宋','宋诗','song-poetry','','[]','乃公不識賈公閭，之子饑寒夜讀書。',32,'全唐诗/poet.song.68000.json','["乃公不識賈公閭，之子饑寒夜讀書。", "前年避賊逐江鷺，今歲垾田鞭海魚。"]'),
('e154f1f4-abb6-42ce-90ed-03c46806ead6','謝圓機送梅','晁說之','宋','宋诗','song-poetry','','[]','何事新梅度玉溪，應憐泯默與詩題。',32,'全唐诗/poet.song.68000.json','["何事新梅度玉溪，應憐泯默與詩題。", "少年曾賦宋開府，老大無如羯鼓迷。"]'),
('e06fdca2-be2a-43ec-93ef-d4a0e1da5443','圓機寵以長句賀禱雪龍池輒次韻述謝','晁說之','宋','宋诗','song-poetry','','[]','神州鍾鼓浹年豐，燈熖紅綿照景龍。',64,'全唐诗/poet.song.68000.json','["神州鍾鼓浹年豐，燈熖紅綿照景龍。", "况有玉楚榮廣內，不勞金甲老邊封。", "同雲出洞如人意，孤宦臨岐斂病容。", "何事儒先詩思苦，欲抛萬卷作三農。"]'),
('9ff5d82c-606e-44f8-a23f-9dc8a993c570','再和圓機喜雪之作','晁說之','宋','宋诗','song-poetry','','[]','十遇荒饑一遇豐，人間不見壁間龍。',64,'全唐诗/poet.song.68000.json','["十遇荒饑一遇豐，人間不見壁間龍。", "既慳雨澤空倉厄，仍廣車輿小子封。", "俗吏教條徒自愧，滮池雲物幸相容。", "怪來不與秦湫詛，應許多藏漢大農。"]'),
('7186c269-3883-40c8-bc94-a6042763c6e6','又再和','晁說之','宋','宋诗','song-poetry','','[]','人人講德自元豐，何處荀家有八龍。',64,'全唐诗/poet.song.68000.json','["人人講德自元豐，何處荀家有八龍。", "白羽不施寧洗甲，赤雲常見預乾封。", "無煩禾黍如茨稼，自足鵷鸞琢玉容。", "稽首寶香通列畢，傾心御糴走良農。"]'),
('579c2e5f-ad39-48d9-81ce-eca5f4eab176','對雪再用豐字呈圓機','晁說之','宋','宋诗','song-poetry','','[]','何人醉酒在新豐，暮雪瓊飛驂玉龍。',64,'全唐诗/poet.song.68000.json','["何人醉酒在新豐，暮雪瓊飛驂玉龍。", "雲借威稜如直指，風排傾倚似斜封。", "堂堂不及侏儒飽，烈烈徒多憔悴容。", "久負梁園能賦客，且遵漢詔善勤農。"]'),
('f8798d5c-4b2c-49c4-a20a-2245347966e6','再用豐字韻對雪呈圓機','晁說之','宋','宋诗','song-poetry','','[]','樂只康州得婁豐，鼓簫欣喜有池龍。',64,'全唐诗/poet.song.68000.json','["樂只康州得婁豐，鼓簫欣喜有池龍。", "魚由米穴多爭出，泥在函關廣費封。", "鎮玉無時非北渚，磨圭在處是南容。", "胡然最愛田疇事，即日歸休學老農。"]'),
('4381e637-879c-4211-9860-fe3b64338c08','朱郎元章以予不得宮觀與諸侄有唱和見寄攬之欣喜五更枕上賦四首  其一','晁說之','宋','宋诗','song-poetry','','[]','天上何曾有謫仙，一來下土便頑然。',64,'全唐诗/poet.song.68000.json','["天上何曾有謫仙，一來下土便頑然。", "偶遭愁鬼棲遲厄，永結羈人寂寞緣。", "不得閒身從靜志，徒思樂食與安眠。", "兒曹詩句來存問，盡賀朱家爲發編。"]'),
('c35663c8-8e00-4fa3-adf8-24e6730fd59c','朱郎元章以予不得宮觀與諸侄有唱和見寄攬之欣喜五更枕上賦四首  其二','晁說之','宋','宋诗','song-poetry','','[]','璈音在昔是文仙，近世仙才殊不然。',64,'全唐诗/poet.song.68000.json','["璈音在昔是文仙，近世仙才殊不然。", "每見傳言多俗態，定知所事亦塵緣。", "况爲末吏惟貪佞，何處高人得醉眠。", "此際朱郎真有道，樂吾羣從有殘編。"]'),
('0ef4d5b0-ed58-4c18-9ba0-813952a2a473','朱郎元章以予不得宮觀與諸侄有唱和見寄攬之欣喜五更枕上賦四首  其三','晁說之','宋','宋诗','song-poetry','','[]','狂醉何爲號八仙，三郎宮裏亦頹然。',64,'全唐诗/poet.song.68000.json','["狂醉何爲號八仙，三郎宮裏亦頹然。", "呼山絳節方無數，犯闕紅旗自有緣。", "便醉攜家船上去，已輸傍舍甕頭眠。", "箕南潁北逍遙客，好笑仇池戀簡編。"]'),
('7fe8d3df-4e25-4478-88d9-4bf9a3c2cd43','朱郎元章以予不得宮觀與諸侄有唱和見寄攬之欣喜五更枕上賦四首  其四','晁說之','宋','宋诗','song-poetry','','[]','莫笑吹笙便得仙，絕勝祭竈事茫然。',64,'全唐诗/poet.song.68000.json','["莫笑吹笙便得仙，絕勝祭竈事茫然。", "白頭吏役徒多犯，黄帽閒居政寡緣。", "仰愧高僧能五鬛，俯慚垂柳解三眠。", "詩成自贈仍堪寄，聞道衰蒲尚可編。"]'),
('846474a7-b029-4d5f-a69b-ad899dfb2438','過萬丈潭觀山呈圓機','晁說之','宋','宋诗','song-poetry','','[]','棄捐蹤跡盡悠悠，山水之恩亦太優。',64,'全唐诗/poet.song.68000.json','["棄捐蹤跡盡悠悠，山水之恩亦太優。", "成熟此生無再辱，發揚何事敢他求。", "乘閒今日聯高足，就隱明年獨遠遊。", "潭面可量才萬丈，總於春恨作浮漚。"]'),
('cd58a4ce-1fad-476d-a8c4-048036756491','社日偶集恨去歲社與圓機有約阻雨','晁說之','宋','宋诗','song-poetry','','[]','歸閏於春得社遲，酒應過熟老農嬉。',64,'全唐诗/poet.song.68000.json','["歸閏於春得社遲，酒應過熟老農嬉。", "故巢候燕賓朋禁，驟雨前年唱和詩。", "要使歌喉扶嫵媚，肯教鼠目鬬狐疑。", "雲南薊北休驚怕，今日寛仁不戮師。"]'),
('ee1c3a88-51d4-4f26-b883-1e1be9472ae0','才上人處見圓機五字輒用其韻作','晁說之','宋','宋诗','song-poetry','','[]','振錫千峰下，觀空萬象前。',48,'全唐诗/poet.song.68000.json','["振錫千峰下，觀空萬象前。", "水深猿臂直，雪厚虎蹄圓。", "工部淚徒感，贊公燈不眠。", "當年郭有道，今日更談襌。"]'),
('1c2f986d-0f2b-40a1-a46c-b96eeb66602f','山行微雨對花覺秦少游山路雨添花之語爲佳因有感於斯人','晁說之','宋','宋诗','song-poetry','','[]','今日山行花畔語，故人佳句雨添花。',64,'全唐诗/poet.song.68000.json','["今日山行花畔語，故人佳句雨添花。", "瘴來首秃成纍鬼，夢裏懷鉛稱史家。", "輕薄揚州真可笑，賢良漢殿更堪嗟。", "寧知用短難鳴者，只得身存下澤車。"]'),
('650001a1-9db5-4c70-9881-586b4b427abd','書事酬新興元使君邵大兄邵與圓機有舊因以奉呈','晁說之','宋','宋诗','song-poetry','','[]','東來車騎豈君歸，我欲懸車歸則時。',64,'全唐诗/poet.song.68000.json','["東來車騎豈君歸，我欲懸車歸則時。", "仙女丹砂能不老，腐儒青簡亦難衰。", "寧乖洛水田園計，且及燕山餽餉期。", "最課直當中祕閣，白頭相望更遲遲。"]'),
('81487597-bab7-4b74-9559-58aebfc9e872','又依韻一首','晁說之','宋','宋诗','song-poetry','','[]','看去朱轓今已歸，問余山郡幾多時。',64,'全唐诗/poet.song.68000.json','["看去朱轓今已歸，問余山郡幾多時。", "盤絛綾様知能盛，带葉甘香定不衰。", "惜别荔枝紅髪𩭝，恨看山嶺碧參差。", "自憐藉手有何物，學把鋤頭不用嗤。"]'),
('91fbbb83-c39f-4e7c-8802-fd8f8421cf0b','圓機和邵大及予二詩可謂壓倒五更枕上誦嘆不已復作謝之足見來章之美能發人情思也  其一','晁說之','宋','宋诗','song-poetry','','[]','去歲巢乾燕子歸，生涯辛苦問何時。',64,'全唐诗/poet.song.68000.json','["去歲巢乾燕子歸，生涯辛苦問何時。", "門前似覺酒徒散，坐上何嘗筆力衰。", "郡印故人能若若，田廬晚友亦差差。", "莫嫌相望函關外，且是不爲陶令嗤。"]'),
('75bab3ee-9ef0-4270-8eb6-ccaafc4acbd9','圓機和邵大及予二詩可謂壓倒五更枕上誦嘆不已復作謝之足見來章之美能發人情思也  其二','晁說之','宋','宋诗','song-poetry','','[]','借問高吟何所歸，元和格律定同時。',64,'全唐诗/poet.song.68000.json','["借問高吟何所歸，元和格律定同時。", "折除官職知多少，兼領才名孰盛衰。", "奏疏不爲黄閣計，結廬且共白雲期。", "君家博士歸依佛，可笑夫君得計遲。"]'),
('59a2daa5-eaf5-474e-a745-0b616f6a77d3','約圓機不至將出遊雞頭山作二絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','君何忘我不交關，爲我勝君便不閒。',32,'全唐诗/poet.song.68000.json','["君何忘我不交關，爲我勝君便不閒。", "豹霧人須歸豹谷，雞棲車且遊雞山。"]'),
('88d13cd3-29db-40e8-abd2-dacdedcafe44','約圓機不至將出遊雞頭山作二絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','君知我亦有柴關，我豈輸君獨自閒。',32,'全唐诗/poet.song.68000.json','["君知我亦有柴關，我豈輸君獨自閒。", "把筆何人鳳尾諾，杖藜望我雞頭山。"]'),
('60b9ab93-ff2b-46e7-aeda-0f7d491ccbd3','復作山字絕句呈圓機','晁說之','宋','宋诗','song-poetry','','[]','羊頭山笑雞頭山，我粲文章爾漫頑。',32,'全唐诗/poet.song.68000.json','["羊頭山笑雞頭山，我粲文章爾漫頑。", "遊子白頭顔不少，任人譏侮亢高顔。"]'),
('68230b90-1b64-40e7-8871-f4bb326bde51','聞圓機遊山歸作','晁說之','宋','宋诗','song-poetry','','[]','把酒相忘笑語違，新詩應已勒巖扉。',32,'全唐诗/poet.song.68000.json','["把酒相忘笑語違，新詩應已勒巖扉。", "何人龍尾道前出，獨自雞頭山裏歸。"]'),
('a1312d4c-0493-4e86-a804-66ae1e234f42','聞圓機遊山政爲梵供復用前韻作','晁說之','宋','宋诗','song-poetry','','[]','蹙縮饑腸與世違，崚嶒折屐到雲扉。',32,'全唐诗/poet.song.68000.json','["蹙縮饑腸與世違，崚嶒折屐到雲扉。", "丹砂不逐飛仙去，白叠甘從佞佛歸。"]'),
('8fc70a49-2605-425c-9b7e-a1d3d6d64886','請休致後閒書','晁說之','宋','宋诗','song-poetry','','[]','折軸迷邦漫問津，行藏不斷只因循。',64,'全唐诗/poet.song.68000.json','["折軸迷邦漫問津，行藏不斷只因循。", "那知老作邊城守，好去閒爲負郭人。", "細向舊圖逢景色，偶因掘筆得精神。", "舉軍追恨成何事，可笑將軍走解巾。"]'),
('26ece287-d6c3-4501-916b-580570bc610f','試邁侄所寄冷金牋','晁說之','宋','宋诗','song-poetry','','[]','不煩鐘鼓强吹蕭，自有詩書共欝陶。',32,'全唐诗/poet.song.68000.json','["不煩鐘鼓强吹蕭，自有詩書共欝陶。", "暖玉何年來比德，冷金即日得抽毫。"]'),
('be643c16-c87d-44bf-aeb3-9db11e8caee7','夜聽雨','晁說之','宋','宋诗','song-poetry','','[]','岐汴無煩和恊使，秦雲送我入梁園。',32,'全唐诗/poet.song.68000.json','["岐汴無煩和恊使，秦雲送我入梁園。", "殘燈半夜夢回雨，心事誰來慟哭論。"]'),
('0ae27c71-81f3-447f-9f12-3ad988c83789','致仕歸東里','晁說之','宋','宋诗','song-poetry','','[]','板令懸車欠四年，散關如砥去欣然。',32,'全唐诗/poet.song.68000.json','["板令懸車欠四年，散關如砥去欣然。", "鄭州門首人爭入，誰伴山翁老洧淵。"]'),
('248538a6-8f38-4a7b-85b1-5b7847e9cea6','致仕後寄白蓮然公','晁說之','宋','宋诗','song-poetry','','[]','僧衣換却朝衣盡，知悔知非恐不任。',64,'全唐诗/poet.song.68000.json','["僧衣換却朝衣盡，知悔知非恐不任。", "磬韻應憐持課罷，香銷當識坐禪深。", "芭蕉庭下三身正，蟋蟀床頭百慮侵。", "憶我白蓮菴裏士，幾年消息亦沉沉。"]'),
('010721dd-1753-4788-9dc0-6caaf3ec2e48','然公發人自天台來不以烏藥見寄','晁說之','宋','宋诗','song-poetry','','[]','石橋不得往，烏藥不寄來。',24,'全唐诗/poet.song.68000.json','["石橋不得往，烏藥不寄來。", "空令圖畫裏，指點說天台。"]'),
('f038a2c2-4a10-4242-896b-315bacaa4738','致仕後間夜雨','晁說之','宋','宋诗','song-poetry','','[]','厚矣皇恩得謝休，蕭然白髮更何求。',32,'全唐诗/poet.song.68000.json','["厚矣皇恩得謝休，蕭然白髮更何求。", "雨聲中夜生高興，不似官人身外愁。"]'),
('bd160052-b30c-4303-95b5-daeabc50e747','即事二首  其一','晁說之','宋','宋诗','song-poetry','','[]','晚靄沈山月隱林，終朝好學仲長瘖。',32,'全唐诗/poet.song.68000.json','["晚靄沈山月隱林，終朝好學仲長瘖。", "忍將老易供書畫，更與何人得斷金。"]'),
('c642991a-86aa-41a3-9b88-7e49c881877b','即事二首  其二','晁說之','宋','宋诗','song-poetry','','[]','藥苗晚種已青青，應念尫羸與養形。',32,'全唐诗/poet.song.68000.json','["藥苗晚種已青青，應念尫羸與養形。", "肯爲嵇生徒著論，便同玄晏剩翻經。"]'),
('4406e1e2-27d6-43fd-bdbc-787a0a86eb29','哀韓君表無文編','晁說之','宋','宋诗','song-poetry','','[]','少師名德振鵷鸞，孫子何爲短羽翰。',64,'全唐诗/poet.song.68000.json','["少師名德振鵷鸞，孫子何爲短羽翰。", "不使功名藏竹簡，宜留文字後人看。", "六丁取去嗟韓第，七子亡來恨建安。", "賴有上公曾塔葬，多情無用涕汍瀾。"]'),
('927cbd08-a832-4c43-bef7-ba30d5c0659d','山中酒熟','晁說之','宋','宋诗','song-poetry','','[]','山醖今朝熟，黄花老不香。',24,'全唐诗/poet.song.68000.json','["山醖今朝熟，黄花老不香。", "沉陰千萬里，何處有重陽。"]'),
('61637df3-8cf5-44ad-8293-acf6c7947b69','雨中','晁說之','宋','宋诗','song-poetry','','[]','雨中新種竹，波上舊來鷗。',24,'全唐诗/poet.song.68000.json','["雨中新種竹，波上舊來鷗。", "客子何時樂，幽人未肯愁。"]'),
('46df587f-9076-49ec-8b1c-917d4085909d','悲秋','晁說之','宋','宋诗','song-poetry','','[]','白楊夾道起秋聲，要使征人恨不平。',32,'全唐诗/poet.song.68000.json','["白楊夾道起秋聲，要使征人恨不平。", "自笑一生成底事，元常筆秃却談兵。"]'),
('788a2388-3bf2-456a-925d-eb71a7f9049e','寄温倅江十四','晁說之','宋','宋诗','song-poetry','','[]','離别蹉跎歲月深，故人带未九環金。',64,'全唐诗/poet.song.68000.json','["離别蹉跎歲月深，故人带未九環金。", "狂兒易悦笙歌費，志士徒勞涕淚侵。", "金紫早年唯樂夢，令公老去亦傷心。", "永嘉康樂風流在，别乘猶能翦綠林。"]'),
('0e217510-ac07-4bb1-a516-bb9f6d6de544','憶天台東掖然老','晁說之','宋','宋诗','song-poetry','','[]','然公嗟契闊，海岳阻招攜。',48,'全唐诗/poet.song.68000.json','["然公嗟契闊，海岳阻招攜。", "白法歸龍樹，清談落虎溪。", "著書非草具，傳業漫私題。", "歲暮茅楹客，臨文處處迷。"]'),
('53a02e99-29cd-4982-9adb-d1a92e10a12e','風琴','晁說之','宋','宋诗','song-poetry','','[]','不植風琴二十年，僧來爲我置齋前。',32,'全唐诗/poet.song.68000.json','["不植風琴二十年，僧來爲我置齋前。", "欲教羈思殘春夢，吟落浮雲共灑然。"]'),
('3422e66d-78a2-4983-8198-43a1bd98674c','次朱少章韻','晁說之','宋','宋诗','song-poetry','','[]','喜就三冬學，仍開橘秫韲。',48,'全唐诗/poet.song.68000.json','["喜就三冬學，仍開橘秫韲。", "星霜吳地客，風雨鄭人鷄。", "逸興逢蓬霤，高懷絕石梯。", "五言何富麗，種玉不論畦。"]'),
('abc7eb48-39af-4327-becd-d8463e67b934','二十二弟獲金印','晁說之','宋','宋诗','song-poetry','','[]','季也獲金印，籀文秦不如。',48,'全唐诗/poet.song.68000.json','["季也獲金印，籀文秦不如。", "情知非鬼篆，恨不識天書。", "池靜龜游罷，庭閒鵲鬬餘。", "春風還舊物，疏俊獨憐渠。"]'),
('12570c94-91b1-42d9-8ef0-977a379d46c5','和朱少章見寄','晁說之','宋','宋诗','song-poetry','','[]','兼該夫子耻專門，却笑何人哮吼村。',64,'全唐诗/poet.song.68000.json','["兼該夫子耻專門，却笑何人哮吼村。", "悶己賦疑唯獨語，惱卿詩似得同論。", "夜來雨足寛貧病，秋到凉生破睡昏。", "幾欲抛書閒過日，只慚無可謝嫣蓀。"]'),
('e939d45e-aabc-4941-87dd-979401913793','贈弟送山醖','晁說之','宋','宋诗','song-poetry','','[]','山醖今朝熟，溪氛起正炎。',24,'全唐诗/poet.song.68000.json','["山醖今朝熟，溪氛起正炎。", "醉予難酩酊，泣汝淚闌干。"]'),
('9ebd44c8-0c07-42d7-bc13-39be3eb81541','宋太夫人挽詞  其一','晁說之','宋','宋诗','song-poetry','','[]','漢室賢良逝，萊妻節操長。',48,'全唐诗/poet.song.68000.json','["漢室賢良逝，萊妻節操長。", "生涯兩丱角，心事一縑緗。", "膝下黄金带，齋中紫玉章。", "人間足悲樂，壠柏起清商。"]'),
('0603c691-ded5-4ccd-a7ab-f8a460811e7a','宋太夫人挽詞  其二','晁說之','宋','宋诗','song-poetry','','[]','白髮餘欣喜，清時忽嘆嗟。',48,'全唐诗/poet.song.68000.json','["白髮餘欣喜，清時忽嘆嗟。", "棧危思杜宇，淮漲夢僧伽。", "鸑鷟能儀國，驊騮善保家。", "傳聞專却粒，歸去五雲車。"]'),
('5b862b0e-75db-4e43-b4e6-47d0fc9f606c','悼亂','晁說之','宋','宋诗','song-poetry','','[]','解組邊亭畿甸來，且將白髪共徘徊。',32,'全唐诗/poet.song.68000.json','["解組邊亭畿甸來，且將白髪共徘徊。", "去年亭下花何在，日夜風塵不得開。"]'),
('279270e7-f877-4f58-b59e-60a5a2292821','題縣南莊壁','晁說之','宋','宋诗','song-poetry','','[]','城下之師莫問天，只將性命託忠賢。',64,'全唐诗/poet.song.68000.json','["城下之師莫問天，只將性命託忠賢。", "效官三黜未爲恨，閉戶七奔方可憐。", "虎變不宜懷猶預，龍韜豈憚費迍邅。", "前村父老來相問，本望今年是好年。"]'),
('67a4e1d4-41c3-4a82-9afa-faf696d52346','上元前再題南莊壁二首  其一','晁說之','宋','宋诗','song-poetry','','[]','蒼皇徒步子孫隨，倒邑空城失所之。',64,'全唐诗/poet.song.68000.json','["蒼皇徒步子孫隨，倒邑空城失所之。", "十日不通京國信，一燈誰憶上元時。", "大河難阻金人過，遠道休論鐵馬期。", "弭難九州宜祭鼎，慶雲翔鶴誤聲詩。"]'),
('4f4c2932-2969-438f-a9de-2796f7a2570c','上元前再題南莊壁二首  其二','晁說之','宋','宋诗','song-poetry','','[]','古今之禍此云奇，倏忽犬戎城下師。',64,'全唐诗/poet.song.68000.json','["古今之禍此云奇，倏忽犬戎城下師。", "犯闕過於侯景速，劫君更比祿山危。", "萬方瑞物問何在，五世誓書知謾爲。", "禍難羣凶誰首尾，京如狼虎黼狐狸。"]'),
('8ccdd7e3-6fd1-4f25-b462-eeb8eabcb971','我昔題南莊壁','晁說之','宋','宋诗','song-poetry','','[]','我昔柴門宜樂只，田園遠近亦康哉。',64,'全唐诗/poet.song.68000.json','["我昔柴門宜樂只，田園遠近亦康哉。", "花摇笠頂唱歌去，草塞瓶頭沽酒來。", "白叟披衣論甲子，青禽哺乳占莓苔。", "豈期一日風塵起，南北東山俱可哀。"]'),
('fc21c786-02c9-4e12-b112-68de227a50ee','花石題南莊壁','晁說之','宋','宋诗','song-poetry','','[]','花石倡優樂未央，四維忽絕失皇綱。',64,'全唐诗/poet.song.68000.json','["花石倡優樂未央，四維忽絕失皇綱。", "敵人便欲吞鄰國，鶴駕知誰從上皇。", "雲外安妃情已斷，塵中仙伯恨空長。", "豈無撥亂濟時策，久棄蒿萊不得將。"]'),
('c4cf6e48-10f0-4b7d-b8e9-34c630a13e64','我生','晁說之','宋','宋诗','song-poetry','','[]','我生初世本堯年，大厲羣哇不謂然。',64,'全唐诗/poet.song.68000.json','["我生初世本堯年，大厲羣哇不謂然。", "方喜神光射天下，忽驚烽火到甘泉。", "寺人衮服參巖廟，宮女素衣遊市廛。", "一道德來千道會，試開言路問羣賢。"]'),
('9bcaaa92-106b-4326-a03a-f70069c229fb','春晚','晁說之','宋','宋诗','song-poetry','','[]','春晚何爲尚絮袍，强尋樂事慰無寥。',67,'全唐诗/poet.song.68000.json','["春晚何爲尚絮袍，强尋樂事慰無寥。", "鍛聲不讓雨聲急，花影争隨幡影高。", "莫問糇粮難卒歲，且無甲馬在今朝。", "書成泥首懶{扌舁}櫬，定是蒼生不我遭。"]'),
('9b459cf9-b0b5-4e86-bc74-c0f4e23475a3','聞景龍不試燈','晁說之','宋','宋诗','song-poetry','','[]','華燈不試管絃新，八字歌聲滿市塵。',32,'全唐诗/poet.song.68000.json','["華燈不試管絃新，八字歌聲滿市塵。", "今日景龍門寂寞，唯將明德照新春。"]'),
('8e8feca9-1234-443b-97be-2458bff763dc','送蒲君赴陜西漕屬','晁說之','宋','宋诗','song-poetry','','[]','殽函爲客樂，巴蜀故鄉榮。',48,'全唐诗/poet.song.68000.json','["殽函爲客樂，巴蜀故鄉榮。", "風雪擔書夢，旌旂從使行。", "黷兵烽燧息，積粟犬羊平。", "同谷曾談話，知君筆陣横。"]'),
('b5e36c54-d848-4f34-a23e-0d5d11fb3be9','外甥三郎删定和予冠字韻詩極可喜再用其韻作二首韋蘇州有外甥趙伉獻詩合雅音  其一','晁說之','宋','宋诗','song-poetry','','[]','趙甥詩與雅音合，韋舅宜高進德冠。',64,'全唐诗/poet.song.68000.json','["趙甥詩與雅音合，韋舅宜高進德冠。", "我到古人良已遠，汝承宗姓莫教難。", "傳家自喜春秋在，居職應憐翰墨殘。", "門戶人身難相稱，衣裳儀觀不須嘆。"]'),
('d7d31380-30bc-4806-b846-d7f67328a7fb','外甥三郎删定和予冠字韻詩極可喜再用其韻作二首韋蘇州有外甥趙伉獻詩合雅音  其二','晁說之','宋','宋诗','song-poetry','','[]','趙妹生兒身七尺，倚天劍稱切雲冠。',64,'全唐诗/poet.song.68000.json','["趙妹生兒身七尺，倚天劍稱切雲冠。", "長人自惜聲名達，志士寧令扞格難。", "墨翟商瞿心總厚，司空城旦術何殘。", "還將格律成吟詠，作者應須爲爾歎。"]'),
('63e46590-fd06-42bc-9e23-843a8fa5454c','寄城中親舊','晁說之','宋','宋诗','song-poetry','','[]','蒼皇逐客投蘭若，傍曉衾寒喜且驚。',64,'全唐诗/poet.song.68000.json','["蒼皇逐客投蘭若，傍曉衾寒喜且驚。", "隱隱似聞開静版，沈沈欲歇讀經聲。", "好將遲暮此間過，强欲論思何處行。", "城裏有誰能念我，勞渠努力致升平。"]'),
('b6bd05b7-c5df-4e91-85c3-724e58b6f97a','淮口作','晁說之','宋','宋诗','song-poetry','','[]','王畿胡騎滿，何地可逃生。',48,'全唐诗/poet.song.68000.json','["王畿胡騎滿，何地可逃生。", "盡室半徒步，有舟無水行。", "長淮能見阻，久雨自難晴。", "雜立官稱在，低頭媿國榮。"]'),
('4bb0857e-765e-49db-b6ef-5d64a50c543e','洪澤守閘和二十二弟韻','晁說之','宋','宋诗','song-poetry','','[]','小舟洪澤歎嗟餘，欲說人間孰得如。',64,'全唐诗/poet.song.68000.json','["小舟洪澤歎嗟餘，欲說人間孰得如。", "蝙蝠倒懸徒頡頑，獼猴徐步漫趑趄。", "歲窮雲際行求鴈，日暮溪頭坐羡魚。", "何處長風萬里浪，龍盤鼇抃蜃樓居。"]'),
('379ee90a-4cb5-4a5d-8797-07e1b3456697','和二十二弟龜山寺三絕  其一','晁說之','宋','宋诗','song-poetry','','[]','江邊龜步亦平平，淮上龜山聳五兵。',32,'全唐诗/poet.song.68000.json','["江邊龜步亦平平，淮上龜山聳五兵。", "何但八公山草木，解令王國列金城。"]'),
('2ab006bb-f718-4d3c-be32-b282e9cbf07e','和二十二弟龜山寺三絕  其二','晁說之','宋','宋诗','song-poetry','','[]','龜山之操恨時危，語樂徒勞魯太師。',32,'全唐诗/poet.song.68000.json','["龜山之操恨時危，語樂徒勞魯太師。", "今日龜山無可恨，祥符年上御題詩。"]'),
('82533979-6062-40d5-90e6-26989c2bc1b0','和二十二弟龜山寺三絕  其三','晁說之','宋','宋诗','song-poetry','','[]','海岸石龜恨未平，時時入海自馮陵。',32,'全唐诗/poet.song.68000.json','["海岸石龜恨未平，時時入海自馮陵。", "此山盤礴清淮上，寶塔分功更就曾。"]'),
('0e429bcf-1bdc-4478-b73f-277576f9370f','過鴈和二十二弟韻  其一','晁說之','宋','宋诗','song-poetry','','[]','我避邊塵淮海遠，悠然問鴈爾何來。',32,'全唐诗/poet.song.68000.json','["我避邊塵淮海遠，悠然問鴈爾何來。", "中原消息須聞取，南岳峰頭莫漫回。"]'),
('63dac9fe-9c68-4538-b1eb-4db95f81ee91','過鴈和二十二弟韻  其二','晁說之','宋','宋诗','song-poetry','','[]','莊周口舌過平生，擇鴈何爲貴不鳴。',32,'全唐诗/poet.song.68000.json','["莊周口舌過平生，擇鴈何爲貴不鳴。", "默默高飛寧有樂，人間生死本來輕。"]'),
('b79d512e-96ac-420e-b54f-19f954fe29fb','窮途','晁說之','宋','宋诗','song-poetry','','[]','窮途無達士，今日信途窮。',48,'全唐诗/poet.song.68000.json','["窮途無達士，今日信途窮。", "處處兵如市，行行馬似龍。", "魂迷公主館，夢斷翠微宮。", "欲向江東去，風波更幾重。"]'),
('4f999806-726c-4a5a-9540-134ed3eae6fd','消息','晁說之','宋','宋诗','song-poetry','','[]','兩月中原消息斷，不應京國亦無聞。',32,'全唐诗/poet.song.68000.json','["兩月中原消息斷，不應京國亦無聞。", "廟堂如未棄黎庶，日日詔書清垢氛。"]'),
('317ba1bb-1caf-469e-acc7-bed1c6d1b660','初到高郵','晁說之','宋','宋诗','song-poetry','','[]','避難蒼黄處處過，扁舟不復怯風波。',64,'全唐诗/poet.song.68000.json','["避難蒼黄處處過，扁舟不復怯風波。", "禹功淮海施偏少，漢業東南得最多。", "幾日兵强令敵退，今年米賤奈予何。", "孫公鄉里仍堪住，愁訪山齋空薜蘿。"]'),
('22efadd1-3fa9-4f46-b8ea-1e67fe52973d','揚州三絕句  其一','晁說之','宋','宋诗','song-poetry','','[]','客散平山堂上後，孰如子駿在揚州。',32,'全唐诗/poet.song.68000.json','["客散平山堂上後，孰如子駿在揚州。", "解傳鮑照舊辭賦，輸盡蕪城千古愁。"]'),
('ab8bacb0-badf-4648-8e10-02a94a5e7cae','揚州三絕句  其二','晁說之','宋','宋诗','song-poetry','','[]','風常歡喜月常愁，愁有盈虧喜自由。',32,'全唐诗/poet.song.68000.json','["風常歡喜月常愁，愁有盈虧喜自由。", "客到揚州已迷路，不須特地上迷樓。"]'),
('fc2e3593-6def-4f22-95a7-41eb43cdf33f','揚州三絕句  其三','晁說之','宋','宋诗','song-poetry','','[]','便風五兩更悠悠，回望鄉閭烟霧浮。',32,'全唐诗/poet.song.68000.json','["便風五兩更悠悠，回望鄉閭烟霧浮。", "若問無情唯潁水，不來隨我到揚州。"]'),
('18feb5ec-2979-4635-86ae-c01b6c4f66db','病中謝張簿陽字韻詩','晁說之','宋','宋诗','song-poetry','','[]','藥有一君元長厚，病教五鬼逞狂陽。',32,'全唐诗/poet.song.68000.json','["藥有一君元長厚，病教五鬼逞狂陽。", "公詩可但能除瘧，萬痾都如律令忙。"]'),
('fa9b25d3-ff48-4616-a828-4e2fc1eda651','新合柏子香因誦皮日休坐久重焚柏子香輒以其香贈張簿','晁說之','宋','宋诗','song-poetry','','[]','柏子香清誰喜聞，五言句法更清芬。',32,'全唐诗/poet.song.68000.json','["柏子香清誰喜聞，五言句法更清芬。", "病仍春困在難久，遣向吟窗起暮雲。"]'),
('ee6b4a2c-5408-4199-a2f5-5e572163339e','依韻和張姑夫主簿','晁說之','宋','宋诗','song-poetry','','[]','即今時節總堪悲，寒食仍多雨意垂。',64,'全唐诗/poet.song.68000.json','["即今時節總堪悲，寒食仍多雨意垂。", "幾處壠頭飄斷紙，誰家碑額仆盤螭。", "江湖魚糝聊爲客，兒女來團難療饑。", "即見邊塵都掃盡，張公詩思更温其。"]'),
('42542f4e-184d-422b-8400-1ee1adc9fdbe','次韻張姑丈感舊  其一','晁說之','宋','宋诗','song-poetry','','[]','用舊爲邦不務新，舜琴何事有埃塵。',64,'全唐诗/poet.song.68000.json','["用舊爲邦不務新，舜琴何事有埃塵。", "焚香祕殿期王母，躍馬荒郊訪異人。", "爾保丘園爲爾土，吾憐盗賊本吾民。", "四愁不及一枝賦，誰許張衡社稷臣。"]'),
('16b4c342-77b5-4b2b-b880-aaeddab8e403','次韻張姑丈感舊  其二','晁說之','宋','宋诗','song-poetry','','[]','聞道江頭柳色新，可憐不識洛陽塵。',64,'全唐诗/poet.song.68000.json','["聞道江頭柳色新，可憐不識洛陽塵。", "景龍門外千鍾酒，葆籙宮前萬國人。", "此日凄凉徒費淚，即時興復愧遺民。", "浮家逃死知何處，羣寇頻招未肯臣。"]'),
('360db0b0-b6a5-4c2d-81fd-61251b0c67e8','奉紙百番於姑夫主簿并以謝四詩之寵','晁說之','宋','宋诗','song-poetry','','[]','怯見詩千首，慳持紙百番。',24,'全唐诗/poet.song.68000.json','["怯見詩千首，慳持紙百番。", "紙多詩剩到，費殺啞兒言。"]'),
('0c9760fd-cfaa-49ad-8764-823ce9825344','和出郭','晁說之','宋','宋诗','song-poetry','','[]','萬斛無多寧貯愁，不如留著寸心憂。',64,'全唐诗/poet.song.68000.json','["萬斛無多寧貯愁，不如留著寸心憂。", "怕聞天假漁陽騎，莫話春迷煬帝樓。", "出去暫能欣綠野，歸來還是夢滄洲。", "何人解賞鷦鷯賦，豈但工夫在句頭。"]'),
('2a47dada-2eaa-4c2b-be83-454e202c290c','蒙用諸人韻賦詩見貽復用韻謝之  其一','晁說之','宋','宋诗','song-poetry','','[]','昔人何事愛吾廬，燕雀鸞凰不並居。',64,'全唐诗/poet.song.68000.json','["昔人何事愛吾廬，燕雀鸞凰不並居。", "鄉社鳴琴欣日永，宦遊退鶂恨風初。", "迷樓賦罷夢何處，雙扇詩成淚不疏。", "莫問今朝多白髪，年時曾奏萬言書。"]'),
('e76831f0-3306-4d73-ad27-d132b650f554','蒙用諸人韻賦詩見貽復用韻謝之  其二','晁說之','宋','宋诗','song-poetry','','[]','一年幾相作新沙，鼙皷難開上苑花。',64,'全唐诗/poet.song.68000.json','["一年幾相作新沙，鼙皷難開上苑花。", "顧我何堪鳴玉佩，如君不得侍金華。", "隱身思傍懸壺樹，仙馭須求蒙頂茶。", "辜負麒麟功業志，只教人喚作詩家。"]'),
('fcfe2d35-221f-464d-9de7-f61bcade5cec','寓高郵禪居寺','晁說之','宋','宋诗','song-poetry','','[]','冰霜歲暮時，澤國更何爲。',48,'全唐诗/poet.song.68000.json','["冰霜歲暮時，澤國更何爲。", "菰米經寒澀，蘆門避亂宜。", "小人誇敵騎，志士憶京師。", "欲語殘僧笑，君歸未可期。"]'),
('f989858e-16f5-4d77-b853-3a6574e58b38','送二十二弟入浙','晁說之','宋','宋诗','song-poetry','','[]','世亂還家未有期，汝於何處望京師。',32,'全唐诗/poet.song.68000.json','["世亂還家未有期，汝於何處望京師。", "韋郎舊恨今新恨，細學南音寄我詩。"]'),
('13d35c34-a879-41ba-a9c6-d53dcf63c29e','災怪','晁說之','宋','宋诗','song-poetry','','[]','幾歲廟堂生物怪，一朝敵騎應天烖。',64,'全唐诗/poet.song.68000.json','["幾歲廟堂生物怪，一朝敵騎應天烖。", "頗聞北斗光芒見，未見東京消息來。", "志士此時憂國淚，將軍他日望鄉臺。", "世間如有嚴夫子，時命應須更可哀。"]'),
('1dac7a96-4047-4108-91fe-025d34fcd209','春書','晁說之','宋','宋诗','song-poetry','','[]','春色今朝見，羈人有好懷。',48,'全唐诗/poet.song.68000.json','["春色今朝見，羈人有好懷。", "暄風催酒熟，細雨送花門。", "魂夢迷梁苑，文章愧楚才。", "重湖烟艇去，月下採珠迴。"]'),
('91cdb2ed-e6f2-4299-8357-e30bb79e7b7b','送鍾離秀才往越州','晁說之','宋','宋诗','song-poetry','','[]','客游會稽去，惜哉無鏡湖。',48,'全唐诗/poet.song.68000.json','["客游會稽去，惜哉無鏡湖。", "雲迷神禹廟，鴉護季真居。", "五字君詩費，千秋我恨除。", "寄來休草草，涕淚憶皇都。"]'),
('9c27261b-8a3d-44bc-91b3-13a914e0aa81','依韻和鍾離秀才留别之作','晁說之','宋','宋诗','song-poetry','','[]','不脱征裘已到春，縱風横雨又經旬。',64,'全唐诗/poet.song.68000.json','["不脱征裘已到春，縱風横雨又經旬。", "期君獨步入京國，與我相逢在水濵。", "憤世何言詩濺淚，愁心自醉酒生塵。", "胡然乘興稽山去，爲問流觴曲水人。"]'),
('6476006c-357b-4169-8fae-8df0546235d2','一舍','晁說之','宋','宋诗','song-poetry','','[]','一舍終朝得自容，强如平昔慰途窮。',64,'全唐诗/poet.song.68000.json','["一舍終朝得自容，强如平昔慰途窮。", "爐心捜火分香燼，硯首融冰護筆鋒。", "愁極偶逢醽醁酒，夢回猶待景陽鍾。", "廟堂未肯圖興復，四海九州思會同。"]'),
('dce2c305-aa48-4485-a59c-8fe15234ec08','寄中遠越州旅舍兼簡宋倅','晁說之','宋','宋诗','song-poetry','','[]','自言無悶於兹久，何事今朝嘆息頻。',64,'全唐诗/poet.song.68000.json','["自言無悶於兹久，何事今朝嘆息頻。", "同病願逢閒話客，異鄉難得借書人。", "獨尋剡縣溪山去，厭見揚州花木新。", "茶寄卧龍何日到，貳車東宋世相親。"]'),
('4bc92868-fb87-4d7f-acfa-875b8abfdbf5','白鴈陂','晁說之','宋','宋诗','song-poetry','','[]','白鴈陂前淮海思，今朝淮海鴈相隨。',32,'全唐诗/poet.song.68000.json','["白鴈陂前淮海思，今朝淮海鴈相隨。", "固知憐我飄零甚，忘却青嵩碧潁時。"]'),
('e8e38b77-1c0a-43e6-9e08-11878dc64846','孤鴈','晁說之','宋','宋诗','song-poetry','','[]','風驅雲卷一身微，慕侣高高急急飛。',32,'全唐诗/poet.song.68000.json','["風驅雲卷一身微，慕侣高高急急飛。", "未許高人能遠遁，梁王池館故同歸。"]'),
('d2619069-d5a8-46c0-96cb-72330339e4e8','即事','晁說之','宋','宋诗','song-poetry','','[]','抛盡圖書避俗塵，楞伽讀罷與誰親。',64,'全唐诗/poet.song.68000.json','["抛盡圖書避俗塵，楞伽讀罷與誰親。", "波濤遠嶼羈遊夢，風雨幽齋默坐身。", "盞底不堪留酒客，句頭何敢惱詩人。", "和詩送酒俱休問，只恐歸期誤此春。"]'),
('b56479cf-0b8e-4d59-bee7-89f6e0322416','自賦親字韻','晁說之','宋','宋诗','song-poetry','','[]','久息人間車馬塵，香殘紅晻自相親。',64,'全唐诗/poet.song.68000.json','["久息人間車馬塵，香殘紅晻自相親。", "嘗看海散千波月，亦睹蓮開百葉身。", "清世豈無逃俗客，白頭不是插花人。", "明朝若便西歸去，嶽寺花遲留得春。"]'),
('25982de0-9846-4958-bfbd-50e590166f09','伏蒙二十二叔俯和親字韻詩不勝欽歎輒復用韻上呈','晁說之','宋','宋诗','song-poetry','','[]','樂難得似新篇樂，親莫親如同祖親。',64,'全唐诗/poet.song.68000.json','["樂難得似新篇樂，親莫親如同祖親。", "熟身典刑平世事，恭聞詩禮少年身。", "五言自發曹劉興，七澤誰知魯衛人。", "李白酒樓今在否，不堪回首小園春。"]'),
('e2bae2b7-7668-44bd-bf50-6aa4be0c38a0','子强賦詩還張簿與予唱和詩卷復用韻謝之','晁說之','宋','宋诗','song-poetry','','[]','同時先後避風塵，異縣相看意更親。',64,'全唐诗/poet.song.68000.json','["同時先後避風塵，異縣相看意更親。", "不武可知難陷陣，片文安得易容身。", "游兵去喜添新恨，燕子來驚問故人。", "何處有詩能自勝，賴君揖客賞陽春。"]'),
('3c024668-24f0-4832-a90c-0ea3bdc9df88','高郵忽見叔易嵩山下所寄絕句次韻和之舊所作不次韻也','晁說之','宋','宋诗','song-poetry','','[]','我憶故人頭更白，故人夢我眼猶青。',32,'全唐诗/poet.song.68000.json','["我憶故人頭更白，故人夢我眼猶青。", "重湖疊浪君知否，正似當年翻水經。"]'),
('c9ff4dc7-e667-4c9d-9e5a-7e53699b9b46','痛心','晁說之','宋','宋诗','song-poetry','','[]','爲問誰今有好懷，園林春色不須來。',64,'全唐诗/poet.song.68000.json','["爲問誰今有好懷，園林春色不須來。", "王孫草向荒城短，驛使梅因戰陣回。", "但道邊塵迷上苑，不聞漢詔出中臺。", "痛心一日復一日，何日皇威遍九垓。"]'),
('da666325-2b3a-42e8-92bc-e1a1228cdcf5','感時','晁說之','宋','宋诗','song-poetry','','[]','千里逋亡蒲柳身，淚痕長短送殘春。',64,'全唐诗/poet.song.68000.json','["千里逋亡蒲柳身，淚痕長短送殘春。", "望惟書問平安到，樂在兒童讀誦聲。", "桑海恩深變未得，龍虵躁甚起何因。", "即看廊廟申威令，爲問勤王有幾人。"]'),
('5505f416-f1f8-494c-aa98-16d31b2f3f7d','秋懷','晁說之','宋','宋诗','song-poetry','','[]','草木衰殘意，關河離别情。',24,'全唐诗/poet.song.68000.json','["草木衰殘意，關河離别情。", "秋風已如此，况復更論兵。"]'),
('9f3bcf61-d579-47e7-99e2-443623996588','秋書','晁說之','宋','宋诗','song-poetry','','[]','秋爲棗多暑，天因禾未霜。',24,'全唐诗/poet.song.68000.json','["秋爲棗多暑，天因禾未霜。", "吁嗟爾勍敵，宜亦畏皇綱。"]'),
('a08621c6-299a-4108-856b-dff748553672','有客喜予爲江東之役者輒效齊梁體','晁說之','宋','宋诗','song-poetry','','[]','翡翠鈎寒陪曉月，珊瑚枕浄揖高丘。',32,'全唐诗/poet.song.68000.json','["翡翠鈎寒陪曉月，珊瑚枕浄揖高丘。", "人間聚散何須問，夢斷西陵更送秋。"]'),
('eff63b04-67d7-4899-ba17-7e2fd71132cc','避地','晁說之','宋','宋诗','song-poetry','','[]','久欲爲僧避世喧，況當寰海正飛翻。',32,'全唐诗/poet.song.68000.json','["久欲爲僧避世喧，況當寰海正飛翻。", "五臺自有天台院，處處流通玄妙門。"]'),
('3a8c67a9-7b13-4223-9721-e67da670cbef','雨中即事','晁說之','宋','宋诗','song-poetry','','[]','寥寥兹夏晚，秋韻已蕭然。',96,'全唐诗/poet.song.68000.json','["寥寥兹夏晚，秋韻已蕭然。", "風雨疏籬外，詩書曲几前。", "道心勤自厲，愁緒每相牽。", "秦樹連烽火，吳鞵落海壖。", "不能先到縣，豈待晚歸田。", "丹劑誰能遘，金爐試得烟。", "去天真一百，奏牘舊三千。", "藁草紛盈架，誰令宿瘤研。"]'),
('2655e32e-d6e6-403a-885f-5109a5e1f979','感事','晁說之','宋','宋诗','song-poetry','','[]','長鯨江海尚翻波，欲濟無航可奈何。',64,'全唐诗/poet.song.68000.json','["長鯨江海尚翻波，欲濟無航可奈何。", "物象蕭條秋序薄，人生感慨腐儒多。", "翠輿不見邊塵起，旅鴈能隨漢月過。", "七日之誅今幾日，猶煩樂職在中和。"]'),
('d0d9427d-f496-4c0d-afde-bb3f0a5dbefd','依韻和袁秀才見贈之作','晁說之','宋','宋诗','song-poetry','','[]','志士相逢屬暮年，淚如有盡恨無邊。',64,'全唐诗/poet.song.68000.json','["志士相逢屬暮年，淚如有盡恨無邊。", "空城鬼火隨胡騎，滿驛蓴絲倚楚天。", "愁外誰知餐玉術，醉來自詠釣竿篇。", "夫君心事有如此，何日騎鯨出九淵。"]'),
('c1551cbd-2e7f-4274-b894-649b225a5f6a','再和','晁說之','宋','宋诗','song-poetry','','[]','不知今歲是何年，鐵馬胡兒遶日邊。',64,'全唐诗/poet.song.68000.json','["不知今歲是何年，鐵馬胡兒遶日邊。", "雖有廟堂能格帝，更求巖穴與談天。", "廢興誰識詩千首，消長難忘易二篇。", "卧雪諸孫心事苦，重湖頗愧汨羅淵。"]'),
('fc687d5c-fb51-4acc-8c07-0f7fd534273a','旅懷','晁說之','宋','宋诗','song-poetry','','[]','春來歸計尚茫然，往事知非莫問天。',64,'全唐诗/poet.song.68000.json','["春來歸計尚茫然，往事知非莫問天。", "九牧勤王誰誤國，千門受箭悔開邊。", "立朝不得當言路，在野無從自行田。", "誰念龍鍾湖海畔，苦遭風雨日留連。"]'),
('99ef7c11-3a93-4adb-85bf-c8a16aef5a6a','因客談湖中大珠作','晁說之','宋','宋诗','song-poetry','','[]','既無武略擒渠帥，又乏文章騁國才。',32,'全唐诗/poet.song.68000.json','["既無武略擒渠帥，又乏文章騁國才。", "甓社湖中有明月，可憐不肯入君懷。"]'),
('393e89dc-d0d7-498b-ad32-8d3e9a206b05','高郵書事','晁說之','宋','宋诗','song-poetry','','[]','飄然去國到他鄉，晝晷難移夜漏長。',64,'全唐诗/poet.song.68000.json','["飄然去國到他鄉，晝晷難移夜漏長。", "自恨旅懷多偪仄，誰教春夢遠顛狂。", "舒虹蕩月明珠過，積雪迷雲小稻香。", "雙絕兹焉甘作客，只慚不得去勤王。"]'),
('f337d219-3ffb-494a-aa73-c43dceec5f14','三月五日南京梢工來報船經金人殘毁之後尚有書籍存者且以二詩爲信忽睹高仲夷唱和詩不勝感嘆輒用其韻識其事率同賦','晁說之','宋','宋诗','song-poetry','','[]','桃花源上避秦人，豈料漁舟見此身。',64,'全唐诗/poet.song.68000.json','["桃花源上避秦人，豈料漁舟見此身。", "胡虜殺人掊玉帛，簡編破櫝委泥塵。", "誰施骨肉死生惠，只有皇天后土仁。", "可保斯文猶未墮，廟堂宜亦用儒臣。"]'),
('0d366d2e-a1c4-4c7d-8ddd-2cc548cac8b2','和高二偶作長句','晁說之','宋','宋诗','song-poetry','','[]','流落歸來少故人，婆娑白髮强容身。',64,'全唐诗/poet.song.68000.json','["流落歸來少故人，婆娑白髮强容身。", "雷霆能斷王敦首，宇宙猶多庾亮塵。", "以國與盟非所志，在邊不戰豈其仁。", "兼資文武唯高子，誰識中原有虎臣。"]'),
('f0d97100-b860-4682-a97e-dcdac132678e','次韻飲酒','晁說之','宋','宋诗','song-poetry','','[]','舒懷來遊地，悲歡付與君。',48,'全唐诗/poet.song.68000.json','["舒懷來遊地，悲歡付與君。", "深慚偏愛酒，有客總能文。", "春去欣搜粟，秋來漫護軍。", "何如東里老，憨腹醉醺醺。"]'),
('ef284c77-e073-41f7-ac04-ffc34dc24d2d','淮海二絕  其一','晁說之','宋','宋诗','song-poetry','','[]','卜錢簇簇怯單單，小婦揚州橋上看。',32,'全唐诗/poet.song.68000.json','["卜錢簇簇怯單單，小婦揚州橋上看。", "拜鬼求神春更恨，不堪風雨作花寒。"]'),
('f0ef69b2-713e-4575-ad68-7e53ebc3c37a','淮海二絕  其二','晁說之','宋','宋诗','song-poetry','','[]','莫問揚州桃葉生，渡江今日得風晴。',32,'全唐诗/poet.song.68000.json','["莫問揚州桃葉生，渡江今日得風晴。", "長沙子弟更相笑，上到隋堤便住營。"]'),
('113eaa5f-bef0-4069-a0d0-99d94b2a2c90','飲酒','晁說之','宋','宋诗','song-poetry','','[]','與君厭苦洛陽塵，望斷今朝那得親。',64,'全唐诗/poet.song.68000.json','["與君厭苦洛陽塵，望斷今朝那得親。", "爲問紅旗白馬客，何如左蔗右螯人。", "醉來無意誅讒鬼，醒後傾身事麴神。", "辜負景鐘勳業志，杜康廟裏作功臣。"]'),
('650c1597-a723-4cc9-8645-56894782b710','有喜','晁說之','宋','宋诗','song-poetry','','[]','世事獨知誰謂然，衣冠直待見戈鋋。',64,'全唐诗/poet.song.68000.json','["世事獨知誰謂然，衣冠直待見戈鋋。", "是非在彼從三刖，忠孝於身必兩全。", "問饍綵衣還仆地，感時諫疏欲干天。", "羶胡猖獗須臾爾，仁澤昭陵億萬年。"]'),
('a412347f-c21d-4b34-aecd-ef2ffc242f07','尚憂','晁說之','宋','宋诗','song-poetry','','[]','建康庾令豈多愁，未識皇恩覆九州。',64,'全唐诗/poet.song.68000.json','["建康庾令豈多愁，未識皇恩覆九州。", "初訝單于陵大漢，重驚玁狁犯宗周。", "今朝不見安邊策，前日空多定遠侯。", "江海張公漂泊久，即看讜議動前旒。"]'),
('ad48641e-c901-4e6d-86c1-cad2c0e9cc1b','謝乾明滋老送炒團','晁說之','宋','宋诗','song-poetry','','[]','蓼花散畔輕盈意，炒米團邊笑語親。',32,'全唐诗/poet.song.68000.json','["蓼花散畔輕盈意，炒米團邊笑語親。", "多謝稻畦磨衲老，十方撮聚戲閒人。"]'),
('79045132-be64-4145-a457-5f2dffb0516b','寄焦山成老高郵滋老','晁說之','宋','宋诗','song-poetry','','[]','他鄉卧病白頭翁，孤憤猶存涕淚中。',64,'全唐诗/poet.song.68000.json','["他鄉卧病白頭翁，孤憤猶存涕淚中。", "竹葉有陰唯待月，蓮花自殞不須風。", "明朝白帝行商令，何日黄麾入漢宮。", "一死等閒無足惜，道人第一莫談空。"]'),
('0bd03823-1347-430a-ac8c-79e240afdc3d','私願','晁說之','宋','宋诗','song-poetry','','[]','胡塵未動朔雲浮，行在多懽見小侯。',32,'全唐诗/poet.song.68000.json','["胡塵未動朔雲浮，行在多懽見小侯。", "願保三冬資我樂，更無一事使人愁。"]'),
('1306ffd3-fe1f-47a9-81e7-374acda07a2b','新志','晁說之','宋','宋诗','song-poetry','','[]','前日徒嗟與世違，從今絕世心事微。',64,'全唐诗/poet.song.68000.json','["前日徒嗟與世違，從今絕世心事微。", "彌陀印裏一身重，梵網經中萬古非。", "元亮胡然兹漫浪，遺民有侣便因依。", "欣予不負遂初賦，寄愧於顔得所歸。"]'),
('34dffb1a-c957-4f66-b506-d66568b3bf33','病中思建茶不可得因作呈胡季和','晁說之','宋','宋诗','song-poetry','','[]','新政勤勞儉素中，建溪千焙一毫供。',64,'全唐诗/poet.song.68000.json','["新政勤勞儉素中，建溪千焙一毫供。", "人知廉恥苞苴減，運屬危原丘壑空。", "慣以槍旗論勝負，果勞甲胄歷危凶。", "不登王會篇中物，便好從今永絕蹤。"]'),
('4bc06117-b913-47ae-bb48-375c7e676f69','謝季和朝議牡丹','晁說之','宋','宋诗','song-poetry','','[]','侍無童子懶焚香，君送花來恨便忘。',32,'全唐诗/poet.song.68000.json','["侍無童子懶焚香，君送花來恨便忘。", "盡日清芬與風競，熏爐漫使令君狂。"]'),
('1a343db7-d4ac-4950-9ec4-00e8f4829618','静','晁說之','宋','宋诗','song-poetry','','[]','蕭然一室静，樂只復何如。',48,'全唐诗/poet.song.68000.json','["蕭然一室静，樂只復何如。", "子晉吹笙罷，孫登長嘯餘。", "兒童奔入學，賓客遠回車。", "更願干戈息，殘年老敝廬。"]'),
('57db6825-0e25-4477-870b-8dbbaefa5937','因觀劉侍讀姚祕丞孫處士平山堂詩寄歐陽公唱和作絕句','晁說之','宋','宋诗','song-poetry','','[]','醉公認得揚州路，堂上平山列酒罇。',32,'全唐诗/poet.song.68000.json','["醉公認得揚州路，堂上平山列酒罇。", "後日公榮來酩酊，賦詩可但屬姚孫。"]'),
('d662c3ec-f28d-4685-b0e7-8fd02268c4cf','予以四韻記陸大夫三高圖自謂能省句矣後作絕句增畫筆之妙','晁說之','宋','宋诗','song-poetry','','[]','馬解馱經度碧空，便令王許伴支公。',32,'全唐诗/poet.song.68000.json','["馬解馱經度碧空，便令王許伴支公。", "山童野僕立如石，忘却儂曾在會中。"]'),
('d1583ea9-9537-4dec-b681-76f25f8df1c3','感嘆二首  其一','晁說之','宋','宋诗','song-poetry','','[]','險阻空千里，都城整六師。',48,'全唐诗/poet.song.68000.json','["險阻空千里，都城整六師。", "憂心常忽忽，春日獨遲遲。", "未見忠良出，休言昏亂爲。", "白頭難作客，日日問歸期。"]'),
('53680b8e-17e6-41cb-998b-cb4096699aa0','感嘆二首  其二','晁說之','宋','宋诗','song-poetry','','[]','龜筮總茫茫，風塵慘大荒。',48,'全唐诗/poet.song.68000.json','["龜筮總茫茫，風塵慘大荒。", "丹心能許國，旅力愧勤王。", "若使官兵衛，猶能干戚揚。", "叩閽陳膽策，折翅亦難将。"]'),
('e783e44a-8e0c-4f8a-b6b2-335d0e2e72fb','感事  其一','晁說之','宋','宋诗','song-poetry','','[]','玉仙鴻福最先春，今日枝頭壓戰塵。',64,'全唐诗/poet.song.68000.json','["玉仙鴻福最先春，今日枝頭壓戰塵。", "千里無非逃難客，二年誰是看花人。", "偶來水國充饑易，況有儒冠請益頻。", "天地雖窮吾道在，圖書焚盡更重新。"]'),
('a0666ca9-7fb8-4671-8bc1-a7c4619b808d','感事  其二','晁說之','宋','宋诗','song-poetry','','[]','青春住莫過，伴我恨無窮。',48,'全唐诗/poet.song.68000.json','["青春住莫過，伴我恨無窮。", "家在風塵裏，客來兵刃中。", "小人真樂禍，大吏競興戎。", "暫適义魚市，長慚斬将功。"]'),
('07123166-e2db-4a71-9679-4acfcd94a9da','斬将','晁說之','宋','宋诗','song-poetry','','[]','斬將斬誰將，今多樊愛能。',48,'全唐诗/poet.song.68000.json','["斬將斬誰將，今多樊愛能。", "庶幾威國俗，聊可讋邊僧。", "縛虎何堪責，騎猪尚不勝。", "将軍如自治，盪宼有先登。"]'),
('2deadc27-3c26-4e35-a1bf-a4a6dc75e49f','感嘆','晁說之','宋','宋诗','song-poetry','','[]','消息沈沈當下國，風塵漠漠望中都。',32,'全唐诗/poet.song.68000.json','["消息沈沈當下國，風塵漠漠望中都。", "平生鉛槧胡塵裏，不免從今讀誤書。"]'),
('b195f5c2-241e-4273-88a0-287f6de09cb3','偶見新花呈季和','晁說之','宋','宋诗','song-poetry','','[]','寂寥仍抱病，風雨尚征師。',24,'全唐诗/poet.song.68000.json','["寂寥仍抱病，風雨尚征師。", "幾許野花發，無窮客淚垂。"]'),
('b8fbdcb4-672e-4363-8511-33c15c792991','胡季和送江梅山茶來','晁說之','宋','宋诗','song-poetry','','[]','山茶有色笑江梅，無色江梅謝不才。',64,'全唐诗/poet.song.68000.json','["山茶有色笑江梅，無色江梅謝不才。", "莫言無色無才思，幾許才從色上來。", "天際素娥能綽約，人間紅袖恨徘徊。", "誰将玉質酡顔醉，絳雪朱絲解不開。"]'),
('1d2c2639-8da4-4f8c-b1a0-0713324a0488','晚日臨水得此句呈季和先爲公家池上明日之遊也','晁說之','宋','宋诗','song-poetry','','[]','客子思歸悔遠遊，曾波新綠戀汀洲。',32,'全唐诗/poet.song.68000.json','["客子思歸悔遠遊，曾波新綠戀汀洲。", "庾郎得暇爲春賦，定是春來未肯愁。"]'),
('1432e719-9808-4b23-81e0-1f74745f50e0','高郵人物絕句二首  其一','晁說之','宋','宋诗','song-poetry','','[]','高郵崔監富詩書，筆力雄豪與世疏。',32,'全唐诗/poet.song.68000.json','["高郵崔監富詩書，筆力雄豪與世疏。", "不是魏公公道在，定垂白髪老菰蒲。"]'),
('e6b6b57f-7f90-4190-9062-49211cf6d893','高郵人物絕句二首  其二','晁說之','宋','宋诗','song-poetry','','[]','高郵少年有王令，豪氣雄才海內無。',32,'全唐诗/poet.song.68000.json','["高郵少年有王令，豪氣雄才海內無。", "當日談兵今可用，只愁遺像是癯儒。"]'),
('a72ac55f-1135-4000-8698-9d0ef61b333e','次韻二十二弟謝胡以純餉米','晁說之','宋','宋诗','song-poetry','','[]','十日饑膓吳越客，空将苦淚濕寒烟。',64,'全唐诗/poet.song.68000.json','["十日饑膓吳越客，空将苦淚濕寒烟。", "喫虚兄弟嗟同病，任死圖書愧滿船。", "飲露求肥真漫與，耕雲卒歲更堪憐。", "胡家清德今猶爾，顧我窮途一惘然。"]'),
('a6698c30-d52c-494a-9056-910109d80423','因雞鳴不響厲而作','晁說之','宋','宋诗','song-poetry','','[]','腸斷之雞不解鳴，要須煩汝報升平。',32,'全唐诗/poet.song.68000.json','["腸斷之雞不解鳴，要須煩汝報升平。", "故知二虜非劉石，只是中原無祖生。"]'),
('804c9dbe-ae9d-4ad4-9fca-e3ba0e02df5f','别一上人','晁說之','宋','宋诗','song-poetry','','[]','同遊不二境，却有别離情。',24,'全唐诗/poet.song.68000.json','["同遊不二境，却有别離情。", "爲日添香火，中原正用兵。"]'),
('a66581ca-d875-49bc-b434-541ebac8093e','夜聞鐘惜其不響','晁說之','宋','宋诗','song-poetry','','[]','宋都爲客喜還驚，無數霜天歸鴈横。',32,'全唐诗/poet.song.68000.json','["宋都爲客喜還驚，無數霜天歸鴈横。", "夜半鐘聲何太啞，由來石霣五無聲。"]'),
('88049dd0-c75d-4dba-9f5b-a89b1cde8cf4','冬至前一日至穀熟遇趙子和大夫','晁說之','宋','宋诗','song-poetry','','[]','盜賊羌胡逐隊行，幾家避難到荒城。',64,'全唐诗/poet.song.68000.json','["盜賊羌胡逐隊行，幾家避難到荒城。", "也知明日當長至，便望今年可太平。", "京國笙歌無寂寞，将軍旗皷耐縱横。", "鈍菴居士全非鈍，先我驅車百感生。"]'),
('2f1a4675-b6cb-481d-b4e9-13159ec38a2e','冬至日塗中','晁說之','宋','宋诗','song-poetry','','[]','海角沙塲過冬至，未如今日最傷情。',64,'全唐诗/poet.song.68000.json','["海角沙塲過冬至，未如今日最傷情。", "孝王池畔憂戎壘，煬帝河邊嘆楚兵。", "萬壽獻觴身不與，百城和議淚空横。", "明年高會知何處，擊磬焚香畢此生。"]'),
('138c9237-d95f-49da-8d9c-73b9e84c3f20','後十一月十一日夜宿柳子鎮','晁說之','宋','宋诗','song-poetry','','[]','早歲無知到柳橋，黄流澎湃客雄豪。',32,'全唐诗/poet.song.68000.json','["早歲無知到柳橋，黄流澎湃客雄豪。", "自從道路無形勢，今日睢陽益漫勞。"]'),
('f8f75518-cbf6-45ca-9430-6f9fcf759da1','有感','晁說之','宋','宋诗','song-poetry','','[]','帝室中興運更賒，如聞廟議尚堪嗟。',64,'全唐诗/poet.song.68000.json','["帝室中興運更賒，如聞廟議尚堪嗟。", "和親費盡三公力，兵革傷殘百姓家。", "解使亞夫營細柳，却教賈誼傅長沙。", "顧予豈是奔亡者，獨抱寒枝愧暝鴉。"]'),
('0140894e-a4e2-4107-af7f-bf7612249ea9','遠戎','晁說之','宋','宋诗','song-poetry','','[]','遠戎深入震中原，爲問何人守薊門。',64,'全唐诗/poet.song.68000.json','["遠戎深入震中原，爲問何人守薊門。", "功業論天初已繆，和親割地竟難存。", "将軍不戰喜三北，逐客何堪厭七奔。", "尚有微誠思獻策，千行血淚叩天閽。"]'),
('c95c7ad2-ba80-40c1-bc44-2e71e693597d','予三十年前爲宿州教授今塗次見諸生一二人','晁說之','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','滄海枯來失夜光，泰山走去誤朝陽。',32,'全唐诗/poet.song.68000.json','["滄海枯來失夜光，泰山走去誤朝陽。", "可憐憔悴蒼顔客，曾是呻吟黄卷郎。"]'),
('382bcd99-5b35-47d2-8331-ddfeb570fae2','感事','晁說之','宋','宋诗','song-poetry','','[]','王師真不戰，天險易摧殘。',48,'全唐诗/poet.song.68000.json','["王師真不戰，天險易摧殘。", "盡室少徒步，朝饑夜更寒。", "胡塵無甸服，漢月照長安。", "凶悍仍無禮，嗔予不守官。"]'),
('048e4cc4-0224-4037-bafc-610f1ee93a8a','避地','晁說之','宋','宋诗','song-poetry','','[]','避地半徒步，身存亦幸哉。',48,'全唐诗/poet.song.68000.json','["避地半徒步，身存亦幸哉。", "有詩慚寡和，無酒愧空杯。", "重鎮求須與，親王去未回。", "吾生本多樂，今日但餘哀。"]'),
('84844da1-5bdb-4be8-8574-7539596ad82b','途次憶故居','晁說之','宋','宋诗','song-poetry','','[]','自喜白髯翁，深居看歲窮。',48,'全唐诗/poet.song.68000.json','["自喜白髯翁，深居看歲窮。", "雪迷石嶺上，月在草堂中。", "樵客曉來市，田家夜半舂。", "豈期胡騎到，無地得相容。"]'),
('d32ec2ed-172c-4835-aa25-a8dd0f4ee6ed','旅舍朝雞','晁說之','宋','宋诗','song-poetry','','[]','獨抱微誠人不知，山公啟事定何施。',32,'全唐诗/poet.song.68000.json','["獨抱微誠人不知，山公啟事定何施。", "鳴雞本候海潮信，不爲金門上馬時。"]'),
('f688d7c0-d668-49b1-823e-057d4864168a','聞鐘五更起行','晁說之','宋','宋诗','song-poetry','','[]','野寺鐘聲報曉寒，征人方夢到長安。',32,'全唐诗/poet.song.68000.json','["野寺鐘聲報曉寒，征人方夢到長安。", "茫然塗路知難易，兩避胡塵一歲殘。"]'),
('8cd22ef1-0788-4694-9128-134dd17a4ee9','痛恨','晁說之','宋','宋诗','song-poetry','','[]','丞相開邊靡有它，中原要復識干戈。',64,'全唐诗/poet.song.68000.json','["丞相開邊靡有它，中原要復識干戈。", "百年身事今如此，萬里胡塵可奈何。", "隴上健兒嗟不見，洛陽女子恨偏多。", "朝朝上食陵頭否，腸斷東巡白帝歌。"]'),
('230c38e3-ac0f-4560-a6d2-8b692b6f42b1','書事','晁說之','宋','宋诗','song-poetry','','[]','逋亡今五月，百感若爲情。',48,'全唐诗/poet.song.68000.json','["逋亡今五月，百感若爲情。", "馬借從軍沒，舟疑破浪輕。", "奏書無路達，故里有誰耕。", "戴笠蓑衣雨，猶憐李少卿。"]'),
('cb177707-d880-47e3-b6ae-1fa288e75724','追感','晁說之','宋','宋诗','song-poetry','','[]','潁水箕山已卜休，忽逢新政悞恩收。',64,'全唐诗/poet.song.68000.json','["潁水箕山已卜休，忽逢新政悞恩收。", "白頭不識爲郎嘆，黄帽難供作客愁。", "何事京師書信斷，漫從澤國稻粱謀。", "和親莫恃河爲界，百騎東來破一州。"]'),
('dfd95885-2aac-4253-b4c6-bcdcc3f6dd72','冒雨西行','晁說之','宋','宋诗','song-poetry','','[]','敗堤留沮洳，苦雨劇泥塗。',48,'全唐诗/poet.song.68000.json','["敗堤留沮洳，苦雨劇泥塗。", "婢子求芒屫，童兒競地爐。", "能甘逐客分，但恥潰兵俱。", "何必滔天水，兹爲縱壑魚。"]'),
('db2f8e4c-9ed1-4780-91e3-b5d954fb97af','問雪','晁說之','宋','宋诗','song-poetry','','[]','此雪問誰偏最喜，羯胡得意逞天驕。',64,'全唐诗/poet.song.68000.json','["此雪問誰偏最喜，羯胡得意逞天驕。", "黄河穩渡魚龍静，白馬增光劍甲豪。", "我有玉鈐今震疊，爾看瑤璧莫呼號。", "何妨特勅近臣燕，腸斷金罇費獨謡。"]'),
('6f446bc0-0c08-41e4-99c9-5577248b9a3e','痛恨','晁說之','宋','宋诗','song-poetry','','[]','胡兒直犯洛陽宮，藹藹園陵指點中。',32,'全唐诗/poet.song.68000.json','["胡兒直犯洛陽宮，藹藹園陵指點中。", "殄滅四夷心不遂，裕陵蕭瑟獨悲風。"]'),
('ea095704-17fd-4f1e-b900-38b1518aeac1','夜來枕上得四絕句因視王性之謝其相訪也末専爲渠作  其一','晁說之','宋','宋诗','song-poetry','','[]','不待功成逐赤松，腐儒畢竟若爲功。',32,'全唐诗/poet.song.68000.json','["不待功成逐赤松，腐儒畢竟若爲功。", "田園破碎風塵裏，腸斷當年夜雨舂。"]'),
('554f9ed2-1128-4023-b427-b2f3d68996be','夜來枕上得四絕句因視王性之謝其相訪也末専爲渠作  其二','晁說之','宋','宋诗','song-poetry','','[]','皇祚中興徹九垓，不煩猶道宋王臺。',32,'全唐诗/poet.song.68000.json','["皇祚中興徹九垓，不煩猶道宋王臺。", "歸鴻特比常年少，應戀黄麾不忍來。"]'),
('47948c7f-360c-40f9-ae43-a305fb12d7ae','夜來枕上得四絕句因視王性之謝其相訪也末専爲渠作  其三','晁說之','宋','宋诗','song-poetry','','[]','三川皆震大災異，汴水絕流上帝仁。',32,'全唐诗/poet.song.68000.json','["三川皆震大災異，汴水絕流上帝仁。", "不使六龍遠巡幸，興王蒨地福重新。"]'),
('d3fc163b-c6b5-4c1b-a56d-663a1af809a1','夜來枕上得四絕句因視王性之謝其相訪也末専爲渠作  其四','晁說之','宋','宋诗','song-poetry','','[]','井臼無供戢羽貧，未知何地老容身。',32,'全唐诗/poet.song.68000.json','["井臼無供戢羽貧，未知何地老容身。", "更無一卷文書在，七錄家藏許卜鄰。"]'),
('cd4c0bb5-cd82-4c17-8a4a-d35354cca546','拭目','晁說之','宋','宋诗','song-poetry','','[]','拭目中興宜碌碌，褊心觸事獨遲遲。',64,'全唐诗/poet.song.68000.json','["拭目中興宜碌碌，褊心觸事獨遲遲。", "劉琨祖逖無由見，鄴下關中何所之。", "萬里耕桑仁德在，九天雨露廟堂滋。", "龍鍾只合歸田去，猶解重吟采芑詩。"]'),
('5702c73d-9762-4b9f-8552-0e4d861d912d','自寛','晁說之','宋','宋诗','song-poetry','','[]','無奈愁何强自寛，細将心事樂江干。',64,'全唐诗/poet.song.68000.json','["無奈愁何强自寛，細将心事樂江干。", "新詩時向夢中得，明月多從枕上看。", "吾道若存生有益，君恩可報死何難。", "五陵祥瑞煙何在，何日端門朝百官。"]'),
('5d97fee2-9932-41c6-9367-af9ed817170b','贈儀真天寧訥老','晁說之','宋','宋诗','song-poetry','','[]','若說真州水，時人不道甘。',24,'全唐诗/poet.song.68000.json','["若說真州水，時人不道甘。", "天寧老誰識，板齒毛鬖鬖。"]'),
('5bf09d0f-aab3-4dea-b78f-a19411cac002','贈筆處士屠希','晁說之','宋','宋诗','song-poetry','','[]','屠希祖是屠牛坦，今日却屠秋兔毫。',32,'全唐诗/poet.song.68000.json','["屠希祖是屠牛坦，今日却屠秋兔毫。", "自識有心三副健，可憐無副一心勞。"]'),
('4d46b526-ffb2-4afb-980f-46fcbec8ff1c','贈筆處士曹忠','晁說之','宋','宋诗','song-poetry','','[]','葦管予何愛，輕圓稱白毫。',24,'全唐诗/poet.song.68000.json','["葦管予何愛，輕圓稱白毫。", "固知今獨妙，舊數浙西曹。"]'),
('34005dc1-1599-49ba-9f19-9198f9e94dcd','知宗節使臨渡江至金陵送蠟梅來','晁說之','宋','宋诗','song-poetry','','[]','江北江南疊鼓催，清香清淚各徘徊。',32,'全唐诗/poet.song.68000.json','["江北江南疊鼓催，清香清淚各徘徊。", "知君清德用無盡，棹欲移時留蠟梅。"]'),
('c0e512f6-5a3a-4b32-862e-51d3e42bc2f7','和許嵩老江上舟災','晁說之','宋','宋诗','song-poetry','','[]','火德孝嚴嗟掠虚，祝融江面怒心餘。',128,'全唐诗/poet.song.68000.json','["火德孝嚴嗟掠虚，祝融江面怒心餘。", "千尋赤尾干堯曆，百仞紅鱗滅禹書。", "丙穴烘天誰得及，丁翁奔日更難如。", "文昌右轄知幾早，無妄之災不我居。", "平生易象論孤虚，富貴功名不願餘。", "政府頻垂憂國淚，梵宮獨看竺乾書。", "衆驚赤壁復焚爾，自擅三禪早晏如。", "回首焚軀并溺骨，何爲不早傍禪居。"]'),
('54ad3d4b-2a16-4179-8d98-ebccc50e849e','再和  其一','晁說之','宋','宋诗','song-poetry','','[]','不肯喧喧奏子虚，何心江上惜三餘。',64,'全唐诗/poet.song.68000.json','["不肯喧喧奏子虚，何心江上惜三餘。", "陸渾火但無家計，宣榭灾宜費圖書。", "每恨血鱗能雨若，何堪脱角去焚如。", "知公輔弼關心處，不比他人樂退居。"]'),
('46007c7a-83bd-41e7-8b05-64aa3cb120f5','再和  其二','晁說之','宋','宋诗','song-poetry','','[]','頃歲官嘗傍紫虚，嵩雲緱月笑談餘。',64,'全唐诗/poet.song.68000.json','["頃歲官嘗傍紫虚，嵩雲緱月笑談餘。", "惟知猿鶴乞骸疏，不錄熊羆諫獵書。", "遊寺但知能自與，焚舟不復問何如。", "巖廊德量誰能比，大令山陰難並居。"]'),
('faca68bb-d66a-418b-9cfe-67baa8e7a01a','夜雨不少住枕上作','晁說之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','幾年飄泊敢何求，甘作傖公對楚囚。',64,'全唐诗/poet.song.68000.json','["幾年飄泊敢何求，甘作傖公對楚囚。", "風轉榮光新輦道，雨無時節舊揚州。", "陸公奏議同誰恨，屈子離騷亦獨愁。", "歲暮長江癃病客，飄飄荆渚覓同游。"]'),
('7ba306c7-b4fc-43c4-b09b-0e7b60c0d970','莫道','晁說之','宋','宋诗','song-poetry','','[]','莫道飄零天一涯，安時自勝孰興嗟。',64,'全唐诗/poet.song.68000.json','["莫道飄零天一涯，安時自勝孰興嗟。", "已春庭宇不留雪，逢閏園林無早花。", "素履欵遊禪老室，白頭慣見富人家。", "胡然齊趙兵戈起，自是司戎好盜誇。"]'),
('0dbc4fe3-b382-4940-9d29-01a9336f2f6d','晝寢看壁上陳希夷','晁說之','宋','宋诗','song-poetry','','[]','昔人辛苦處難追，慵懶多閒自有奇。',32,'全唐诗/poet.song.68000.json','["昔人辛苦處難追，慵懶多閒自有奇。", "睡著不知春晝永，壁間圖像傲希夷。"]'),
('04190fef-d1ec-4988-a356-72f671a47a4e','新年','晁說之','宋','宋诗','song-poetry','','[]','何事重新作此年，身無疾病意欣然。',32,'全唐诗/poet.song.68000.json','["何事重新作此年，身無疾病意欣然。", "春風莫但開桃李，吹落妖星静九天。"]'),
('aa690675-db3c-4b35-b8c7-1e54a62de1a7','感事','晁說之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江無月令，氛祲日胚胎。',48,'全唐诗/poet.song.68000.json','["長江無月令，氛祲日胚胎。", "北闕望不見，東風呼弗來。", "后皇本圖治，上帝肯遺才。", "爲問縉紳士，何容賦七哀。"]'),
('b0adeff5-b681-4cc6-b9a4-664a5170e60e','書事  其一','晁說之','宋','宋诗','song-poetry','','[]','先生不飲而常醉，醉倒四海支狂流。',32,'全唐诗/poet.song.68000.json','["先生不飲而常醉，醉倒四海支狂流。", "不煩高士傾佳釀，要使魚龍同我愁。"]'),
('f898a521-648c-4a43-9bb7-32f50e41d1ea','書事  其二','晁說之','宋','宋诗','song-poetry','','[]','狂寇舳艫星斗落，列炬燒江猶未覺。',32,'全唐诗/poet.song.68000.json','["狂寇舳艫星斗落，列炬燒江猶未覺。", "太平斥候固不嚴，樽俎之謀在河朔。"]'),
('bfad9cc8-39b6-4e43-9329-150c676f4b29','書事  其三','晁說之','宋','宋诗','song-poetry','','[]','一江如鼎魚龍沸，我欲逃生何所之。',32,'全唐诗/poet.song.68000.json','["一江如鼎魚龍沸，我欲逃生何所之。", "今古興亡有同恨，乾陵火照奉天時。"]'),
('bd5c17c9-9979-40b9-8e72-3093dec5a83a','絮被','晁說之','宋','宋诗','song-poetry','','[]','絮被蒙頭曉日高，厭聞處處殺官曹。',32,'全唐诗/poet.song.68000.json','["絮被蒙頭曉日高，厭聞處處殺官曹。", "古人言盡致禦術，今日興言盜是招。"]'),
('fc097eab-fd23-4aab-9f5f-e1628464689a','正月二十八日避難至海陵從先流寓兄弟之招仍邂逅馮元禮故人  其一','晁說之','宋','宋诗','song-poetry','','[]','百困身猶在，尫羸怯鏡看。',48,'全唐诗/poet.song.68000.json','["百困身猶在，尫羸怯鏡看。", "干戈朝食拙，風雨夜眠難。", "天際旄頭遠，淮南春首寒。", "病夫藥裹外，兄弟爲謀安。"]'),
('f2b1774b-2573-481a-bae7-ea1184d25d76','正月二十八日避難至海陵從先流寓兄弟之招仍邂逅馮元禮故人  其二','晁說之','宋','宋诗','song-poetry','','[]','脱身兵火欲何之，不料兹焉過所期。',64,'全唐诗/poet.song.68000.json','["脱身兵火欲何之，不料兹焉過所期。", "軒檻如僧縈橘柚，鄉關似夢識蒿藜。", "弟兄朋友談平昔，盜賊羌胡問幾時。", "共約更明王道正，或能一語到天墀。"]'),
('d5456947-6cc4-4654-b4a1-10cce8bd3984','二月二日','晁說之','宋','宋诗','song-poetry','','[]','柳花多情不肯新，可憐失盡漢家春。',64,'全唐诗/poet.song.68000.json','["柳花多情不肯新，可憐失盡漢家春。", "二年不識挑生菜，萬國誰知有殺身。", "羣盜猶多南渡客，征鴻難問北歸人。", "始知前日一樽酒，上帝升平與爾親。"]'),
('6e6c3fad-c67d-41cf-a6f7-d3514e6d0aa5','杜詩','晁說之','宋','宋诗','song-poetry','','[]','古人愁在吾愁裏，庾信江淹可共論。',32,'全唐诗/poet.song.68000.json','["古人愁在吾愁裏，庾信江淹可共論。", "孰似少陵能嘆息，一身牢落識乾坤。"]'),
('0c324bef-d378-4af0-b0d9-f720969dac30','春光','晁說之','宋','宋诗','song-poetry','','[]','春光能負我，爲客更添愁。',48,'全唐诗/poet.song.68000.json','["春光能負我，爲客更添愁。", "梅蘂一何晚，鶯聲便欲休。", "新庖驚異味，舊侣夢同遊。", "道術知何用，江山空白頭。"]'),
('3bfa2d5d-2236-439f-99a2-f29a51ee6211','謝藴文承議陽關圖','晁說之','宋','宋诗','song-poetry','','[]','邂逅故人逃難處，王孫氣象獨升平。',32,'全唐诗/poet.song.68000.json','["邂逅故人逃難處，王孫氣象獨升平。", "詩吟摩詰如無味，畫到陽關别有情。"]'),
('98bf32e6-f880-48ca-99a6-abe149259661','不眠','晁說之','宋','宋诗','song-poetry','','[]','孤客危冠不得眠，清燈古像共安禪。',32,'全唐诗/poet.song.68000.json','["孤客危冠不得眠，清燈古像共安禪。", "鬼神未用來聽法，我自觀心絕世緣。"]'),
('4991622e-cc62-488f-9032-16213ef3d0af','寒甚','晁說之','宋','宋诗','song-poetry','','[]','二月春風著意來，氈裘北客尚低回。',32,'全唐诗/poet.song.68000.json','["二月春風著意來，氈裘北客尚低回。", "只應是日無何遜，江上梅花未肯開。"]'),
('2d6e8366-e870-4748-976d-f87b6aae455c','翻憂','晁說之','宋','宋诗','song-poetry','','[]','歲暮窮途惱白頭，況加一歲更荒州。',64,'全唐诗/poet.song.68000.json','["歲暮窮途惱白頭，況加一歲更荒州。", "家禽聚處無居屋，野水分時便斷流。", "何物不堪供佛淚，誰人可與共咨謀。", "一生本藉詩書樂，今日詩書翻百憂。"]'),
('89db57d4-4d2e-421e-9371-b00290798e37','自樂  其一','晁說之','宋','宋诗','song-poetry','','[]','避地悠悠處處居，何妨涕淚作歡娛。',64,'全唐诗/poet.song.68000.json','["避地悠悠處處居，何妨涕淚作歡娛。", "碾茶勢軟春心静，搗藥香多病意除。", "夢寐未嘗忘仗衛，兒童猶不戀江湖。", "心期歸計嵩箕近，只恐風塵尚畏途。"]'),
('3d68038d-1e56-495e-a8c8-80b1cc722e4c','自樂  其二','晁說之','宋','宋诗','song-poetry','','[]','自愁還自樂，於道得吾真。',48,'全唐诗/poet.song.68000.json','["自愁還自樂，於道得吾真。", "花以瓶爲圃，人将飽作春。", "詩書惟務舊，老大豈知新。", "明日還如此，太平先此身。"]'),
('e1784db9-69e1-460b-a131-c2dca5decdde','感事  其一','晁說之','宋','宋诗','song-poetry','','[]','我有清時略，白頭病在床。',48,'全唐诗/poet.song.68000.json','["我有清時略，白頭病在床。", "必須誅國賊，先要射天狼。", "割據江山舊，艱難日月長。", "百花寒未發，朱帝恨茫茫。"]'),
('7126a5fc-abc2-4f2a-bcf5-f8295965eea7','感事  其二','晁說之','宋','宋诗','song-poetry','','[]','人心端可見，戎馬幾時休。',48,'全唐诗/poet.song.68000.json','["人心端可見，戎馬幾時休。", "往哲真能恨，來賢更用愁。", "只應當日淚，常共大江流。", "漢縣寥寥甚，今爲輔帝州。"]'),
('4d793ca0-8f71-4c5a-a352-73b6b82a1eb2','夢斷','晁說之','宋','宋诗','song-poetry','','[]','夢斷咨嗟故國寒，江湖風物共彫殘。',64,'全唐诗/poet.song.68000.json','["夢斷咨嗟故國寒，江湖風物共彫殘。", "麻姑嫁時浪未息，織女支機石豈安。", "不許忠臣施一語，徒令志士起三嘆。", "不患盜賊不撲滅，要使盜賊耕桑難。"]'),
('0a824c85-45da-454e-975b-77752b8c6412','疾病','晁說之','宋','宋诗','song-poetry','','[]','疾病非吾有，吾身與世輕。',48,'全唐诗/poet.song.68000.json','["疾病非吾有，吾身與世輕。", "看棋得静意，說藥肯傷生。", "不道江湖遠，惟多鷗鷺情。", "況聞登俊傑，即日是升平。"]'),
('e671fcdc-fa51-4287-9752-7ed921eade70','感事二首  其一','晁說之','宋','宋诗','song-poetry','','[]','本是懸車却掃人，猥貪雨露政惟新。',64,'全唐诗/poet.song.68000.json','["本是懸車却掃人，猥貪雨露政惟新。", "干戈難作牆東客，疾病猶存硯北身。", "敢覓圖書灰燼裏，誰分盜賊甲兵屯。", "紛紛四海人知否，猶屬炎年第一春。"]'),
('0dcd6c6b-2ee9-49ee-9c76-e9d9b44c1e48','感事二首  其二','晁說之','宋','宋诗','song-poetry','','[]','流寓無家浪漫行，全家處處話升平。',64,'全唐诗/poet.song.68000.json','["流寓無家浪漫行，全家處處話升平。", "溪山色外京關色，風雨聲中讀誦聲。", "周粟本難供口腹，漢庭未易議公卿。", "海涯更比天涯遠，泛泛天波一葉輕。"]'),
('feb775e6-7c3b-4605-adad-cd2212d8f462','攬古','晁說之','宋','宋诗','song-poetry','','[]','攬古茫茫涕淚頻，誰教末路尚沈淪。',64,'全唐诗/poet.song.68000.json','["攬古茫茫涕淚頻，誰教末路尚沈淪。", "青山會有爲塵日，紫陌曾無不死人。", "王莽曆期餘數在，董賢恩幸幾番新。", "只應不武空憔悴，自有長歌薇蕨春。"]'),
('7a3a32f4-6ab9-4e38-ba01-2d919d625695','題六一東坡像  其一','晁說之','宋','宋诗','song-poetry','','[]','座右銘何有，丹青得若人。',72,'全唐诗/poet.song.68000.json','["座右銘何有，丹青得若人。", "東坡禪客衲，六一醉人巾。", "先後文章伯，安危社稷臣。", "廟堂思潁日，海嶠夢鈞辰。", "□□□□□，□□歎會神。", "何當均雨露，劍佩畫麒麟。"]'),
('ef590fca-7172-46db-97b1-ac8baedb9668','題六一東坡像  其二','晁說之','宋','宋诗','song-poetry','','[]','眉山凝間氣，渤海識茲人。',72,'全唐诗/poet.song.68000.json','["眉山凝間氣，渤海識茲人。", "一代執鞭士，千秋折角巾。", "高趨周室輔，平處漢廷臣。", "白首齊明易，鴻鈞異撫辰。", "參差非所嘆，契闊自如神。", "不念乞靈者，翩然駕白麟。"]'),
('6bc58e57-7307-4e54-923f-2aab9fcceaa9','有恨','晁說之','宋','宋诗','song-poetry','','[]','有恨将何遣，軒車盡俊髦。',48,'全唐诗/poet.song.68000.json','["有恨将何遣，軒車盡俊髦。", "官非十女壻，政鄙小兒曹。", "歲暮客悰急，塗窮馬力勞。", "故山真可戀，築室更增高。"]'),
('55d72cc6-4bdc-487d-993b-4e199534e9ae','無悶','晁說之','宋','宋诗','song-poetry','','[]','無悶吾無欲，浮沈誰使然。',48,'全唐诗/poet.song.68000.json','["無悶吾無欲，浮沈誰使然。", "命通公道日，自是艷陽年。", "鸞鳯能寥廓，魴鱒幸棄捐。", "由來食肉士，久亦忘腥羶。"]'),
('bfdade8d-3863-47d8-92e8-d2ff116fae89','因事','晁說之','宋','宋诗','song-poetry','','[]','風雨連宵疾病增，幽憂到此果何勝。',64,'全唐诗/poet.song.68000.json','["風雨連宵疾病增，幽憂到此果何勝。", "弟兄分散兩三處，圖史尋求萬一能。", "魯酒齊歌元不惡，吳酸楚酪乍須稱。", "東皇太一仁恩大，終使白頭見中興。"]'),
('5c305c66-e8fd-49ad-8a15-e3cd86499b8a','海陵社日','晁說之','宋','宋诗','song-poetry','','[]','信美非真美，徒勞本自勞。',24,'全唐诗/poet.song.68000.json','["信美非真美，徒勞本自勞。", "異鄉今日社，寂寞食無糕。"]'),
('eff419bf-989e-4cbb-a9ee-ab5000d0d083','謝藴文薺菜餛飩','晁說之','宋','宋诗','song-poetry','','[]','無奈國風怨，薺荼論苦甘。',24,'全唐诗/poet.song.68000.json','["無奈國風怨，薺荼論苦甘。", "王孫舊肥羜，湯餅亦多慚。"]'),
('49849566-a545-4571-93d2-2163d6abbc97','撫古','晁說之','宋','宋诗','song-poetry','','[]','撫古論今百感生，興亡異世實同情。',64,'全唐诗/poet.song.68000.json','["撫古論今百感生，興亡異世實同情。", "鬼神能告廣陵散，才智無如大廈傾。", "天御日躔歸故國，江潮淮浦漫新城。", "論都不及百世事，誰爲君王致太平。"]'),
('215f95fa-d6eb-48ba-80fa-d531a1716e40','書恨','晁說之','宋','宋诗','song-poetry','','[]','挂帆到何處，明月古揚州。',48,'全唐诗/poet.song.68000.json','["挂帆到何處，明月古揚州。", "百計隨愁盡，一生爲客休。", "干戈臨暮境，風雨困春柔。", "爲問荀文若，能慚諸葛不。"]'),
('309e94fb-0677-4471-9690-f57b9123bc79','夜聞烏啼  其一','晁說之','宋','宋诗','song-poetry','','[]','不眠無恨自悽悽，真聽人間烏夜啼。',32,'全唐诗/poet.song.68000.json','["不眠無恨自悽悽，真聽人間烏夜啼。", "明月未教塵鏡掩，華堂歌舞乍高低。"]'),
('88ff21fa-7bd7-4c2a-828c-54c4bd33e1e2','夜聞烏啼  其二','晁說之','宋','宋诗','song-poetry','','[]','義烏此夜一何啼，明日歡欣事不迷。',32,'全唐诗/poet.song.68000.json','["義烏此夜一何啼，明日歡欣事不迷。", "定是軍回薊南北，寧論賊退關東西。"]'),
('9d800b19-c115-4c22-a7f5-b8318a519a2b','置身','晁說之','宋','宋诗','song-poetry','','[]','置身唯所安，世累莫相干。',48,'全唐诗/poet.song.68000.json','["置身唯所安，世累莫相干。", "蓬鬢江湖適，披衣天地寛。", "尚須煩束带，忍復更危冠。", "居安歎匪易，淚垂行路難。"]');
